-- Poems batch 432
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-94','相和歌辭：銅雀妓','朱放','唐','御定全唐诗','yuding','','[]','恨唱歌聲咽，愁翻舞袖遲。西陵日欲暮，是妾斷腸時。',24,'御定全唐詩/json/019.json','["恨唱歌聲咽，愁翻舞袖遲。西陵日欲暮，是妾斷腸時。"]'),
('yuding-95','相和歌辭：銅雀妓','皎然','唐','御定全唐诗','yuding','','[]','強開尊酒向陵看，憶得君王舊日歡。',32,'御定全唐詩/json/019.json','["強開尊酒向陵看，憶得君王舊日歡。", "不覺餘歌悲自斷，非關豔曲轉聲難。"]'),
('yuding-96','相和歌辭：雀台怨','馬戴','唐','御定全唐诗','yuding','','[]','魏宮歌舞地，蝶戲鳥還鳴。玉座人難到，銅台雨滴平。',48,'御定全唐詩/json/019.json','["魏宮歌舞地，蝶戲鳥還鳴。玉座人難到，銅台雨滴平。", "西陵樹不見，漳浦草空生。萬恨盡埋此，徒懸千載名。"]'),
('yuding-97','相和歌辭：雀台怨','程氏長文','唐','御定全唐诗','yuding','','[]','君王去後行人絕，簫竽不響歌喉咽。雄劍無威光彩沉，',40,'御定全唐詩/json/019.json','["君王去後行人絕，簫竽不響歌喉咽。雄劍無威光彩沉，", "當時歌舞人不回，化為今日西陵灰。"]'),
('yuding-98','相和歌辭：置酒行','李益','唐','御定全唐诗','yuding','','[]','置酒命所歡，憑觴遂為戚。日往不再來，茲辰坐成昔。',96,'御定全唐詩/json/019.json','["置酒命所歡，憑觴遂為戚。日往不再來，茲辰坐成昔。", "百齡非長久，五十將半百。胡為勞我形，已須還複白。", "西山鸞鶴顧，矯矯煙霧翮。明霞發金丹，陰洞潛水碧。", "安得淩風羽，崦嵫駐靈魄。兀然坐衰老，慚歎東陵柏。"]'),
('yuding-99','相和歌辭：置酒行','陸龜蒙','唐','御定全唐诗','yuding','','[]','落塵花片排香痕，闌珊醉露棲愁魂。洞庭波色惜不得，',41,'御定全唐詩/json/019.json','["落塵花片排香痕，闌珊醉露棲愁魂。洞庭波色惜不得，", "安知寂寞西海頭，青pF未垂孤鳳餓。"]'),
('yuding-100','相和歌辭：長歌續短歌','李賀','唐','御定全唐诗','yuding','','[]','長歌破衣襟，短歌斷白髮。秦王不可見，旦夕成內熱。',84,'御定全唐詩/json/019.json','["長歌破衣襟，短歌斷白髮。秦王不可見，旦夕成內熱。", "渴飲壺中酒，饑拔隴頭粟。淒淒四月蘭，千里一時綠。", "夜峰何離離，月明落石底。裴回沿石尋，照出高峰外。", "不得與之游，歌成鬢先改。"]'),
('yuding-101','相和歌辭：猛虎行','儲光羲','唐','御定全唐诗','yuding','','[]','寒亦不憂雪，饑亦不食人。人血豈不甘，所惡傷明神。',96,'御定全唐詩/json/019.json','["寒亦不憂雪，饑亦不食人。人血豈不甘，所惡傷明神。", "太室為我宅，孟門為我鄰。百獸為我膳，五龍為我賓。", "蒙馬一何威，浮江亦以仁。彩章耀朝日，牙爪雄武臣。", "高雲逐氣浮，厚地隨聲振。君能賈餘勇，日夕長相親。"]'),
('yuding-102','相和歌辭：猛虎行','李白','唐','御定全唐诗','yuding','','[]','朝作猛虎行，暮作猛虎吟。腸斷非關隴頭水，',188,'御定全唐詩/json/019.json','["朝作猛虎行，暮作猛虎吟。腸斷非關隴頭水，", "秦人半作燕地囚，胡馬翻銜洛陽草。一輸一失關下兵，", "頗似楚漢時，翻覆無定止。朝過博浪沙，暮入淮陰市。", "張良未遇韓信貧，劉項存亡在兩臣。暫到下邳受兵略，", "有策不敢犯龍鱗，竄身南國避胡塵。寶書長劍掛高閣，", "有時六博快壯心，繞床三匝呼一擲。楚人每道張旭奇，", "蕭曹曾作沛中吏，攀龍附鳳當有時。溧陽酒樓三月春，", "丈夫相見且為樂，槌牛撾鼓會眾賓。我從此去釣東海，"]'),
('yuding-103','相和歌辭：猛虎行','韓愈','唐','御定全唐诗','yuding','','[]','猛虎雖雲惡，亦各有匹儕。群行深谷間，百獸望風低。',192,'御定全唐詩/json/019.json','["猛虎雖雲惡，亦各有匹儕。群行深谷間，百獸望風低。", "身食黃熊父，子食赤豹麛。擇肉于熊羆，肯視兔與狸。", "正晝當穀眠，眼有百步威。自矜無當對，氣性縱以乖。", "朝怒殺其子，暮還飧其妃。匹儕四散走，猛虎還孤棲。", "狐鳴門四旁，烏鵲從噪之。出逐猴入居，虎不知所歸。", "誰雲猛虎惡，中路正悲啼。豹來銜其尾，熊來攫其頤。", "猛虎死不辭，但慚前所為。虎坐無助死，況如汝細微。", "故當結以信，親當結以私。親故且不保，人誰信汝為。"]'),
('yuding-104','相和歌辭：猛虎行','張籍','唐','御定全唐诗','yuding','','[]','南山北山樹冥冥，猛虎白日繞林行。向晚一身當道食，',48,'御定全唐詩/json/019.json','["南山北山樹冥冥，猛虎白日繞林行。向晚一身當道食，", "穀中近窟有山村，長向村家取黃犢。五陵年少不敢射，"]'),
('yuding-105','相和歌辭：猛虎行','李賀','唐','御定全唐诗','yuding','','[]','長戈莫舂，強弩莫烹。乳孫哺子，教得生獰。',81,'御定全唐詩/json/019.json','["長戈莫舂，強弩莫烹。乳孫哺子，教得生獰。", "舉頭為城，掉尾為旌。東海黃公，愁見夜行。", "道逢騶虞，牛哀不平。生何用尺刀，壁上雷鳴。", "泰山之下，婦人哭聲。官家有程，吏不敢聽。"]'),
('yuding-106','相和歌辭：猛虎行','齊己','唐','御定全唐诗','yuding','','[]','磨爾牙，錯爾爪，狐莫威，兔莫狡。飲來吞噬取腸飽，',24,'御定全唐詩/json/019.json','["磨爾牙，錯爾爪，狐莫威，兔莫狡。飲來吞噬取腸飽，"]'),
('yuding-107','相和歌辭：君子行','齊己','唐','御定全唐诗','yuding','','[]','聖人不生，麟龍何瑞；梧桐不高，鳳凰何止。',58,'御定全唐詩/json/019.json','["聖人不生，麟龍何瑞；梧桐不高，鳳凰何止。", "吾聞古之有君子，行藏以時，進退求己；", "榮必為天下榮，恥必為天下恥。苟進不如此，"]'),
('yuding-108','相和歌辭：燕歌行','高適','唐','御定全唐诗','yuding','','[]','漢家煙塵在東北，漢將辭家破殘賊。男兒本自重橫行，',129,'御定全唐詩/json/019.json','["漢家煙塵在東北，漢將辭家破殘賊。男兒本自重橫行，", "校尉羽書飛瀚海，單于獵火照狼山。山川蕭條極邊土，", "大漠窮秋塞草衰，孤城落日鬥兵稀。身當恩遇常輕敵，", "少婦城南欲斷腸。征人薊北空回首。邊風飄飄那可度，", "相看白刃血紛紛，死節從來豈顧勳。", "君不見沙場征戰苦，至今猶憶李將軍。"]'),
('yuding-109','相和歌辭：燕歌行','賈至','唐','御定全唐诗','yuding','','[]','國之重鎮惟幽都，東威九夷制北胡。五軍精卒三十萬，',136,'御定全唐詩/json/019.json','["國之重鎮惟幽都，東威九夷制北胡。五軍精卒三十萬，", "昔時燕王重賢士，黃金築台從隗始。倏忽興王定薊丘，", "我唐區夏餘十紀，軍容武備赫萬祀。彤弓黃鉞授元帥，", "千營萬隊連旌旗，望之如火忽雷馳。匈奴懾竄窮發北，", "南風不競多死聲，鼓臥旗折黃雲橫。六軍將士皆死盡，", "自有農夫已高枕，無勞校尉重橫行。"]'),
('yuding-110','相和歌辭：燕歌行','陶翰','唐','御定全唐诗','yuding','','[]','請君留楚調，聽我吟燕歌。家在遼水頭，邊風意氣多。',108,'御定全唐詩/json/019.json','["請君留楚調，聽我吟燕歌。家在遼水頭，邊風意氣多。", "出自為漢將，正值戎未和。雪中淩天山，冰上渡交河。", "大小百餘戰，封侯竟蹉跎。歸來霸陵下，故舊無相過。", "雄劍委塵匣，空門唯雀羅。玉簪還趙女，寶瑟付齊娥。", "昔日不為樂，時哉今奈何。"]'),
('yuding-111','相和歌辭：從軍行二首','虞世南','唐','御定全唐诗','yuding','','[]','塗山烽候驚，弭節度龍城。冀馬樓蘭將，燕犀上穀兵。',204,'御定全唐詩/json/019.json','["塗山烽候驚，弭節度龍城。冀馬樓蘭將，燕犀上穀兵。", "劍寒花不落，弓曉月逾明。凜凜嚴霜節，冰壯黃河絕。", "蔽日卷征蓬，浮天散飛雪。全兵值月滿，精騎乘膠折。", "結髮早驅馳，辛苦事旌麾。馬凍重關冷，輪摧九折危。", "獨有西山將，年年屬數奇。", "爟火發金微，連營出武威。孤城寒雲起，絕陣虜塵飛。", "俠客吸龍劍，惡少縵胡衣。朝摩骨都壘，夜解穀蠡圍。", "蕭關遠無極，蒲海廣難依。沙磴離旌斷，晴川候馬歸。", "交河梁已畢，燕山旆欲飛。方知萬里相，侯服有光輝。"]'),
('yuding-112','相和歌辭：從軍行','駱賓王','唐','御定全唐诗','yuding','','[]','平生一顧念，意氣溢三軍。野日分戈影，天星合劍文。',48,'御定全唐詩/json/019.json','["平生一顧念，意氣溢三軍。野日分戈影，天星合劍文。", "弓弦抱漢月，馬足踐胡塵。不求生入塞，唯當死報君。"]'),
('yuding-113','相和歌辭：從軍行','劉希夷','唐','御定全唐诗','yuding','','[]','秋來風瑟瑟，群馬胡行疾。嚴城晝不開，伏兵暗相失。',108,'御定全唐詩/json/019.json','["秋來風瑟瑟，群馬胡行疾。嚴城晝不開，伏兵暗相失。", "天子廟堂拜，將軍玉門出。紛紛伊洛間，戎馬數千匹。", "軍門壓黃河，兵氣沖白日。平生懷伏劍，慷慨既投筆。", "南登漢月孤，北走燕雲密。近取韓彭計，早知孫吳術。", "丈夫清萬里，誰能掃一室。"]'),
('yuding-114','相和歌辭：從軍行','喬知之','唐','御定全唐诗','yuding','','[]','南庭結白露，北風掃黃葉。此時鴻雁來，驚鳴催思妾。',144,'御定全唐詩/json/019.json','["南庭結白露，北風掃黃葉。此時鴻雁來，驚鳴催思妾。", "曲房理針線，平砧搗文練。鴛綺裁易成，龍鄉信難見。", "窈窕九重閨，寂寞十年啼。紗窗白雲宿，羅幌月光棲。", "雲月曉微微，愁思流黃機。玉霜凍珠履，金吹薄羅衣。", "漢家已得地，君去將何事。宛轉結蠶書，寂寞無雁使。", "生平荷恩信，本為容華進。況複落紅顏，蟬聲催綠鬢。"]'),
('yuding-115','相和歌辭：從軍行','李頎','唐','御定全唐诗','yuding','','[]','白日登山望烽火，昏黃飲馬傍交河。行人刁鬥風砂暗，',48,'御定全唐詩/json/019.json','["白日登山望烽火，昏黃飲馬傍交河。行人刁鬥風砂暗，", "胡雁哀鳴夜夜飛，胡兒眼淚雙雙落。聞道玉門猶被遮，"]'),
('yuding-116','相和歌辭：從軍行三首','李約','唐','御定全唐诗','yuding','','[]','看圖閑教陣，畫地靜論邊。烏壘天西戍，鷹姿塞上川。',144,'御定全唐詩/json/019.json','["看圖閑教陣，畫地靜論邊。烏壘天西戍，鷹姿塞上川。", "路長須算日，書遠每題年。無複生還望，翻思未別前。", "柵高三面鬥，箭盡舉烽頻。營柳和煙暮，關榆帶雪春。", "邊城多老將，磧路少歸人。點盡三河卒，年年添塞塵。", "候火起雕城，塵砂擁戰聲。游軍藏漢幟，降騎說蕃情。", "霜降滮池淺，秋深太白明。嫖姚方虎視，不覺請添兵。"]'),
('yuding-117','相和歌辭：從軍行','戎昱','唐','御定全唐诗','yuding','','[]','昔從李都尉，雙鞬照馬蹄。擒生黑山北，殺敵黃雲西。',108,'御定全唐詩/json/019.json','["昔從李都尉，雙鞬照馬蹄。擒生黑山北，殺敵黃雲西。", "太白沉虜地，邊草複萋萋。歸來邯鄲市，百尺青樓梯。", "感激然諾重，平生膽力齊。芳筵暮歌發，豔粉輕鬟低。", "半醉秋風起，鐵騎門前嘶。遠戍報烽火，孤城嚴鼓鼙。", "揮鞭望塵去，少婦莫含啼。"]'),
('yuding-118','相和歌辭：從軍行','厲玄','唐','御定全唐诗','yuding','','[]','邊草早不春，劍花增濘塵。廣場收驥尾，清瀚怯龍鱗。',48,'御定全唐詩/json/019.json','["邊草早不春，劍花增濘塵。廣場收驥尾，清瀚怯龍鱗。", "帆色已歸越，松聲厭避秦。幾時逢範蠡，處處是通津。"]'),
('yuding-119','相和歌辭：從軍行二首','李白','唐','御定全唐诗','yuding','','[]','從軍玉門道，逐虜金微山。笛奏梅花曲，刀開明月環。',80,'御定全唐詩/json/019.json','["從軍玉門道，逐虜金微山。笛奏梅花曲，刀開明月環。", "鼓聲鳴海上，兵氣擁雲間。願斬單于首，長驅靜鐵關。", "百戰沙場碎鐵衣，城南已合數重圍。", "突營射殺呼延將，獨領殘兵千騎歸。"]'),
('yuding-120','相和歌辭：從軍行','王維','唐','御定全唐诗','yuding','','[]','吹角動行人，喧喧行人起。笳鳴馬嘶亂，爭渡金河水。',48,'御定全唐詩/json/019.json','["吹角動行人，喧喧行人起。笳鳴馬嘶亂，爭渡金河水。", "日暮沙漠垂，戰聲煙塵裏。盡系名王頸，歸來報天子。"]'),
('yuding-121','相和歌辭：從軍行','王昌齡','唐','御定全唐诗','yuding','','[]','向夕臨大荒，朔風軫歸慮。平沙萬里餘，飛鳥宿何處。',180,'御定全唐詩/json/019.json','["向夕臨大荒，朔風軫歸慮。平沙萬里餘，飛鳥宿何處。", "虜騎獵長原，翩翩傍河去。邊聲搖白草，海氣生黃霧。", "百戰苦風塵，十年履霜露。雖投定遠筆，未坐將軍樹。", "早知行路難，悔不理章句。", "烽火城西百尺樓，黃昏獨上海風秋。", "更吹橫笛關山月，誰解金閨萬里愁。", "琵琶起舞換新聲，總是關山舊別情。", "撩亂邊愁彈不盡，高高秋月下長城。", "青海長雲暗雪山，孤城遙望雁門關。", "黃沙百戰穿金甲，不破樓蘭終不還。"]'),
('yuding-122','相和歌辭：從軍行','盧綸','唐','御定全唐诗','yuding','','[]','二十在邊城，軍中得勇名。卷旗收敗馬，斷磧擁殘兵。',72,'御定全唐詩/json/019.json','["二十在邊城，軍中得勇名。卷旗收敗馬，斷磧擁殘兵。", "覆陣烏鳶起，燒山草木明。塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足雁聲。李陵甘此沒，惆悵漢公卿。"]'),
('yuding-123','相和歌辭：從軍行六首','劉長卿','唐','御定全唐诗','yuding','','[]','回看虜騎合，城下漢兵稀。白刃兩相向，黃雲愁不飛。',216,'御定全唐詩/json/019.json','["回看虜騎合，城下漢兵稀。白刃兩相向，黃雲愁不飛。", "手中無尺鐵，徒欲突重圍。", "落日更蕭條，北方動枯草。將軍追虜騎，夜失陰山道。", "戰敗仍樹勳，韓彭但空老。", "草枯秋塞上，望見漁陽郭。胡馬嘶一聲，漢兵淚雙落。", "誰為吮癰者，此事令人薄。", "目極雁門道，青青邊草春。一身事征戰，匹馬同辛勤。", "末路成白首，功歸天下人。", "倚劍白日暮，望鄉登戍樓。北風吹羌笛，此夜關山愁。", "回首不無意，滹河空自流。", "黃沙一萬里，白首無人憐。報國劍已折，歸鄉身幸全。", "單于古台下，邊色寒蒼然。"]'),
('yuding-124','相和歌辭：從軍行','杜頠','唐','御定全唐诗','yuding','','[]','秋草馬蹄輕，角弓持弦急。去為龍城候，正值胡兵襲。',96,'御定全唐詩/json/019.json','["秋草馬蹄輕，角弓持弦急。去為龍城候，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。長風金鼓動，白霧鐵衣濕。", "四起愁邊聲，南轅時佇立。斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，路平冰霰澀。夜聞漢使歸，獨向刀環泣。"]'),
('yuding-125','相和歌辭：從軍行','皎然','唐','御定全唐诗','yuding','','[]','候騎出紛紛，元戎霍冠軍。漢鞞秋聒地，羌火晝燒雲。',240,'御定全唐詩/json/019.json','["候騎出紛紛，元戎霍冠軍。漢鞞秋聒地，羌火晝燒雲。", "萬里戍城合，三邊羽檄分。烏孫驅未盡，肯顧遼陽勳。", "漢旆拂丹霄，漢軍新破遼。紅塵驅鹵簿，白羽擁嫖姚。", "戰苦軍猶樂，功高將不驕。至今丁令塞，朔吹空蕭蕭。", "百萬逐呼韓，頻年不解鞍。兵屯絕漠暗，馬飲濁河幹。", "破虜功未錄，勞師力已殫。須防肘腋下，飛禍出無端。", "飛將下天來，奇謀閫外裁。水心龍劍動，地肺雁山開。", "望氣燕師銳，當鋒虜陣摧。從今射雕騎，不敢過雲堆。", "黃紙君王詔，青泥校尉書。誓師張虎落，選將擐犀渠。", "霧暗津浦失，天寒塞柳疏。橫行十萬騎，欲掃虜塵餘。"]'),
('yuding-126','相和歌辭：從軍行','王建','唐','御定全唐诗','yuding','','[]','漢軍逐單于，日沒處河曲。浮雲道傍起，行子車下宿。',96,'御定全唐詩/json/019.json','["漢軍逐單于，日沒處河曲。浮雲道傍起，行子車下宿。", "槍城圍鼓角，氈帳依山谷。馬上懸壺漿，刀頭分頓肉。", "來時高堂上，父母親結束。回首不見家，風吹破衣服。", "金創生肢節，相與拔箭鏃。聞道西涼州，家家婦人哭。"]'),
('yuding-127','相和歌辭：從軍行','張祜','唐','御定全唐诗','yuding','','[]','少年金紫就光輝，直指邊城虎翼飛。一卷旌收千騎虜，',40,'御定全唐詩/json/019.json','["少年金紫就光輝，直指邊城虎翼飛。一卷旌收千騎虜，", "白首漢廷刀筆吏，丈夫功業本相依。"]'),
('yuding-128','相和歌辭：從軍行五首','令狐楚','唐','御定全唐诗','yuding','','[]','荒雞隔水啼，汗馬逐風嘶。終日隨旌旆，何時罷鼓鼙。',120,'御定全唐詩/json/019.json','["荒雞隔水啼，汗馬逐風嘶。終日隨旌旆，何時罷鼓鼙。", "孤心眠夜雪，滿眼是秋沙。萬里猶防塞，三年不見家。", "卻望冰河闊，前登雪嶺高。征人幾多在，又擬戰臨洮。", "胡風千里驚，漢月五更明。縱有還家夢，猶聞出塞聲。", "暮雪連青海，陰雲覆白山。可憐班定遠，出入玉門關。"]'),
('yuding-129','相和歌辭：從軍行三首','王涯','唐','御定全唐诗','yuding','','[]','旌甲從軍久，風雲識陣難。今朝韓信計，日下斬成安。',80,'御定全唐詩/json/019.json','["旌甲從軍久，風雲識陣難。今朝韓信計，日下斬成安。", "燕頷多奇相，狼頭敢犯邊。寄言班定遠，正是立功年。", "旄頭夜落捷書飛，來奏金門著賜衣。", "白馬將軍頻破敵，黃龍戍卒幾時歸。"]'),
('yuding-130','相和歌辭：從軍有苦樂行','李益','唐','御定全唐诗','yuding','','[]','勞者且勿歌，我欲送君觴。從軍有苦樂，此曲樂未央。',216,'御定全唐詩/json/019.json','["勞者且勿歌，我欲送君觴。從軍有苦樂，此曲樂未央。", "僕本居隴上，隴水斷人腸。東過秦宮路，宮路入咸陽。", "時逢漢帝出，諫獵至長楊。詎馳遊俠窟，非結少年場。", "一旦承嘉惠，輕命重恩光。秉筆參帷帟，從軍至朔方。", "邊地多陰風，草木自淒涼。斷絕海雲去，出沒胡沙長。", "參差引雁翼，隱轔騰軍裝。劍文夜如水，馬汗凍成霜。", "俠氣五都少，矜功六郡良。山河起目前，睚眥死路傍。", "北逐驅獯虜，西臨復舊疆。昔還賦餘資，今出乃贏糧。", "一矢弢夏服，我弓不再張。寄言丈夫雄，苦樂身自當。"]'),
('yuding-131','相和歌辭：苦哉遠征人','鮑溶','唐','御定全唐诗','yuding','','[]','征人歌古曲，攜手上河梁。李陵死別處，杳杳玄冥鄉。',144,'御定全唐詩/json/019.json','["征人歌古曲，攜手上河梁。李陵死別處，杳杳玄冥鄉。", "憶昔從此路，連年征鬼方。久行迷漢曆，三洗氈衣裳。", "百戰身且在，微功信難忘。遠承雲台議，非勢孰敢當。", "落日吊李廣，白身過河陽。閑弓失月影，勞劍無龍光。", "去日始束發，今來發成霜。虛名乃閒事，生見父母鄉。", "掩抑大風歌，裴回少年場。誠哉古人言，鳥盡良弓藏。"]'),
('yuding-132','相和歌辭：苦哉行五首','戎昱','唐','御定全唐诗','yuding','','[]','彼鼠侵我廚，縱狸授粱肉。鼠雖為君卻，狸食自須足。',408,'御定全唐詩/json/019.json','["彼鼠侵我廚，縱狸授粱肉。鼠雖為君卻，狸食自須足。", "冀雪大國恥，翻是大國辱。膻腥逼綺羅，磚瓦雜珠玉。", "登樓非騁望，目笑是心哭。何意天樂中，至今奏胡曲。", "官軍收洛陽，家住洛陽裏。夫婿與兄弟，目前見傷死。", "吞聲不許哭，還遣衣羅綺。上馬隨匈奴，數秋黃塵裏。", "生為名家女，死作塞垣鬼。鄉國無還期，天津哭流水。", "登樓望天衢，目極淚盈睫。強笑無笑容，須妝舊花靨。", "昔年買奴僕，奴僕來碎葉。豈意未死間，自為匈奴妾。", "一生忽至此，萬事痛苦業。得出塞垣飛，不如彼蜂蝶。", "妾家青河邊，七葉承貂蟬。身為最小女，偏得渾家憐。", "親戚不相識，幽閨十五年。有時最遠出，只到中門前。", "前年狂胡來，懼死翻生全。今秋官軍至，豈意遭戈鋋。", "匈奴為先鋒，長鼻黃發拳。彎弓獵生人，百步牛羊膻。", "脫身落虎口，不及歸黃泉。苦哉難重陳，暗哭蒼蒼天。", "可汗奉親詔，今月歸燕山。忽如亂刀劍，攪妾心腸間。", "出戶望北荒，迢迢玉門關。生人為死別，有去無時還。", "漢月割妾心，胡風凋妾顏。去去斷絕魂，叫天天不聞。"]'),
('yuding-133','相和歌辭：鞠歌行','李白','唐','御定全唐诗','yuding','','[]','玉不自言如桃李，魚目笑之卞和恥。楚國青蠅何太多，',108,'御定全唐詩/json/019.json','["玉不自言如桃李，魚目笑之卞和恥。楚國青蠅何太多，", "聽曲知甯戚，夷吾因小妻。秦穆五羊皮，買死百里奚。", "洗拂青雲上，當時賤如泥。朝歌鼓刀叟，虎變蟠溪中。", "一舉釣六合，遂荒營丘東。平生渭水曲，誰識此老翁。", "奈何今之人，雙目送征鴻。"]'),
('yuding-0','相和歌辭：前苦寒行二首','杜甫','唐','御定全唐诗','yuding','','[]','漢時長安雪一丈，牛馬毛寒縮如蝟。楚江巫峽冰入懷，',80,'御定全唐詩/json/020.json','["漢時長安雪一丈，牛馬毛寒縮如蝟。楚江巫峽冰入懷，", "玄冥祝融氣或交，手持白羽未敢釋。", "去年白帝雪在山，今年白帝雪在地。凍埋蛟龍南浦縮，", "三足之烏足恐斷，羲和送將安所歸。"]'),
('yuding-1','相和歌辭：後苦寒行二首','杜甫','唐','御定全唐诗','yuding','','[]','南紀巫廬瘴不絕，太古已來無尺雪。蠻夷長老怨苦寒，',48,'御定全唐詩/json/020.json','["南紀巫廬瘴不絕，太古已來無尺雪。蠻夷長老怨苦寒，", "晚來江門失大木，猛風中夜吹白屋。天兵斷斬青海戎，"]'),
('yuding-2','相和歌辭：苦寒行','劉駕','唐','御定全唐诗','yuding','','[]','嚴寒動八荒，藾藾無休時。陽烏不自暖，雪壓扶桑枝。',60,'御定全唐詩/json/020.json','["嚴寒動八荒，藾藾無休時。陽烏不自暖，雪壓扶桑枝。", "歲暮寒益壯，青春安得歸。朔雁到南海，越禽何處飛。", "誰言貧士歎，不為身無衣。"]'),
('yuding-3','相和歌辭：苦寒行','貫休','唐','御定全唐诗','yuding','','[]','北風北風，職何嚴毒，摧壯士心，縮金烏足。',78,'御定全唐詩/json/020.json','["北風北風，職何嚴毒，摧壯士心，縮金烏足。", "凍雲囂囂礙雪，一片下不得。聲繞枯桑，根在沙塞。", "黃河徹底，頑直到海。一氣搏束，萬物無態。", "唯有吾庭前杉松樹枝，枝枝健在。"]'),
('yuding-4','相和歌辭：苦寒行','齊己','唐','御定全唐诗','yuding','','[]','冰峰撐空寒矗矗，雲凝水凍埋海陸。',39,'御定全唐詩/json/020.json','["冰峰撐空寒矗矗，雲凝水凍埋海陸。", "殺物之性，傷人之欲，既不能斷絕蒺藜荊棘之根株，"]'),
('yuding-5','相和歌辭：北上行','李白','唐','御定全唐诗','yuding','','[]','北上何所苦，北上緣太行。磴道盤且峻，巉岩淩穹蒼。',168,'御定全唐詩/json/020.json','["北上何所苦，北上緣太行。磴道盤且峻，巉岩淩穹蒼。", "馬足蹶側石，車輪摧高岡。沙塵接幽州，烽火連朔方。", "殺氣毒劍戟，嚴風裂衣裳。奔鯨夾黃河，鑿齒屯洛陽。", "前行無歸日，返顧思舊鄉。慘戚冰雪裏，悲號絕中腸。", "尺布不掩體，皮膚劇枯桑。汲水澗穀阻，采薪隴阪長。", "猛虎又掉尾，磨牙皓秋霜。草木不可餐，饑飲零露漿。", "歎此北上苦，停驂為之傷。何日王道平，開顏睹天光。"]'),
('yuding-6','相和歌辭：豫章行','李白','唐','御定全唐诗','yuding','','[]','胡風吹代馬，北擁魯陽關。吳兵照海雪，西討何時還。',132,'御定全唐詩/json/020.json','["胡風吹代馬，北擁魯陽關。吳兵照海雪，西討何時還。", "半渡上遼津，黃雲慘無顏。老母與子別，呼天野草間。", "白馬繞旌旗，悲鳴相追攀。白楊秋月苦，早落豫章山。", "本為休明人，斬虜素不閑。豈惜戰鬥死，為君掃凶頑。", "精感石沒羽，豈忘憚險艱。樓船若鯨飛，波蕩落星灣。", "此曲不可奏，三軍鬢成斑。"]'),
('yuding-7','相和歌辭：董逃行','元稹','唐','御定全唐诗','yuding','','[]','董逃董逃董卓逃，揩鏗戈甲聲勞嘈。剜剜深臍脂焰焰，',72,'御定全唐詩/json/020.json','["董逃董逃董卓逃，揩鏗戈甲聲勞嘈。剜剜深臍脂焰焰，", "膏銷骨盡煙火死，長安城中賊毛起。城門四走公卿士，", "董逃董逃人莫喜，勝負翻環相枕倚。縫綴難成裁破易，"]'),
('yuding-8','相和歌辭：董逃行','張籍','唐','御定全唐诗','yuding','','[]','洛陽城頭火曈曈，亂兵燒我天子宮。宮城南面有深山，',52,'御定全唐詩/json/020.json','["洛陽城頭火曈曈，亂兵燒我天子宮。宮城南面有深山，", "聞道官軍猶掠人，舊裏如今歸未得。", "董逃行，漢家幾時重太平。"]'),
('yuding-9','相和歌辭：相逢行','崔顥','唐','御定全唐诗','yuding','','[]','妾年初二八，家住洛橋頭。玉戶臨馳道，朱門近禦溝。',72,'御定全唐詩/json/020.json','["妾年初二八，家住洛橋頭。玉戶臨馳道，朱門近禦溝。", "使君何假問，夫婿大長秋。女弟新承寵，諸兄近拜侯。", "春生百子殿，花發五城樓。出入千門裏，年年樂未休。"]'),
('yuding-10','相和歌辭：相逢行二首','李白','唐','御定全唐诗','yuding','','[]','朝騎五花馬，謁帝出銀台。秀色誰家子，雲車珠箔開。',228,'御定全唐詩/json/020.json','["朝騎五花馬，謁帝出銀台。秀色誰家子，雲車珠箔開。", "金鞭遙指點，玉勒近遲回。夾轂相借問，疑從天上來。", "憐腸愁欲斷，斜日複相催。下車何輕盈，飄然似落梅。", "邀入青綺門，當歌共銜杯。銜杯映歌扇，似月雲中見。", "相見不相親，不如不相見。相見情已深，未語可知心。", "胡為守空閨，孤眠愁錦衾。錦衾與羅幃，纏綿會有時。", "春風正澹蕩，暮雨來何遲。願因三青鳥，更報長相思。", "光景不待人，須臾發成絲。當年失行樂，老去徒傷悲。", "持此道密意，無令曠佳期。", "相逢紅塵內，高揖黃金鞭。萬戶垂楊裏，君家阿那邊。"]'),
('yuding-11','相和歌辭：相逢行','韋應物','唐','御定全唐诗','yuding','','[]','二十登漢朝，英聲邁今古。適從東方來，又欲謁明主。',72,'御定全唐詩/json/020.json','["二十登漢朝，英聲邁今古。適從東方來，又欲謁明主。", "猶酣新豐酒，尚帶霸陵雨。邂逅兩相逢，別來間寒暑。", "甯知白日晚，暫向花間語。忽聞長樂鐘，走馬東西去。"]'),
('yuding-12','相和歌辭：三婦豔詩','董思恭','唐','御定全唐诗','yuding','','[]','大婦裁紈素，中婦弄明璫。小婦多姿態，登樓紅粉妝。',36,'御定全唐詩/json/020.json','["大婦裁紈素，中婦弄明璫。小婦多姿態，登樓紅粉妝。", "丈人且安坐，初日漸流光。"]'),
('yuding-13','相和歌辭：中婦織流黃','虞世南','唐','御定全唐诗','yuding','','[]','寒閨織素錦，含怨斂雙蛾。綜新交縷澀，經脆斷絲多。',48,'御定全唐詩/json/020.json','["寒閨織素錦，含怨斂雙蛾。綜新交縷澀，經脆斷絲多。", "衣香逐舉袖，釧動應鳴梭。還恐裁縫罷，無信達交河。"]'),
('yuding-14','相和歌辭：難忘曲','李賀','唐','御定全唐诗','yuding','','[]','夾道開洞門，弱楊低畫戟。簾影竹葉起，簫聲吹日色。',48,'御定全唐詩/json/020.json','["夾道開洞門，弱楊低畫戟。簾影竹葉起，簫聲吹日色。", "蜂語繞妝鏡，拂蛾學春碧。亂系丁香梢，滿闌花向夕。"]'),
('yuding-15','相和歌辭：塘上行','李賀','唐','御定全唐诗','yuding','','[]','藕花涼露濕，花缺藕根澀。飛下雌鴛鴦，塘水聲溢溢。',24,'御定全唐詩/json/020.json','["藕花涼露濕，花缺藕根澀。飛下雌鴛鴦，塘水聲溢溢。"]'),
('yuding-16','相和歌辭：苦辛行','戎昱','唐','御定全唐诗','yuding','','[]','且莫奏短歌，聽余苦辛詞：如今刀筆士，不及屠酤兒。',118,'御定全唐詩/json/020.json','["且莫奏短歌，聽余苦辛詞：如今刀筆士，不及屠酤兒。", "少年無事學詩賦，豈意文章複相誤。東西南北少知音，", "天地生我尚如此，陌上他人何足論。誰謂西江深，", "險巇惟有世間路，一向令人堪白頭。貴人立意不可測，", "悲來卻憶漢天子，不棄相如家舊貧。飲酒酒能散羈愁，"]'),
('yuding-17','相和歌辭：秋胡行','高適','唐','御定全唐诗','yuding','','[]','妾本邯鄲未嫁時，容華倚翠人未知。一朝結髮從君子，',136,'御定全唐詩/json/020.json','["妾本邯鄲未嫁時，容華倚翠人未知。一朝結髮從君子，", "蕙樓獨臥頻度春，彩落辭君幾徂暑。三月垂楊蠶未眠，", "妾家夫婿輕離久，寸心誓與長相守。願言行路莫多情，", "勞心苦力終無恨，所冀君恩那可依。聞說行人已歸止，", "從來自隱無疑背，直為君情也相會。如何咫尺仍有情，", "莫道向來不得意，故欲留規誡後人。"]'),
('yuding-18','相和歌辭：善哉行','貫休','唐','御定全唐诗','yuding','','[]','有美一人兮婉如清揚，識曲別音兮令姿煌煌。',62,'御定全唐詩/json/020.json','["有美一人兮婉如清揚，識曲別音兮令姿煌煌。", "繡袂捧琴兮登君子堂，如彼萱草兮使我憂忘。", "欲贈之以紫玉尺，白銀璫，久不見之兮湘水茫茫。"]'),
('yuding-19','相和歌辭：善哉行','齊己','唐','御定全唐诗','yuding','','[]','大鵬刷翮謝溟渤，青雲萬層高突出。下視秋濤空渺彌，',40,'御定全唐詩/json/020.json','["大鵬刷翮謝溟渤，青雲萬層高突出。下視秋濤空渺彌，", "願除嗜欲待身輕，攜手同尋列仙事。"]'),
('yuding-20','相和歌辭：來日大難','李白','唐','御定全唐诗','yuding','','[]','來日一身，攜糧負薪。道長食盡，苦口焦唇。今日醉飽，',72,'御定全唐詩/json/020.json','["來日一身，攜糧負薪。道長食盡，苦口焦唇。今日醉飽，", "乘龍上三天，飛目瞻兩角。授以神藥，金丹滿握。", "蟪蛄蒙恩，深愧短促。思填東海，強銜一木。道重天地，"]'),
('yuding-21','相和歌辭：當來日大難','元稹','唐','御定全唐诗','yuding','','[]','當來日大難行，前有阪，後有坑，大樑側，小梁傾。',76,'御定全唐詩/json/020.json','["當來日大難行，前有阪，後有坑，大樑側，小梁傾。", "兩軸相絞，兩輪相撐。大牛豎，小牛橫。烏啄牛背，", "輪軸自撓，牽制不停。泥潦漸久，荊棘旋生。", "行必不得，不如不行。"]'),
('yuding-22','相和歌辭：隴西行','王維','唐','御定全唐诗','yuding','','[]','十裏一走馬，五裏一揚鞭。都護軍書至，匈奴圍酒泉。',36,'御定全唐詩/json/020.json','["十裏一走馬，五裏一揚鞭。都護軍書至，匈奴圍酒泉。", "關山正飛雪，烽戍斷無煙。"]'),
('yuding-23','相和歌辭：隴西行','耿湋','唐','御定全唐诗','yuding','','[]','雪下陽關路，人稀隴戍頭。封狐猶未翦，邊將豈無羞。',48,'御定全唐詩/json/020.json','["雪下陽關路，人稀隴戍頭。封狐猶未翦，邊將豈無羞。", "白草三冬色，黃雲萬里愁。因思李都尉，畢竟不封侯。"]'),
('yuding-24','相和歌辭：隴西行','長孫佐輔','唐','御定全唐诗','yuding','','[]','陰雲凝朔氣，隴上正飛雪。四月草不生，北風勁如切。',96,'御定全唐詩/json/020.json','["陰雲凝朔氣，隴上正飛雪。四月草不生，北風勁如切。", "朝來羽書急，夜救長城窟。道隘行不前，相呼抱鞍歇。", "人寒指欲墮，馬凍蹄亦裂。射雁旋充饑，斧冰還止渴。", "寧辭解圍鬥，但恐乘疲沒。早晚邊候空，歸來養羸卒。"]'),
('yuding-25','相和歌辭：東門行','柳宗元','唐','御定全唐诗','yuding','','[]','漢家三十六將軍，東方雷動橫陣雲。雞鳴函穀客如霧，',72,'御定全唐詩/json/020.json','["漢家三十六將軍，東方雷動橫陣雲。雞鳴函穀客如霧，", "當街一叱百吏走，馮敬胸中函匕首。凶徒側耳潛愜心，", "羌胡轂下一朝起，敵國舟中非所擬。安陵誰辨削礪功，"]'),
('yuding-26','相和歌辭：飲馬長城窟行','李世民','唐','御定全唐诗','yuding','','[]','塞外悲風切，交河冰已結。瀚海百重波，陰山千里雪。',120,'御定全唐詩/json/020.json','["塞外悲風切，交河冰已結。瀚海百重波，陰山千里雪。", "迥戍危烽火，層巒引高節。悠悠卷旆旌，飲馬出長城。", "寒沙連騎跡，朔吹斷邊聲。胡塵清玉塞，羌笛韻金鉦。", "絕漠干戈戢，車徒振原隰。都尉反龍堆，將軍旋馬邑。", "揚麾氛霧靜，紀石功名立。荒裔一戎衣，雲台凱歌入。"]'),
('yuding-27','相和歌辭：飲馬長城窟行','虞世南','唐','御定全唐诗','yuding','','[]','馳馬渡河幹，流深馬渡難。前逢錦車使，都護在樓蘭。',96,'御定全唐詩/json/020.json','["馳馬渡河幹，流深馬渡難。前逢錦車使，都護在樓蘭。", "輕騎猶銜勒，疑兵尚解鞍。溫池下絕澗，棧道接危巒。", "拓地勳未賞，亡城律詎寬。有月關猶暗，經春隴尚寒。", "雲昏無複影，冰合不聞湍。懷君不可遇，聊持報一餐。"]'),
('yuding-28','相和歌辭：飲馬長城窟行','袁朗','唐','御定全唐诗','yuding','','[]','朔風動秋草，清蹕長安道。長城連不窮，所以隔華戎。',180,'御定全唐詩/json/020.json','["朔風動秋草，清蹕長安道。長城連不窮，所以隔華戎。", "規模惟聖作，荷負曉成功。鳥庭已向內，龍荒更鑿空。", "玉關塵卷靜，金微路已通。湯征隨北怨，舜詠起南風。", "畫野功初立，綏邊事雲集。朝服踐狼居，凱歌旋馬邑。", "山響傳鳳吹，霜華藻瓊鈒。屬國擁節歸，單于款關入。", "日落寒雲起，驚沙被原隰。零落葉已寒，河流清且急。", "四時徭役盡，千載干戈戢。太平今若斯，汗馬竟無施。", "惟當事筆研，歸去草封禪。"]'),
('yuding-29','相和歌辭：飲馬長城窟行','王翰','唐','御定全唐诗','yuding','','[]','長安少年無遠圖，一生惟羨執金吾。騏驎前殿拜天子，',120,'御定全唐詩/json/020.json','["長安少年無遠圖，一生惟羨執金吾。騏驎前殿拜天子，", "遙聞鼙鼓動地來，傳道單于夜猶戰。此時顧恩甯顧身，", "回來飲馬長城窟，長安道傍多白骨。問之耆老何代人，", "無罪見誅功不賞，孤魂流落此城邊。當昔秦王按劍起，", "秦王築城何太愚，天實亡秦非北胡。一朝禍起蕭牆內，"]'),
('yuding-30','相和歌辭：飲馬長城窟行','王建','唐','御定全唐诗','yuding','','[]','長城窟，長城窟邊多馬骨。古來此地無井泉，',44,'御定全唐詩/json/020.json','["長城窟，長城窟邊多馬骨。古來此地無井泉，", "蹄跡未幹人去近，續後馬來泥汙盡。枕弓睡著待水生，"]'),
('yuding-31','相和歌辭：飲馬長城窟行','子蘭','唐','御定全唐诗','yuding','','[]','遊客長城下，飲馬長城窟。馬嘶聞水腥，為浸征人骨。',72,'御定全唐詩/json/020.json','["遊客長城下，飲馬長城窟。馬嘶聞水腥，為浸征人骨。", "豈不是流泉，終不成潺湲。洗盡骨上土，不洗骨中冤。", "骨若比流水，四海有還魂。空流嗚咽聲，聲中疑是言。"]'),
('yuding-32','相和歌辭：上留田','李白','唐','御定全唐诗','yuding','','[]','行至上留田，孤墳何崢嶸。積此萬古恨，春草不復生。',171,'御定全唐詩/json/020.json','["行至上留田，孤墳何崢嶸。積此萬古恨，春草不復生。", "悲風四邊來，腸斷白楊聲。借問誰家地，埋沒蒿裏塋。", "古老向餘言，言是上留田，蓬科馬鬣今已平。", "昔之弟死兄不葬，他人於此舉銘旌。一鳥死，百鳥鳴；", "一獸死，百獸驚。桓山之禽別離苦，欲去回翔不能征。", "田氏倉卒骨肉分，青天白日摧紫荊。交柯之木本同形，", "孤竹延陵，讓國揚名；高風緬邈，頹波激清。", "尺布之謠，塞耳不能聽。"]'),
('yuding-33','相和歌辭：上留田','貫休','唐','御定全唐诗','yuding','','[]','父不父，兄不兄，上留田，蝥賊生。徒陟岡，淚崢嶸。',46,'御定全唐詩/json/020.json','["父不父，兄不兄，上留田，蝥賊生。徒陟岡，淚崢嶸。", "我欲使諸凡鳥雀，盡變為鶺鴒；我欲使諸凡草木，"]'),
('yuding-34','相和歌辭：安樂宮','李賀','唐','御定全唐诗','yuding','','[]','深井桐烏起，尚複牽清水。未盥邵陵王，瓶中弄長翠。',60,'御定全唐詩/json/020.json','["深井桐烏起，尚複牽清水。未盥邵陵王，瓶中弄長翠。", "新城安樂宮，宮如鳳凰翅。歌回蠟版鳴，大綰提壺使。", "綠繁悲水曲，茱萸別秋子。"]'),
('yuding-35','相和歌辭：放歌行','王昌齡','唐','御定全唐诗','yuding','','[]','南渡洛陽津，西望十二樓。明堂坐天子，月朔朝諸侯。',144,'御定全唐詩/json/020.json','["南渡洛陽津，西望十二樓。明堂坐天子，月朔朝諸侯。", "清樂動千門，皇風被九州。慶雲從東來，泱漭抱日流。", "升平貴論道，文墨將何求。有詔征草澤，微臣獻謀猷。", "冠冕如星羅，拜揖曹與周。望塵非吾事，入賦且遲留。", "幸蒙國士識，因脫負薪裘。今者放歌行，以慰梁父愁。", "但營數鬥祿，奉養毋豐羞。若得金膏遂，飛雲亦可儔。"]'),
('yuding-36','相和歌辭：野田黃雀行','李白','唐','御定全唐诗','yuding','','[]','游莫逐炎洲翠，棲莫近吳宮燕。吳宮火起焚爾窠，',22,'御定全唐詩/json/020.json','["游莫逐炎洲翠，棲莫近吳宮燕。吳宮火起焚爾窠，"]'),
('yuding-37','相和歌辭：野田黃雀行','儲光羲','唐','御定全唐诗','yuding','','[]','嘖嘖野田雀，不知軀體微。閑穿深蒿裏，爭食複爭飛。',84,'御定全唐詩/json/020.json','["嘖嘖野田雀，不知軀體微。閑穿深蒿裏，爭食複爭飛。", "窮老一頹舍，棗多桑樹稀。無棗猶可食，無桑何以衣。", "蕭條空倉暮，相引時來歸。邪路豈不捷，渚田豈不肥。", "水長路且壞，惻惻與心違。"]'),
('yuding-38','相和歌辭：野田黃雀行','貫休','唐','御定全唐诗','yuding','','[]','高樹風多，吹爾巢落。深蒿葉暖，宜爾依薄。莫近鴞類，',25,'御定全唐詩/json/020.json','["高樹風多，吹爾巢落。深蒿葉暖，宜爾依薄。莫近鴞類，"]'),
('yuding-39','相和歌辭：野田黃雀行','齊己','唐','御定全唐诗','yuding','','[]','雙雙野田雀，上下同飲啄。暖去棲蓬蒿，寒歸傍籬落。',48,'御定全唐詩/json/020.json','["雙雙野田雀，上下同飲啄。暖去棲蓬蒿，寒歸傍籬落。", "殷勤避羅網，乍可遇雕鶚。雕鶚雖不仁，分明在寥廓。"]'),
('yuding-40','相和歌辭：雁門太守行','李賀','唐','御定全唐诗','yuding','','[]','黑雲壓城城欲摧，甲光向月金鱗開。角聲滿天秋色裏，',40,'御定全唐詩/json/020.json','["黑雲壓城城欲摧，甲光向月金鱗開。角聲滿天秋色裏，", "報君黃金臺上意，提攜玉龍為君死。"]'),
('yuding-41','相和歌辭：雁門太守行','張祜','唐','御定全唐诗','yuding','','[]','城頭月沒霜如水，趚趚蹋沙人似鬼。燈前拭淚試香裘，',48,'御定全唐詩/json/020.json','["城頭月沒霜如水，趚趚蹋沙人似鬼。燈前拭淚試香裘，", "寄語年少妻莫哀，魚金虎竹天上來，雁門山邊骨成灰。"]'),
('yuding-42','相和歌辭：雁門太守行','莊南傑','唐','御定全唐诗','yuding','','[]','旌旗閃閃搖天末，長笛橫吹虜塵闊。跨下嘶風白練獰，',40,'御定全唐詩/json/020.json','["旌旗閃閃搖天末，長笛橫吹虜塵闊。跨下嘶風白練獰，", "九泉寂寞葬秋蟲，濕雲荒草啼秋思。"]'),
('yuding-43','相和歌辭：飛來雙白鶴','虞世南','唐','御定全唐诗','yuding','','[]','飛來雙白鶴，奮翼遠淩煙。雙棲集紫蓋，一舉背青田。',120,'御定全唐詩/json/020.json','["飛來雙白鶴，奮翼遠淩煙。雙棲集紫蓋，一舉背青田。", "颺影過伊洛，流聲入管弦。鳴群倒景外，刷羽閬風前。", "映海疑浮雪，拂澗瀉飛泉。燕雀寧知去，蜉蝣不識還。", "何言別儔侶，從此間山川。顧步已相失，裴回反自憐。", "危心猶警露，哀響詎聞天。無因振六翮，輕舉複隨仙。"]'),
('yuding-44','相和歌辭：門有車馬客行','虞世南','唐','御定全唐诗','yuding','','[]','財雄重交結，戚裏擅豪華。曲台臨上路，高門抵狹斜。',142,'御定全唐詩/json/020.json','["財雄重交結，戚裏擅豪華。曲台臨上路，高門抵狹斜。", "赭汗千金馬，繡轂五香車。白鶴隨飛蓋，朱鷺入鳴笳。", "夏蓮開劍水，春桃髮露花。輕裙染回雪，浮蟻泛流霞。", "高談辨飛兔，摛藻握靈蛇。逢恩借羽翼，失路委泥沙。", "曖曖風煙晚，路長歸騎遠。日斜青瑣第，塵飛金谷苑。", "危弦促柱奏巴渝，遺簪墮珥解羅襦。如何守直道，"]'),
('yuding-45','相和歌辭：門有車馬客行','李白','唐','御定全唐诗','yuding','','[]','門有車馬客，金鞍曜朱輪。謂從丹霄落，乃是故鄉親。',156,'御定全唐詩/json/020.json','["門有車馬客，金鞍曜朱輪。謂從丹霄落，乃是故鄉親。", "呼兒掃中堂，坐客論悲辛。對酒兩不飲，停觴淚盈巾。", "歎我萬里遊，飄颻三十春。空談霸王略，紫綬不掛身。", "雄劍藏玉匣，陰符生素塵。廓落無所合，流離湘水濱。", "借問宗黨間，多為泉下人。生苦百戰役，死托萬鬼鄰。", "北風揚胡沙，埋翳周與秦。大運且如此，蒼穹寧匪仁。", "惻愴竟何道，存亡任大鈞。"]'),
('yuding-46','相和歌辭：蜀道難','張文琮','唐','御定全唐诗','yuding','','[]','梁山鎮地險，積石阻雲端。深谷下寥廓，層岩上鬱盤。',48,'御定全唐詩/json/020.json','["梁山鎮地險，積石阻雲端。深谷下寥廓，層岩上鬱盤。", "飛梁架絕嶺，棧道接危巒。攬轡獨長息，方知斯路難。"]'),
('yuding-47','相和歌辭：蜀道難','李白','唐','御定全唐诗','yuding','','[]','噫籲嚱，危乎高哉！蜀道之難，難於上青天。',184,'御定全唐詩/json/020.json','["噫籲嚱，危乎高哉！蜀道之難，難於上青天。", "蠶叢及魚鳧，開國何茫然。爾來四萬八千歲，", "地崩山摧壯士死，然後天梯石棧方鉤連。", "上有六龍回日之高標，下有沖波逆折之回川。", "黃鶴之飛尚不得，猿猱欲度愁攀緣。青泥何盤盤，", "問君西遊何時還，畏途巉岩不可攀。但見悲鳥號枯木，", "其嶮也若此，嗟爾遠道之人胡為乎來哉！", "劍閣崢嶸而崔嵬，一夫當關，萬夫莫開。所守或匪親，", "蜀道之難難於上青天，側身西望長咨嗟。"]'),
('yuding-48','相和歌辭：棹歌行','駱賓王','唐','御定全唐诗','yuding','','[]','寫月圖黃罷，淩波拾翠通。鏡花搖芰日，衣麝入荷風。',72,'御定全唐詩/json/020.json','["寫月圖黃罷，淩波拾翠通。鏡花搖芰日，衣麝入荷風。", "葉密舟難蕩，蓮疏浦易空。鳳媒羞自托，鴛翼恨難窮。", "秋帳燈花翠，倡樓粉色紅。相思無別曲，並在棹歌中。"]'),
('yuding-49','相和歌辭：棹歌行','徐堅','唐','御定全唐诗','yuding','','[]','棹女飾銀鉤，新妝下翠樓。霜絲青桂楫，蘭枻紫霞舟。',108,'御定全唐詩/json/020.json','["棹女飾銀鉤，新妝下翠樓。霜絲青桂楫，蘭枻紫霞舟。", "水落金陵曙，風起洞庭秋。扣船過曲浦，飛帆越回流。", "影入桃花浪，香飄杜若洲。洲長殊未返，蕭散雲霞晚。", "日下大江平，煙生歸岸遠。岸遠聞潮波，爭途遊戲多。", "因聲趙津女，來聽采菱歌。"]'),
('yuding-50','相和歌辭：胡無人行','徐彥伯','唐','御定全唐诗','yuding','','[]','十月繁霜下，征人遠鑿空。雲搖錦更節，海照角端弓。',48,'御定全唐詩/json/020.json','["十月繁霜下，征人遠鑿空。雲搖錦更節，海照角端弓。", "暗磧埋砂樹，沖飆卷塞蓬。方隨膜拜入，歌舞玉門中。"]'),
('yuding-51','相和歌辭：胡無人行','聶夷中','唐','御定全唐诗','yuding','','[]','男兒徇大義，立節不沽名。腰間懸陸離，大歌胡無行。',96,'御定全唐詩/json/020.json','["男兒徇大義，立節不沽名。腰間懸陸離，大歌胡無行。", "不讀戰國書，不覽黃石經。醉臥咸陽樓，夢入受降城。", "更願生羽翼，飛身入青冥。請攜天子劍，斫下旄頭星。", "自然胡無人，雖有無戰爭。悠哉典屬國，驅羊老一生。"]'),
('yuding-52','相和歌辭：胡無人行','李白','唐','御定全唐诗','yuding','','[]','嚴風吹霜海草凋，筋幹精堅胡馬驕。漢家戰士三十萬，',76,'御定全唐詩/json/020.json','["嚴風吹霜海草凋，筋幹精堅胡馬驕。漢家戰士三十萬，", "天兵照雪下玉關，虜箭如沙射金甲。雲龍風虎盡交回，", "懸胡青天上，埋胡紫塞旁。胡無人，漢道昌，", "胡無人，漢道昌。"]'),
('yuding-53','相和歌辭：胡無人行','貫休','唐','御定全唐诗','yuding','','[]','霍嫖姚，趙充國，天子將之平朔漠。肉胡之肉，',42,'御定全唐詩/json/020.json','["霍嫖姚，趙充國，天子將之平朔漠。肉胡之肉，", "但令一物得所，八表來賓，亦何必令彼胡無人。"]'),
('yuding-54','相和歌辭：白頭吟','劉希夷','唐','御定全唐诗','yuding','','[]','洛陽城東桃李花，飛來飛去落誰家。洛陽女兒惜顏色，',112,'御定全唐詩/json/020.json','["洛陽城東桃李花，飛來飛去落誰家。洛陽女兒惜顏色，", "已見松柏摧為薪，更聞桑田變成海。古人無複洛城東，", "寄言全盛紅顏子，須憐半死白頭翁。此翁白頭真可憐，", "光祿池台文錦繡，將軍樓閣畫神仙。一朝臥病無人識，", "但看舊來歌舞地，惟有黃昏鳥雀悲。"]'),
('yuding-55','相和歌辭：白頭吟二首','李白','唐','御定全唐诗','yuding','','[]','錦水東北流，波蕩雙鴛鴦。雄巢漢宮樹，雌弄秦草芳。',274,'御定全唐詩/json/020.json','["錦水東北流，波蕩雙鴛鴦。雄巢漢宮樹，雌弄秦草芳。", "甯同萬死碎綺翼，不忍雲間兩分張。此時阿嬌正嬌妒，", "相如作賦得黃金，丈夫好新多異心，一朝將聘茂陵女，", "兔絲固無情，隨風任顛倒。誰使女蘿枝，而來強縈抱。", "兩草猶一心，人心不如草。莫卷龍須席，從他生網絲。", "且留琥珀枕，或有夢來時。覆水再收豈滿杯，", "錦水東流碧，波蕩雙鴛鴦。雄巢漢宮樹，雌弄秦草芳。", "相如去蜀謁武帝，赤車駟馬生輝光。一朝再覽大人作，", "相如不憶貧賤日，官高金多聘私室。茂陵姝子皆見求，", "五起雞三唱，清晨白頭吟。長籲不整綠雲鬢，", "東流不作西歸水，落花辭枝羞故林。頭上玉燕釵，", "願持照新人，雙對可憐影。覆水卻收不滿杯，"]'),
('yuding-56','相和歌辭：白頭吟','張籍','唐','御定全唐诗','yuding','','[]','請君膝上琴，彈我白頭吟。憶昔君前嬌笑語，',68,'御定全唐詩/json/020.json','["請君膝上琴，彈我白頭吟。憶昔君前嬌笑語，", "春天百草秋始衰，棄我不待白頭時。羅襦玉珥色未暗，", "人心回互自無窮，眼前好惡那能定。君恩已去若再返，"]'),
('yuding-57','相和歌辭：反白頭吟','白居易','唐','御定全唐诗','yuding','','[]','炎炎者烈火，營營者小蠅。火不熱真玉，蠅不點清冰。',120,'御定全唐詩/json/020.json','["炎炎者烈火，營營者小蠅。火不熱真玉，蠅不點清冰。", "此苟無所受，彼莫能相仍。乃知物性中，各有能不能。", "古稱怨報死，則人有所懲。懲淫或應可，在道未為弘。", "譬如蜩鷃徒，啾啾啅龍鵬。宜當委之去，寥廓高飛騰。", "豈能泥塵下，區區酬怨憎。胡為坐自苦，吞悲仍撫膺。"]'),
('yuding-58','相和歌辭：決絕詞三首','元稹','唐','御定全唐诗','yuding','','[]','乍可為天上牽牛織女星，不願為庭前紅槿枝。',225,'御定全唐詩/json/020.json','["乍可為天上牽牛織女星，不願為庭前紅槿枝。", "七月七日一相見，故心終不移。那能朝開暮飛去，", "對面且如此，背面當何知。春風撩亂伯勞語，", "噫春冰之將泮，何餘懷之獨結。有美一人，於焉曠絕。", "一日不見，比一日於三年，況三年之曠別。", "水得風兮小而已波，筍在苞兮高不見節。矧桃李之當春，", "幸他人之既不我先，又安能使他人之終不我奪。已焉哉，", "夜夜相抱眠，幽懷尚沉結。那堪一年事，長遣一宵說。", "但感久相思，何暇暫相悅。虹橋薄夜成，龍駕侵晨列。", "生憎野鵲往遲回，死恨天雞識時節。曙色漸曈曨，"]'),
('yuding-59','相和歌辭：梁甫吟','李白','唐','御定全唐诗','yuding','','[]','長嘯梁甫吟，何時見陽春？君不見朝歌屠叟辭棘津，',143,'御定全唐詩/json/020.json','["長嘯梁甫吟，何時見陽春？君不見朝歌屠叟辭棘津，", "廣張三千六百鈞，風雅暗與文王親。大賢虎變愚不測，", "東下齊城七十二，指麾楚漢如旋蓬。狂生落拓尚如此，", "閶闔九門不可通，以額叩關閽者怒。白日不照吾精誠，", "手接飛猱搏雕虎，側足焦原未言苦。智者可卷愚者豪，", "吳楚弄兵無劇孟，亞夫咍爾為徒勞。梁父吟，梁父吟，"]'),
('yuding-60','相和歌辭：東武吟','李白','唐','御定全唐诗','yuding','','[]','好古笑流俗，素聞賢達風。方希佐明主，長揖辭成功。',204,'御定全唐詩/json/020.json','["好古笑流俗，素聞賢達風。方希佐明主，長揖辭成功。", "白日在高天，回光燭微躬。恭承鳳凰詔，欻起雲蘿中。", "清切紫霄迥，優遊丹禁通。君王賜顏色，聲價淩煙虹。", "乘輿擁翠蓋，扈從金城東。寶馬麗絕景，錦衣入新豐。", "倚岩望松雪，對酒鳴絲桐。因學揚子雲，獻賦甘泉宮。", "天書美片善，清芬播無窮。歸來入咸陽，談笑皆王公。", "一朝去金馬，飄落成飛蓬。賓友日疏散，玉尊亦已空。", "才力猶可倚，不慚世上雄。閑作東武吟，曲盡情未終。", "書此謝知己，吾尋黃綺翁。"]'),
('yuding-61','相和歌辭：怨詩二首','薛奇童','唐','御定全唐诗','yuding','','[]','日晚梧桐落，微寒入禁垣。月懸三雀觀，霜度萬秋門。',96,'御定全唐詩/json/020.json','["日晚梧桐落，微寒入禁垣。月懸三雀觀，霜度萬秋門。", "豔舞矜新寵，愁容泣舊恩。不堪深殿裏，簾外欲黃昏。", "禁苑春風起，流鶯繞合歡。玉窗通日氣，珠箔卷輕寒。", "楊葉垂金砌，梨花入井闌。君王好長袖，新作舞衣寬。"]'),
('yuding-62','相和歌辭：怨詩','張汯','唐','御定全唐诗','yuding','','[]','去年離別雁初歸，今夜裁縫螢已飛。',32,'御定全唐詩/json/020.json','["去年離別雁初歸，今夜裁縫螢已飛。", "征客去來音信斷，不知何處寄寒衣。"]'),
('yuding-63','相和歌辭：怨詩','劉元濟','唐','御定全唐诗','yuding','','[]','玉關芳信斷，蘭閨錦字新。愁來好自抑，念切已含嚬。',48,'御定全唐詩/json/020.json','["玉關芳信斷，蘭閨錦字新。愁來好自抑，念切已含嚬。", "虛牖風驚夢，空床月厭人。歸期儻可促，勿度柳園春。"]'),
('yuding-64','相和歌辭：怨詩三首','李暇','唐','御定全唐诗','yuding','','[]','羅敷初總髻，蕙芳正嬌小。月落始歸船，春眠恒著曉。',72,'御定全唐詩/json/020.json','["羅敷初總髻，蕙芳正嬌小。月落始歸船，春眠恒著曉。", "何處期郎游，小苑花台間。相憶不可見，且複乘月還。", "別來花照路，別後露垂葉。歌舞須及時，如何坐悲妾。"]'),
('yuding-65','相和歌辭：怨詩二首','崔國輔','唐','御定全唐诗','yuding','','[]','樓前桃李疏，池上芙蓉落。織錦猶未成，蟲聲入羅幕。',48,'御定全唐詩/json/020.json','["樓前桃李疏，池上芙蓉落。織錦猶未成，蟲聲入羅幕。", "妾有羅衣裳，秦王在時作。為舞春風多，秋來不堪著。"]'),
('yuding-66','相和歌辭：怨詩','孟郊','唐','御定全唐诗','yuding','','[]','試妾與君淚，兩處滴池水。看取芙蓉花，今年為誰死。',24,'御定全唐詩/json/020.json','["試妾與君淚，兩處滴池水。看取芙蓉花，今年為誰死。"]'),
('yuding-67','相和歌辭：怨詩','劉義','唐','御定全唐诗','yuding','','[]','君莫嫌醜婦，醜婦死守貞。山頭一怪石，長作望夫名。',48,'御定全唐詩/json/020.json','["君莫嫌醜婦，醜婦死守貞。山頭一怪石，長作望夫名。", "鳥有並翼飛，獸有比肩行。丈夫不立義，豈如鳥獸情。"]'),
('yuding-68','相和歌辭：怨詩','鮑溶','唐','御定全唐诗','yuding','','[]','女蘿寄松柏，綠蔓花綿綿。三五定君婚，結髮早移天。',132,'御定全唐詩/json/020.json','["女蘿寄松柏，綠蔓花綿綿。三五定君婚，結髮早移天。", "肅肅羊雁禮，泠泠琴瑟篇。恭承采蘩祀，敢效同居賢。", "皎日不留景，良時如逝川。秋心還遺愛，春貌無歸妍。", "翠袖洗朱粉，碧階對綺錢。新人易如玉，廢瑟難為弦。", "寄羨蕣華木，榮名香閣前。豈無搖落苦，貴與根蒂連。", "希君舊光景，照妾薄暮年。"]'),
('yuding-69','相和歌辭：怨詩','白居易','唐','御定全唐诗','yuding','','[]','奪寵心那慣，尋思倚殿門。不知移舊愛，何處作新恩。',24,'御定全唐詩/json/020.json','["奪寵心那慣，尋思倚殿門。不知移舊愛，何處作新恩。"]'),
('yuding-70','相和歌辭：怨詩二首','姚氏月華','唐','御定全唐诗','yuding','','[]','春水悠悠春草綠，對此思君淚相續。',64,'御定全唐詩/json/020.json','["春水悠悠春草綠，對此思君淚相續。", "羞將離恨向東風，理盡秦箏不成曲。", "與君形影分胡越，玉枕終年對離別。", "登臺北望煙雨深，回身泣向寥天月。"]'),
('yuding-71','相和歌辭：怨歌行','虞世南','唐','御定全唐诗','yuding','','[]','紫殿秋風冷，雕甍白日沉。裁紈淒斷曲，織素別離心。',84,'御定全唐詩/json/020.json','["紫殿秋風冷，雕甍白日沉。裁紈淒斷曲，織素別離心。", "掖庭羞改畫，長門不惜金。寵移恩稍薄，情疏恨轉深。", "香銷翠羽帳，弦斷鳳凰琴。鏡前紅粉歇，階上綠苔侵。", "誰言掩歌扇，翻作白頭吟。"]'),
('yuding-72','相和歌辭：怨歌行','李白','唐','御定全唐诗','yuding','','[]','十五入漢宮，花顏笑春紅。君王選玉色，侍寢金屏中。',108,'御定全唐詩/json/020.json','["十五入漢宮，花顏笑春紅。君王選玉色，侍寢金屏中。", "薦枕嬌夕月，卷衣戀春風。甯知趙飛燕，奪寵恨無窮。", "沉憂能傷人，綠鬢成霜蓬。一朝不得意，世事徒為空。", "鷫鸘換美酒，舞衣罷雕籠。寒苦不忍言，為君奏絲桐。", "腸斷弦亦絕，悲心夜忡忡。"]'),
('yuding-73','相和歌辭：怨歌行','吳少微','唐','御定全唐诗','yuding','','[]','城南有怨婦，含怨倚蘭叢。自謂二八時，歌舞入漢宮，',94,'御定全唐詩/json/020.json','["城南有怨婦，含怨倚蘭叢。自謂二八時，歌舞入漢宮，", "建章西宮煥若神，燕趙美女二千人。君王厭德不忘新，", "長信重門晝掩關，清房曉帳幽且閑。綺窗蟲網氛塵色，", "自憐轉晚暮，試逐佳游芳草路。小腰麗女奪人奇，"]'),
('yuding-74','相和歌辭：明月照高樓','雍陶','唐','御定全唐诗','yuding','','[]','朗月何高高，樓中簾影寒。一婦獨含歎，四坐誰成歡。',96,'御定全唐詩/json/020.json','["朗月何高高，樓中簾影寒。一婦獨含歎，四坐誰成歡。", "時節屢已移，遊旅杳不還。滄溟倘未涸，妾淚終不幹。", "君若無定雲，妾若不動山。雲行出山易，山逐雲去難。", "願為邊塞塵，因風委君顏。君顏良洗多，蕩妾濁水間。"]'),
('yuding-75','相和歌辭：長門怨','徐賢妃','唐','御定全唐诗','yuding','','[]','舊愛柏梁台，新寵昭陽殿。守分辭方輦，含情泣團扇。',48,'御定全唐詩/json/020.json','["舊愛柏梁台，新寵昭陽殿。守分辭方輦，含情泣團扇。", "一朝歌舞榮，夙昔詩書賤。頹恩誠已矣，覆水難重薦。"]'),
('yuding-76','相和歌辭：長門怨','沈佺期','唐','御定全唐诗','yuding','','[]','月皎風泠泠，長門次掖庭。玉階聞墜葉，羅幌見飛螢。',48,'御定全唐詩/json/020.json','["月皎風泠泠，長門次掖庭。玉階聞墜葉，羅幌見飛螢。", "清露凝珠綴，流塵下翠屏。妾心君未察，愁歎劇繁星。"]'),
('yuding-77','相和歌辭：長門怨','吳少微','唐','御定全唐诗','yuding','','[]','月出映曾城，孤圜上太清。君王春愛歇，枕席涼風生。',72,'御定全唐詩/json/020.json','["月出映曾城，孤圜上太清。君王春愛歇，枕席涼風生。", "怨咽不能寢，踟躕步前楹。空階白露色，百草塞蟲鳴。", "念昔金房裏，猶嫌玉座輕。如何嬌所誤，長夜泣恩情。"]'),
('yuding-78','相和歌辭：長門怨','張修之','唐','御定全唐诗','yuding','','[]','長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。',48,'御定全唐詩/json/020.json','["長門落景盡，洞房秋月明。玉階草露積，金屋網塵生。", "妾妒今應改，君恩昔未平。寄語臨邛客，何時作賦成。"]'),
('yuding-79','相和歌辭：長門怨','裴交泰','唐','御定全唐诗','yuding','','[]','自閉長門經幾秋，羅衣濕盡淚還流。',32,'御定全唐詩/json/020.json','["自閉長門經幾秋，羅衣濕盡淚還流。", "一種蛾眉明月夜，南宮歌管北宮愁。"]'),
('yuding-80','相和歌辭：長門怨','劉阜','唐','御定全唐诗','yuding','','[]','宮殿沉沉月欲分，昭陽更漏不堪聞。',32,'御定全唐詩/json/020.json','["宮殿沉沉月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('yuding-81','相和歌辭：長門怨','袁暉','唐','御定全唐诗','yuding','','[]','早知君愛歇，本自無縈妒。誰使恩情深，今來反相誤。',48,'御定全唐詩/json/020.json','["早知君愛歇，本自無縈妒。誰使恩情深，今來反相誤。", "愁眠羅帳曉，泣坐金閨暮。獨有夢中魂，猶言意如故。"]'),
('yuding-82','相和歌辭：長門怨','劉言史','唐','御定全唐诗','yuding','','[]','獨坐爐邊結夜愁，暫時恩去亦難留。',32,'御定全唐詩/json/020.json','["獨坐爐邊結夜愁，暫時恩去亦難留。", "手持金箸垂紅淚，亂撥寒灰不舉頭。"]'),
('yuding-83','相和歌辭：長門怨二首','李白','唐','御定全唐诗','yuding','','[]','天回北斗掛西樓，金屋無人螢火流。',64,'御定全唐詩/json/020.json','["天回北斗掛西樓，金屋無人螢火流。", "月光欲到長門殿，別作深宮一段愁。", "桂殿長愁不記春，黃金四屋起秋塵。", "夜懸明鏡青天上，獨照長門宮裏人。"]'),
('yuding-84','相和歌辭：長門怨','李華','唐','御定全唐诗','yuding','','[]','弱體鴛鴦薦，啼妝翡翠衾。鴉鳴秋殿曉，人靜禁門深。',48,'御定全唐詩/json/020.json','["弱體鴛鴦薦，啼妝翡翠衾。鴉鳴秋殿曉，人靜禁門深。", "每憶椒房寵，那堪永巷陰。日驚羅帶緩，非復舊來心。"]'),
('yuding-85','相和歌辭：長門怨','岑參','唐','御定全唐诗','yuding','','[]','君王嫌妾妒，閉妾在長門。舞袖垂新寵，愁眉結舊恩。',48,'御定全唐詩/json/020.json','["君王嫌妾妒，閉妾在長門。舞袖垂新寵，愁眉結舊恩。", "綠錢生履跡，紅粉濕啼痕。羞被桃花笑，看春獨不言。"]'),
('yuding-86','相和歌辭：長門怨','齊浣','唐','御定全唐诗','yuding','','[]','煢煢孤思逼，寂寂長門夕。妾妒亦非深，君恩那不惜。',48,'御定全唐詩/json/020.json','["煢煢孤思逼，寂寂長門夕。妾妒亦非深，君恩那不惜。", "攜琴就玉階，調悲聲未諧。將心托明月，流影入君懷。"]'),
('yuding-87','相和歌辭：長門怨','劉長卿','唐','御定全唐诗','yuding','','[]','何事長門閉，珠簾只自垂。月移深殿早，春向後宮遲。',48,'御定全唐詩/json/020.json','["何事長門閉，珠簾只自垂。月移深殿早，春向後宮遲。", "蕙草生閑地，梨花發舊枝。芳菲自恩幸，看卻被風吹。"]'),
('yuding-88','相和歌辭：長門怨','皎然','唐','御定全唐诗','yuding','','[]','春風日日閉長門，搖盪春心自夢魂。',32,'御定全唐詩/json/020.json','["春風日日閉長門，搖盪春心自夢魂。", "若遣花開只笑妾，不如桃李正無言。"]'),
('yuding-89','相和歌辭：長門怨','盧綸','唐','御定全唐诗','yuding','','[]','空宮古廊殿，寒月照斜暉。臥聽未央曲，滿箱歌舞衣。',24,'御定全唐詩/json/020.json','["空宮古廊殿，寒月照斜暉。臥聽未央曲，滿箱歌舞衣。"]'),
('yuding-90','相和歌辭：長門怨','戴叔倫','唐','御定全唐诗','yuding','','[]','自憶專房寵，曾居第一流。移恩向何處，暫妒不容收。',48,'御定全唐詩/json/020.json','["自憶專房寵，曾居第一流。移恩向何處，暫妒不容收。", "夜久絲管絕，月明宮殿秋。空將舊時意，長望鳳凰樓。"]'),
('yuding-91','相和歌辭：長門怨','劉駕','唐','御定全唐诗','yuding','','[]','禦泉長繞鳳凰樓，只是恩波別處流。',32,'御定全唐詩/json/020.json','["禦泉長繞鳳凰樓，只是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('yuding-92','相和歌辭：長門怨二首','高蟾','唐','御定全唐诗','yuding','','[]','天上何勞萬古春，君前誰是百年人。魂銷尚愧金爐燼，',72,'御定全唐詩/json/020.json','["天上何勞萬古春，君前誰是百年人。魂銷尚愧金爐燼，", "可憐明鏡來相向，何似恩光朝夕新。", "天上鳳凰休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('yuding-93','相和歌辭：長門怨','張祜','唐','御定全唐诗','yuding','','[]','日映宮牆柳色寒，笙歌遙指碧雲端。',32,'御定全唐詩/json/020.json','["日映宮牆柳色寒，笙歌遙指碧雲端。", "珠鉛滴盡無心語，強把花枝冷笑看。"]'),
('yuding-94','相和歌辭：長門怨二首','鄭穀','唐','御定全唐诗','yuding','','[]','閑把羅衣泣鳳凰，先朝曾教舞霓裳。',64,'御定全唐詩/json/020.json','["閑把羅衣泣鳳凰，先朝曾教舞霓裳。", "春來卻羨庭花落，得逐晴風出禁牆。", "流水君恩共不回，杏花爭忍掃成堆。", "殘春未必多煙雨，淚滴閑階長綠苔。"]'),
('yuding-95','相和歌辭：長門怨二首','劉氏媛','唐','御定全唐诗','yuding','','[]','雨滴梧桐秋夜長，愁心和雨到昭陽。',64,'御定全唐詩/json/020.json','["雨滴梧桐秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭卻千行更萬行。", "學畫蛾眉獨出群，當時人道便承恩。", "經年不見君王面，花落黃昏空掩門。"]'),
('yuding-96','相和歌辭：阿嬌怨','劉禹錫','唐','御定全唐诗','yuding','','[]','望見葳蕤舉翠華，試開金屋掃庭花。',32,'御定全唐詩/json/020.json','["望見葳蕤舉翠華，試開金屋掃庭花。", "須臾宮女傳來信，雲幸平陽公主家。"]'),
('yuding-97','相和歌辭：班婕妤','徐彥伯','唐','御定全唐诗','yuding','','[]','君恩忽斷絕，妾思終未央。巾櫛不可見，枕席空餘香。',48,'御定全唐詩/json/020.json','["君恩忽斷絕，妾思終未央。巾櫛不可見，枕席空餘香。", "窗暗網羅白，階秋苔蘚黃。應門寂已閉，流涕向昭陽。"]'),
('yuding-98','相和歌辭：班婕妤','嚴識玄','唐','御定全唐诗','yuding','','[]','賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。',48,'御定全唐詩/json/020.json','["賤妾如桃李，君王若歲時。秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沉沉綠草滋。榮華非此日，指輦競何辭。"]'),
('yuding-99','相和歌辭：班婕妤三首','王維','唐','御定全唐诗','yuding','','[]','玉窗螢影度，金殿人聲絕。秋夜守羅幃，孤燈耿不滅。',72,'御定全唐詩/json/020.json','["玉窗螢影度，金殿人聲絕。秋夜守羅幃，孤燈耿不滅。", "宮殿生秋草，君王恩幸疏。那堪聞鳳吹，門外度金輿。", "怪來妝閣閉，朝下不相迎。總向春園裏，花間語笑聲。"]'),
('yuding-100','相和歌辭：婕妤怨','崔湜','唐','御定全唐诗','yuding','','[]','不分君恩斷，新妝視鏡中。容華尚春日，嬌愛已秋風。',48,'御定全唐詩/json/020.json','["不分君恩斷，新妝視鏡中。容華尚春日，嬌愛已秋風。", "枕席臨窗曉，幃屏向月空。年年後庭樹，榮落在深宮。"]'),
('yuding-101','相和歌辭：婕妤怨','崔國輔','唐','御定全唐诗','yuding','','[]','長信宮中草，年年愁處生。故侵珠履跡，不使玉階行。',24,'御定全唐詩/json/020.json','["長信宮中草，年年愁處生。故侵珠履跡，不使玉階行。"]'),
('yuding-102','相和歌辭：婕妤怨','張烜','唐','御定全唐诗','yuding','','[]','賤妾裁紈扇，初搖明月姿。君王看舞席，坐起秋風時。',48,'御定全唐詩/json/020.json','["賤妾裁紈扇，初搖明月姿。君王看舞席，坐起秋風時。", "玉樹清禦路，金陳翳垂絲。昭陽無分理，愁寂任前期。"]'),
('yuding-103','相和歌辭：婕妤怨','劉方平','唐','御定全唐诗','yuding','','[]','夕殿別君王，宮深月似霜。人愁在長信，螢出向昭陽。',48,'御定全唐詩/json/020.json','["夕殿別君王，宮深月似霜。人愁在長信，螢出向昭陽。", "露裛紅蘭死，秋凋碧樹傷。惟當合歡扇，從此篋中藏。"]'),
('yuding-104','相和歌辭：婕妤怨','王沈','唐','御定全唐诗','yuding','','[]','長信梨花暗欲棲，應門上鑰草萋萋。',32,'御定全唐詩/json/020.json','["長信梨花暗欲棲，應門上鑰草萋萋。", "春風吹花亂撲戶，班倢車聲不至啼。"]'),
('yuding-105','相和歌辭：婕妤怨','皇甫冉','唐','御定全唐诗','yuding','','[]','由來詠團扇，今與值秋風。事逐時皆往，恩無日再中。',48,'御定全唐詩/json/020.json','["由來詠團扇，今與值秋風。事逐時皆往，恩無日再中。", "早鴻聞上苑，寒露下深宮。顏色年年謝，相如賦豈工。"]'),
('yuding-106','相和歌辭：婕妤怨','陸龜蒙','唐','御定全唐诗','yuding','','[]','妾貌非傾國，君王忽然寵。南山掌上來，不及新恩重。',48,'御定全唐詩/json/020.json','["妾貌非傾國，君王忽然寵。南山掌上來，不及新恩重。", "後宮多窈窕，日日學新聲。一落君王耳，南山又須輕。"]'),
('yuding-107','相和歌辭：婕妤怨','翁綬','唐','御定全唐诗','yuding','','[]','讒謗潛來起百憂，朝承恩寵暮仇讎。火燒白玉非因玷，',40,'御定全唐詩/json/020.json','["讒謗潛來起百憂，朝承恩寵暮仇讎。火燒白玉非因玷，", "繁華事逐東流水，團扇悲歌萬古愁。"]'),
('yuding-108','相和歌辭：婕妤怨','劉氏雲','唐','御定全唐诗','yuding','','[]','君恩不可見，妾豈如秋扇。秋扇尚有時，妾身永微賤。',40,'御定全唐詩/json/020.json','["君恩不可見，妾豈如秋扇。秋扇尚有時，妾身永微賤。", "莫言朝花不復落，嬌容幾奪昭陽殿。"]'),
('yuding-109','相和歌辭：長信怨','王諲','唐','御定全唐诗','yuding','','[]','飛燕倚身輕，爭人巧笑名。生君棄妾意，增妾怨君情。',48,'御定全唐詩/json/020.json','["飛燕倚身輕，爭人巧笑名。生君棄妾意，增妾怨君情。", "日落昭陽殿，秋來長信城。寥寥金殿裏，歌吹夜無聲。"]'),
('yuding-110','相和歌辭：長信怨','王昌齡','唐','御定全唐诗','yuding','','[]','金井梧桐秋葉黃，珠簾不卷夜來霜。',64,'御定全唐詩/json/020.json','["金井梧桐秋葉黃，珠簾不卷夜來霜。", "金爐玉枕無顏色，臥聽南宮清漏長。", "奉帚平明金殿開，暫將團扇共裴回。", "玉顏不及寒鴉色，猶帶昭陽日影來。"]'),
('yuding-111','相和歌辭：長信怨','李白','唐','御定全唐诗','yuding','','[]','月皎昭陽殿，霜清長信宮。天行乘玉輦，飛燕與君同。',48,'御定全唐詩/json/020.json','["月皎昭陽殿，霜清長信宮。天行乘玉輦，飛燕與君同。", "更有留情處，承恩樂未窮。誰憐團扇妾，獨坐怨秋風。"]'),
('yuding-112','相和歌辭：蛾眉怨','王翰','唐','御定全唐诗','yuding','','[]','君不見宜春苑中九華殿，飛閣連連直如發。',179,'御定全唐詩/json/020.json','["君不見宜春苑中九華殿，飛閣連連直如發。", "白日全含朱鳥窗，流雲半入蒼龍闕。宮中彩女夜無事，", "忽聞天子憶蛾眉，寶鳳銜花揲兩螭。傳聲走馬開金屋，", "燈前含笑更羅衣，帳裏承恩薦瑤枕。不意君心半路回，", "欲向人間種桃實，先從海底覓蓬萊。蓬萊可求不可上，", "王母嫣然感君意，雲車雨旆欲相迎。飛廉觀前空怨慕，", "宮車晚出向南山，仙衛逶迤去不還。朝晡泣對麒麟樹，", "剩知白日不可思，一死一生何足算。"]'),
('yuding-113','相和歌辭：玉階怨','李白','唐','御定全唐诗','yuding','','[]','玉階生白露，夜久侵羅襪。卻下水精簾，玲瓏望秋月。',24,'御定全唐詩/json/020.json','["玉階生白露，夜久侵羅襪。卻下水精簾，玲瓏望秋月。"]'),
('yuding-114','相和歌辭：宮怨','長孫佐輔','唐','御定全唐诗','yuding','','[]','窗前好樹名玫瑰，去年花落今年開。無情春色尚識返，',120,'御定全唐詩/json/020.json','["窗前好樹名玫瑰，去年花落今年開。無情春色尚識返，", "拊心卻笑西子嚬，掩鼻誰憂鄭姬謗。草染文章衣下履，", "盛衰傾奪欲何如，嬌愛翻悲逐佞諛。重遠豈能慚沼鵠，", "始意類蘿新托柏，終傷如薺卻甘荼。深院獨開還獨閉，", "痕多開鏡照還悲，綠髻青蛾尚未衰。莫道新縑長絕比，"]'),
('yuding-115','相和歌辭：宮怨','李益','唐','御定全唐诗','yuding','','[]','露濕晴花宮殿香，月明歌吹在昭陽。',32,'御定全唐詩/json/020.json','["露濕晴花宮殿香，月明歌吹在昭陽。", "似將海水添宮漏，共滴長門一夜長。"]'),
('yuding-116','相和歌辭：宮怨','於濆','唐','御定全唐诗','yuding','','[]','妾家望江口，少年家財厚。臨江起珠樓，不賣文君酒。',120,'御定全唐詩/json/020.json','["妾家望江口，少年家財厚。臨江起珠樓，不賣文君酒。", "當年樂貞獨，巢燕時為友。父兄未許人，畏妾事姑舅。", "西牆鄰宋玉，窺見妾眉宇。一旦及天聰，恩光生戶牖。", "謂言入漢宮，富貴可長久。君王縱有情，不奈陳皇后。", "誰憐頰似桃，孰知腰勝柳。今日在長門，從來不如醜。"]'),
('yuding-117','相和歌辭：宮怨','柯崇','唐','御定全唐诗','yuding','','[]','塵滿金爐不炷香，黃昏獨自立重廊。',64,'御定全唐詩/json/020.json','["塵滿金爐不炷香，黃昏獨自立重廊。", "笙歌何處承恩寵，一一隨風入上陽。", "長門槐柳半蕭疏，玉輦沉思恨有餘。", "紅淚旋銷傾國態，黃金誰為達相如。"]'),
('yuding-118','相和歌辭：雜怨三首','聶夷中','唐','御定全唐诗','yuding','','[]','生在綺羅下，豈識漁陽道。良人自戍來，夜夜夢中到。',108,'御定全唐詩/json/020.json','["生在綺羅下，豈識漁陽道。良人自戍來，夜夜夢中到。", "漁陽萬里遠，近於中門限。中門逾有時，漁陽常在眼。", "良人昨日去，明日又不還。別時各有淚，零落青樓前。", "君淚濡羅巾，妾淚滴路塵。羅巾今在手，日得隨妾身。", "路塵如因飛，得上君車輪。"]'),
('yuding-119','相和歌辭：雜怨三首','孟郊','唐','御定全唐诗','yuding','','[]','夭桃花清晨，遊女紅粉新。夭桃花薄暮，遊女紅粉故。',156,'御定全唐詩/json/020.json','["夭桃花清晨，遊女紅粉新。夭桃花薄暮，遊女紅粉故。", "樹有百年花，人無一定顏。花送人老盡，人悲花自閑。", "貧女鏡不明，寒花日少容。暗蛩有虛織，短線無長縫。", "浪水不可照，狂夫不可從。浪水多散影，狂夫多異蹤。", "持此一生薄，空成百恨濃。", "憶人莫至悲，至悲空自衰。寄人莫翦衣，翦衣未必歸。", "朝為雙蒂花，暮為四散飛。花落卻繞樹，遊子不顧期。"]'),
('yuding-0','相和歌辭：子夜春歌','王翰','唐','御定全唐诗','yuding','','[]','春氣滿林香，春遊不可忘。落花吹欲盡，垂柳折還長。',48,'御定全唐詩/json/021.json','["春氣滿林香，春遊不可忘。落花吹欲盡，垂柳折還長。", "桑女淮南曲，金鞍塞北裝。行行小垂手，日暮渭川陽。"]'),
('yuding-1','相和歌辭：子夜冬歌','崔國輔','唐','御定全唐诗','yuding','','[]','寂寥抱冬心，裁羅又褧褧。夜久頻挑燈，霜寒剪刀冷。',24,'御定全唐詩/json/021.json','["寂寥抱冬心，裁羅又褧褧。夜久頻挑燈，霜寒剪刀冷。"]'),
('yuding-2','相和歌辭：子夜冬歌','薛耀','唐','御定全唐诗','yuding','','[]','朔風扣群木，嚴霜凋百草。借問月中人，安得長不老。',24,'御定全唐詩/json/021.json','["朔風扣群木，嚴霜凋百草。借問月中人，安得長不老。"]'),
('yuding-3','相和歌辭：子夜四時歌六首：春歌二首','郭元振','唐','御定全唐诗','yuding','','[]','青樓含日光，綠池起風色。贈子同心花，殷勤此何極。',48,'御定全唐詩/json/021.json','["青樓含日光，綠池起風色。贈子同心花，殷勤此何極。", "陌頭楊柳枝，已被春風吹。妾心正斷絕，君懷那得知。"]'),
('yuding-4','相和歌辭：子夜四時歌六首：秋歌二首','郭元振','唐','御定全唐诗','yuding','','[]','邀歡空佇立，望美頻回顧。何時複采菱，江中密相遇。',48,'御定全唐詩/json/021.json','["邀歡空佇立，望美頻回顧。何時複采菱，江中密相遇。", "辟惡茱萸囊，延年菊花酒。與子結綢繆，丹心此何有。"]'),
('yuding-5','相和歌辭：子夜四時歌六首：冬歌二首','郭元振','唐','御定全唐诗','yuding','','[]','北極嚴氣升，南至溫風謝。調絲競短歌，拂枕憐長夜。',48,'御定全唐詩/json/021.json','["北極嚴氣升，南至溫風謝。調絲競短歌，拂枕憐長夜。", "帷橫雙翡翠，被卷兩鴛鴦。婉態不自得，宛轉君王床。"]'),
('yuding-6','相和歌辭：子夜四時歌四首：春歌','李白','唐','御定全唐诗','yuding','','[]','秦地羅敷女，采桑綠水邊。素手青條上，紅妝白日鮮。',36,'御定全唐詩/json/021.json','["秦地羅敷女，采桑綠水邊。素手青條上，紅妝白日鮮。", "蠶饑妾欲去，五馬莫留連。"]'),
('yuding-7','相和歌辭：子夜四時歌四首：夏歌','李白','唐','御定全唐诗','yuding','','[]','鏡湖三百里，菡萏發荷花。五月西施采，人看隘若邪。',36,'御定全唐詩/json/021.json','["鏡湖三百里，菡萏發荷花。五月西施采，人看隘若邪。", "回舟不待月，歸去越王家。"]'),
('yuding-8','相和歌辭：子夜四時歌四首：秋歌','李白','唐','御定全唐诗','yuding','','[]','長安一片月，萬戶擣衣聲。秋風吹不盡，總是玉關情。',36,'御定全唐詩/json/021.json','["長安一片月，萬戶擣衣聲。秋風吹不盡，總是玉關情。", "何日平胡虜，良人罷遠征。"]'),
('yuding-9','相和歌辭：子夜四時歌四首：冬歌','李白','唐','御定全唐诗','yuding','','[]','明朝驛使發，一夜絮征袍。素手抽針冷，那堪把剪刀。',36,'御定全唐詩/json/021.json','["明朝驛使發，一夜絮征袍。素手抽針冷，那堪把剪刀。", "裁縫寄遠道，幾日到臨洮。"]'),
('yuding-10','相和歌辭：子夜四時歌四首：春歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','山連翠羽屏，草接煙華席。望盡南飛燕，佳人斷信息。',24,'御定全唐詩/json/021.json','["山連翠羽屏，草接煙華席。望盡南飛燕，佳人斷信息。"]'),
('yuding-11','相和歌辭：子夜四時歌四首：夏歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','蘭眼抬露斜，鶯唇映花老。金龍傾漏盡，玉井敲冰早。',24,'御定全唐詩/json/021.json','["蘭眼抬露斜，鶯唇映花老。金龍傾漏盡，玉井敲冰早。"]'),
('yuding-12','相和歌辭：子夜四時歌四首：秋歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','涼漢清泬寥，衰林怨風雨。愁聽絡緯唱，似與羈魂語。',24,'御定全唐詩/json/021.json','["涼漢清泬寥，衰林怨風雨。愁聽絡緯唱，似與羈魂語。"]'),
('yuding-13','相和歌辭：子夜四時歌四首：冬歌','陸龜蒙','唐','御定全唐诗','yuding','','[]','南光走冷圭，北籟號空木。年年任霜霰，不減筼簹綠。',24,'御定全唐詩/json/021.json','["南光走冷圭，北籟號空木。年年任霜霰，不減筼簹綠。"]'),
('yuding-14','相和歌辭：大子夜歌二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','歌謠數百種，子夜最可憐。慷慨吐清音，明轉出天然。',48,'御定全唐詩/json/021.json','["歌謠數百種，子夜最可憐。慷慨吐清音，明轉出天然。", "絲竹發歌響，假器揚清音。不知歌謠妙，聲勢出口心。"]'),
('yuding-15','相和歌辭：子夜警歌二首','陸龜蒙','唐','御定全唐诗','yuding','','[]','鏤碗傳綠酒，雕爐熏紫煙。誰知苦寒調，共作白雪弦。',48,'御定全唐詩/json/021.json','["鏤碗傳綠酒，雕爐熏紫煙。誰知苦寒調，共作白雪弦。", "恃愛如欲進，含羞出不前。朱口發豔歌，玉指弄嬌弦。"]'),
('yuding-16','相和歌辭：丁督護歌','李白','唐','御定全唐诗','yuding','','[]','雲陽上征去，兩岸饒商賈。吳牛喘月時，拖船一何苦。',72,'御定全唐詩/json/021.json','["雲陽上征去，兩岸饒商賈。吳牛喘月時，拖船一何苦。", "水濁不可飲，壺漿半成土。一唱都護歌，心摧淚如雨。", "萬人鑿磐石，無由達江滸。君看石芒碭，掩淚悲千古。"]'),
('yuding-17','相和歌辭：團扇郎','張祜','唐','御定全唐诗','yuding','','[]','白團扇，今來此去捐。願得入郎手，團圓郎眼前。',22,'御定全唐詩/json/021.json','["白團扇，今來此去捐。願得入郎手，團圓郎眼前。"]'),
('yuding-18','相和歌辭：團扇郎','劉禹錫','唐','御定全唐诗','yuding','','[]','團扇複團扇，奉君清暑殿。秋風入庭樹，從此不相見。',48,'御定全唐詩/json/021.json','["團扇複團扇，奉君清暑殿。秋風入庭樹，從此不相見。", "上有乘鸞女，蒼蒼蟲網遍。明年入懷袖，別是機中練。"]'),
('yuding-19','相和歌辭：碧玉歌','李暇','唐','御定全唐诗','yuding','','[]','碧玉上宮妓，出入千花林。珠被玳瑁床，感郎情意深。',24,'御定全唐詩/json/021.json','["碧玉上宮妓，出入千花林。珠被玳瑁床，感郎情意深。"]'),
('yuding-20','相和歌辭：懊惱曲','溫庭筠','唐','御定全唐诗','yuding','','[]','藕絲作線難勝針，蕊粉染黃那得深。玉白蘭芳不相顧，',72,'御定全唐詩/json/021.json','["藕絲作線難勝針，蕊粉染黃那得深。玉白蘭芳不相顧，", "三秋庭綠盡迎霜，惟有荷花守紅死。西江小吏朱斑輪，", "悠悠楚水流如馬，恨紫愁紅滿平野。野土千年怨不平，"]'),
('yuding-21','相和歌辭：讀曲歌五首','張祜','唐','御定全唐诗','yuding','','[]','窗中獨自起，簾外獨自行。愁見蜘蛛織，尋思直到明。',120,'御定全唐詩/json/021.json','["窗中獨自起，簾外獨自行。愁見蜘蛛織，尋思直到明。", "碓上米不舂，窗中絲罷絡。看渠駕去車，定是無四角。", "不見心相許，徒雲腳漫勤。摘荷空摘葉，是底採蓮人。", "窗外山魈立，知渠腳不多。三更機底下，摸著是誰梭。", "郎去摘黃瓜，郎來收赤棗。郎耕種麻地，今作西舍道。"]'),
('yuding-22','相和歌辭：春江花月夜二首','張子容','唐','御定全唐诗','yuding','','[]','林花發岸口，氣色動江新。此夜江中月，流光花上春。',72,'御定全唐詩/json/021.json','["林花發岸口，氣色動江新。此夜江中月，流光花上春。", "分明石潭裏，宜照浣紗人。", "交甫憐瑤佩，仙妃難重期。沉沉綠江晚，惆悵碧雲姿。", "初逢花上月，言是弄珠時。"]'),
('yuding-23','相和歌辭：春江花月夜','張若虛','唐','御定全唐诗','yuding','','[]','春江潮水連海平，海上明月共潮生。灩灩隨波千萬里，',168,'御定全唐詩/json/021.json','["春江潮水連海平，海上明月共潮生。灩灩隨波千萬里，", "空裏流霜不覺飛，汀上白沙看不見。江天一色無纖塵。", "皎皎空中孤月輪。江畔何人初見月，江月何年初照人。", "人生代代無窮已，江月年年望相似。不知江月待何人，", "誰家今夜扁舟子，何處相思明月樓。可憐樓上月裴回，", "此時相望不相聞，願逐月華流照君。鴻雁長飛光不度，", "江水流春去欲盡，江潭落月複西斜。斜月沉沉藏海霧，"]'),
('yuding-24','相和歌辭：春江花月夜','溫庭筠','唐','御定全唐诗','yuding','','[]','玉樹歌闌海雲黑，花庭忽作青蕪國。秦淮有水水無情，',88,'御定全唐詩/json/021.json','["玉樹歌闌海雲黑，花庭忽作青蕪國。秦淮有水水無情，", "百幅錦帆風力滿，連天展盡金芙蓉。珠翠丁星複明滅，", "漏轉霞高滄海西，頗黎枕上聞天雞。蠻弦代雁曲如語，", "後主荒宮有曉鶯，飛來只隔西江水。"]'),
('yuding-25','相和歌辭：玉樹後庭花','張祜','唐','御定全唐诗','yuding','','[]','輕車何草草，獨唱後庭花。玉座誰為主，徒悲張麗華。',24,'御定全唐詩/json/021.json','["輕車何草草，獨唱後庭花。玉座誰為主，徒悲張麗華。"]'),
('yuding-26','相和歌辭：堂堂','溫庭筠','唐','御定全唐诗','yuding','','[]','錢塘岸上春如織，淼淼寒潮帶晴色。淮南遊客馬連嘶，',40,'御定全唐詩/json/021.json','["錢塘岸上春如織，淼淼寒潮帶晴色。淮南遊客馬連嘶，", "一曲堂堂紅燭筵，金鯨瀉酒如飛泉。"]'),
('yuding-27','相和歌辭：三閣詞四首','劉禹錫','唐','御定全唐诗','yuding','','[]','貴人三閣上，日晏未梳頭。不應有恨事，嬌甚卻成愁。',96,'御定全唐詩/json/021.json','["貴人三閣上，日晏未梳頭。不應有恨事，嬌甚卻成愁。", "珠箔曲瓊鉤，子細見揚州。北兵那得度，浪語判悠悠。", "沉香帖閣柱，金縷畫門楣。回首降幡下，已見黍離離。", "三人出眢井，一身登檻車。朱門漫臨水，不可見鱸魚。"]'),
('yuding-28','相和歌辭：神弦曲','李賀','唐','御定全唐诗','yuding','','[]','西山日沒東山昏，旋風吹馬馬踏雲。畫弦素管聲淺繁，',48,'御定全唐詩/json/021.json','["西山日沒東山昏，旋風吹馬馬踏雲。畫弦素管聲淺繁，", "古壁彩虯金帖尾，雨工騎入秋潭水。百年老鴞成木魅，"]'),
('yuding-29','相和歌辭：神弦別曲','李賀','唐','御定全唐诗','yuding','','[]','巫山小女隔雲別，松花春風山上發。綠蓋獨穿香徑歸，',40,'御定全唐詩/json/021.json','["巫山小女隔雲別，松花春風山上發。綠蓋獨穿香徑歸，", "南山桂樹為君死，雲衫殘汙紅脂花。"]'),
('yuding-30','相和歌辭：祠漁山神女歌：迎神','王維','唐','御定全唐诗','yuding','','[]','坎坎擊鼓，漁山之下。吹洞簫，望極浦。',59,'御定全唐詩/json/021.json','["坎坎擊鼓，漁山之下。吹洞簫，望極浦。", "女巫進，紛屢舞。陳瑤席，湛清酤。風淒淒，又夜雨。", "不知神之來兮不來，使我心兮苦複苦。"]'),
('yuding-31','相和歌辭：祠漁山神女歌：送神','王維','唐','御定全唐诗','yuding','','[]','紛進舞兮堂前，目眷眷兮瓊筵。來不言兮意不傳，',37,'御定全唐詩/json/021.json','["紛進舞兮堂前，目眷眷兮瓊筵。來不言兮意不傳，", "倏雲收兮雨歇，山青青兮水潺湲。"]'),
('yuding-32','相和歌辭：祠神歌：迎神','王睿','唐','御定全唐诗','yuding','','[]','蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。',32,'御定全唐詩/json/021.json','["蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。", "引領望江遙滴酒，白蘋風起水生文。"]'),
('yuding-33','相和歌辭：祠神歌：送神','王睿','唐','御定全唐诗','yuding','','[]','棖棖山響答琵琶，酒濕青莎肉飼鴉。',32,'御定全唐詩/json/021.json','["棖棖山響答琵琶，酒濕青莎肉飼鴉。", "樹葉無聲神去後，紙錢灰出木綿花。"]'),
('yuding-34','相和歌辭：烏夜啼','楊巨源','唐','御定全唐诗','yuding','','[]','可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，',24,'御定全唐詩/json/021.json','["可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，"]'),
('yuding-35','相和歌辭：烏夜啼','李白','唐','御定全唐诗','yuding','','[]','黃雲城邊烏欲棲，歸飛啞啞枝上啼。機中織錦秦川女，',24,'御定全唐詩/json/021.json','["黃雲城邊烏欲棲，歸飛啞啞枝上啼。機中織錦秦川女，"]'),
('yuding-36','相和歌辭：烏夜啼二首','顧況','唐','御定全唐诗','yuding','','[]','玉房掣鎖聲翻葉，銀箭添泉繞霜堞。畢逋發刺月銜城，',70,'御定全唐詩/json/021.json','["玉房掣鎖聲翻葉，銀箭添泉繞霜堞。畢逋發刺月銜城，", "搖雜佩，耿華燭，良夜羽人彈此曲，東方曈曈赤日旭。", "月出江林西，江林寂寂城鴉啼。昔人何處為此曲，"]'),
('yuding-37','相和歌辭：烏夜啼','李群玉','唐','御定全唐诗','yuding','','[]','曾波隔夢渚，一望青楓林。有烏在其間，達曉自悲吟。',96,'御定全唐詩/json/021.json','["曾波隔夢渚，一望青楓林。有烏在其間，達曉自悲吟。", "是時月黑天，四野煙雨深。如聞生離哭，其聲痛人心。", "悄悄夜正長，空山響哀音。遠客不可聽，坐愁華髮侵。", "既非蜀帝魂，恐是恒山禽。四子各分散，母聲猶至今。"]'),
('yuding-38','相和歌辭：烏夜啼','聶夷中','唐','御定全唐诗','yuding','','[]','眾鳥各歸枝，烏烏爾不棲。還應知妾恨，故向綠窗啼。',24,'御定全唐詩/json/021.json','["眾鳥各歸枝，烏烏爾不棲。還應知妾恨，故向綠窗啼。"]'),
('yuding-39','相和歌辭：烏夜啼','白居易','唐','御定全唐诗','yuding','','[]','城上歸時晚，庭前宿處危。月明無葉樹，霜滑有風枝。',48,'御定全唐詩/json/021.json','["城上歸時晚，庭前宿處危。月明無葉樹，霜滑有風枝。", "啼澀饑喉咽，飛低凍翅垂。畫堂鸚鵡鳥，冷暖不相知。"]'),
('yuding-40','相和歌辭：烏夜啼','王建','唐','御定全唐诗','yuding','','[]','庭樹烏，爾何不向別處棲？夜夜夜半當戶啼。',60,'御定全唐詩/json/021.json','["庭樹烏，爾何不向別處棲？夜夜夜半當戶啼。", "家人把燭出洞戶，驚棲失群飛落樹。一飛直欲飛上天，", "風飄雨濕亦不移，君家樹頭多好枝。"]'),
('yuding-41','相和歌辭：烏夜啼','張祜','唐','御定全唐诗','yuding','','[]','忽忽南飛返，危弦共怨淒。暗霜移樹宿，殘夜繞枝啼。',48,'御定全唐詩/json/021.json','["忽忽南飛返，危弦共怨淒。暗霜移樹宿，殘夜繞枝啼。", "咽絕聲重敘，愔淫思乍迷。不妨還報喜，誤使玉顏低。"]'),
('yuding-42','相和歌辭：烏棲曲','李白','唐','御定全唐诗','yuding','','[]','姑蘇臺上烏棲時，吳王宮裏醉西施。吳歌楚舞歡未畢，',24,'御定全唐詩/json/021.json','["姑蘇臺上烏棲時，吳王宮裏醉西施。吳歌楚舞歡未畢，"]'),
('yuding-43','相和歌辭：烏棲曲','李端','唐','御定全唐诗','yuding','','[]','白馬逐牛車，黃昏入狹斜。柳樹烏爭宿，',18,'御定全唐詩/json/021.json','["白馬逐牛車，黃昏入狹斜。柳樹烏爭宿，"]'),
('yuding-44','相和歌辭：烏棲曲','王建','唐','御定全唐诗','yuding','','[]','章華宮人夜上樓，君王望月西山頭。',32,'御定全唐詩/json/021.json','["章華宮人夜上樓，君王望月西山頭。", "夜深宮殿門不鎖，白露滿山山葉墮。"]'),
('yuding-45','相和歌辭：烏棲曲','張籍','唐','御定全唐诗','yuding','','[]','西山作宮潮滿池，宮烏曉鳴茱萸枝。',32,'御定全唐詩/json/021.json','["西山作宮潮滿池，宮烏曉鳴茱萸枝。", "吳姬自唱採蓮曲，君王昨夜舟中宿。"]'),
('yuding-46','相和歌辭：棲烏曲二首','劉方平','唐','御定全唐诗','yuding','','[]','蛾眉曼臉傾城國，鳴環動佩新相識。',64,'御定全唐詩/json/021.json','["蛾眉曼臉傾城國，鳴環動佩新相識。", "銀漢斜臨白玉堂，芙蓉行障掩燈光。", "畫舸雙艚錦為纜，芙蓉花發蓮葉暗。", "門前月色映橫塘，感郎中夜渡瀟湘。"]'),
('yuding-47','相和歌辭：莫愁樂','張祜','唐','御定全唐诗','yuding','','[]','儂居石城下，郎到石城遊。自郎石城出，長在石城頭。',24,'御定全唐詩/json/021.json','["儂居石城下，郎到石城遊。自郎石城出，長在石城頭。"]'),
('yuding-48','相和歌辭：莫愁曲','李賀','唐','御定全唐诗','yuding','','[]','草生隴阪下，鴉噪城堞頭。何人此城裏，城角栽石榴。',96,'御定全唐詩/json/021.json','["草生隴阪下，鴉噪城堞頭。何人此城裏，城角栽石榴。", "青絲系五馬，黃金絡雙牛。白魚駕蓮船，夜作十裏遊。", "歸來無人識，暗上沉香樓。羅床倚瑤瑟，殘月傾簾鉤。", "今日槿花落，明朝梧樹秋。若負平生意，何名作莫愁。"]'),
('yuding-49','相和歌辭：估客樂','李白','唐','御定全唐诗','yuding','','[]','海客乘天風，將船遠行役。譬如雲中鳥，一去無蹤跡。',24,'御定全唐詩/json/021.json','["海客乘天風，將船遠行役。譬如雲中鳥，一去無蹤跡。"]'),
('yuding-50','相和歌辭：估客樂','元稹','唐','御定全唐诗','yuding','','[]','估客無住著，有利身即行。出門求火伴，入戶辭父兄。',408,'御定全唐詩/json/021.json','["估客無住著，有利身即行。出門求火伴，入戶辭父兄。", "父兄相教示，求利莫求名。求名有所避，求利無不營。", "火伴相勒縛，賣假莫賣誠。交關少交假，交假本生輕。", "自茲相將去，誓死意不更。一解市頭語，便無鄉里情。", "鍮石打臂釧，糯米炊項瓔。歸來村中賣，敲作金玉聲。", "村中田舍娘，貴賤不敢爭。所費百錢本，已得十倍贏。", "顏色轉光淨，飲食亦甘馨。子本頻蕃息，貨賂日兼併。", "求珠駕滄海，采玉上荊衡。北買黨項馬，西擒吐蕃鸚。", "炎洲布火浣，蜀地錦織成。越婢脂肉滑，奚僮眉眼明。", "通算衣食費，不計遠近程。經營天下遍，卻到長安城。", "城中東西市，聞客次第迎。迎客兼說客，多財為勢傾。", "客心本明黠，聞語心已驚。先問十常侍，次求百公卿。", "侯家與主第，點綴無不精。歸來始安坐，富與王家勍。", "市卒酒肉臭，縣胥家舍成。豈惟絕言語，奔走極使令。", "大兒販材木，巧識梁棟形。小兒販鹽鹵，不入州縣征。", "一身偃市利，突若截海鯨。鉤距不敢下，下則牙齒橫。", "生為估客樂，判爾樂一生。爾又生兩子，錢刀何歲平。"]'),
('yuding-51','相和歌辭：賈客樂','張籍','唐','御定全唐诗','yuding','','[]','金陵向西賈客多，船中生長樂風波。欲發移船近江口，',72,'御定全唐詩/json/021.json','["金陵向西賈客多，船中生長樂風波。欲發移船近江口，", "金多眾中為上客，夜夜算緡眠獨遲。秋江初月猩猩語，", "年年逐利西複東，姓名不在縣籍中。農夫稅多長辛苦，"]'),
('yuding-52','相和歌辭：賈客詞','劉禹錫','唐','御定全唐诗','yuding','','[]','賈客無定游，所遊惟利並。眩俗雜良苦，乘時知重輕。',132,'御定全唐詩/json/021.json','["賈客無定游，所遊惟利並。眩俗雜良苦，乘時知重輕。", "心計析秋毫，搖鉤侔懸衡。錐刀既無棄，轉化日已盈。", "邀福禱波神，施財遊化城。妻約雕金釧，女垂貫珠纓。", "高貲比封君，奇貨通幸卿。趨時鷙鳥思，藏鏹盤龍形。", "大艑浮通川，高樓次旗亭。行止皆有樂，關梁似無征。", "農夫何為者，辛苦事寒耕。"]'),
('yuding-53','相和歌辭：賈客詞','劉駕','唐','御定全唐诗','yuding','','[]','賈客燈下起，猶言發已遲。高山有疾路，暗行終不疑。',72,'御定全唐詩/json/021.json','["賈客燈下起，猶言發已遲。高山有疾路，暗行終不疑。", "寇盜伏其路，猛獸來相追。金玉四散去，空囊委路岐。", "揚州有大宅，白骨無地歸。少婦當此日，對鏡弄花枝。"]'),
('yuding-54','相和歌辭：襄陽樂','張祜','唐','御定全唐诗','yuding','','[]','大堤花月夜，長江春水流。東風正上信，春夜特來遊。',24,'御定全唐詩/json/021.json','["大堤花月夜，長江春水流。東風正上信，春夜特來遊。"]'),
('yuding-55','相和歌辭：襄陽曲二首','崔國輔','唐','御定全唐诗','yuding','','[]','蕙草嬌紅萼，時光舞碧雞。城中美年少，相見白銅鞮。',48,'御定全唐詩/json/021.json','["蕙草嬌紅萼，時光舞碧雞。城中美年少，相見白銅鞮。", "少年襄陽地，來往襄陽城。城中輕薄子，知妾解秦箏。"]'),
('yuding-56','相和歌辭：襄陽曲','施肩吾','唐','御定全唐诗','yuding','','[]','大堤女兒郎莫尋，三三五五結同心。',32,'御定全唐詩/json/021.json','["大堤女兒郎莫尋，三三五五結同心。", "清晨對鏡冶容色，意欲取郎千萬金。"]'),
('yuding-57','相和歌辭：襄陽曲','李端','唐','御定全唐诗','yuding','','[]','襄陽堤路長，草碧楊柳黃。誰家女兒臨夜妝，',44,'御定全唐詩/json/021.json','["襄陽堤路長，草碧楊柳黃。誰家女兒臨夜妝，", "同居女伴正衣裳，中庭寒月白如霜。賈生十八稱才子，"]'),
('yuding-58','相和歌辭：大堤曲','張柬之','唐','御定全唐诗','yuding','','[]','南國多佳人，莫若大堤女。玉床翠羽帳，寶襪蓮花炬。',48,'御定全唐詩/json/021.json','["南國多佳人，莫若大堤女。玉床翠羽帳，寶襪蓮花炬。", "魂處自目成，色授開心許。迢迢不可見，日暮空愁予。"]'),
('yuding-59','相和歌辭：大堤曲','楊巨源','唐','御定全唐诗','yuding','','[]','二八嬋娟大堤女，開爐相對依江渚。待客登樓向水看，',72,'御定全唐詩/json/021.json','["二八嬋娟大堤女，開爐相對依江渚。待客登樓向水看，", "自傳芳酒涴紅袖，誰調妍妝回翠蛾。珍簟華燈夕陽後，", "歲歲逢迎沙岸間，北人多識綠雲鬟。無端嫁與五陵少，"]'),
('yuding-60','相和歌辭：大堤曲','李白','唐','御定全唐诗','yuding','','[]','漢水臨襄陽，花開大堤暖。佳期大堤下，淚向南雲滿。',48,'御定全唐詩/json/021.json','["漢水臨襄陽，花開大堤暖。佳期大堤下，淚向南雲滿。", "春風複無情，吹我夢魂散。不見眼中人，天長音信斷。"]'),
('yuding-61','相和歌辭：大堤曲','李賀','唐','御定全唐诗','yuding','','[]','妾家住橫塘，紅紗滿桂香。青雲教綰頭上髻，',56,'御定全唐詩/json/021.json','["妾家住橫塘，紅紗滿桂香。青雲教綰頭上髻，", "郎食鯉魚尾，妾食猩猩唇。莫指襄陽道，綠浦歸帆少。", "今日菖蒲花，明朝楓樹老。"]'),
('yuding-62','相和歌辭：大堤行','孟浩然','唐','御定全唐诗','yuding','','[]','大堤行樂處，車馬相馳突。歲歲春草生，踏青二三月。',48,'御定全唐詩/json/021.json','["大堤行樂處，車馬相馳突。歲歲春草生，踏青二三月。", "王孫挾珠彈，游女矜羅襪。攜手今莫同，江花為誰發。"]'),
('yuding-63','相和歌辭：三洲歌','溫庭筠','唐','御定全唐诗','yuding','','[]','團圓莫作波中月，潔白莫為枝上雪。月隨波動碎潾潾，',40,'御定全唐詩/json/021.json','["團圓莫作波中月，潔白莫為枝上雪。月隨波動碎潾潾，", "門前有路輕離別，惟恐歸來舊香滅。"]'),
('yuding-64','相和歌辭：拔蒲歌','張祜','唐','御定全唐诗','yuding','','[]','拔蒲來，領郎鏡湖邊。郎心在何處，莫趁新蓮去。',34,'御定全唐詩/json/021.json','["拔蒲來，領郎鏡湖邊。郎心在何處，莫趁新蓮去。", "拔得無心蒲，問郎看好無。"]'),
('yuding-65','相和歌辭：楊叛兒','李白','唐','御定全唐诗','yuding','','[]','君歌楊叛兒，妾勸新豐酒。何許最關人，烏啼白門柳。',52,'御定全唐詩/json/021.json','["君歌楊叛兒，妾勸新豐酒。何許最關人，烏啼白門柳。", "烏啼隱楊花，君醉留妾家。", "博山爐中沉香火，雙咽一氣淩紫霞。"]'),
('yuding-66','相和歌辭：常林歡','溫庭筠','唐','御定全唐诗','yuding','','[]','宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。穠桑繞舍麥如尾，',40,'御定全唐詩/json/021.json','["宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。穠桑繞舍麥如尾，", "錦薦金爐夢正長，東家呃喔雞鳴早。"]'),
('yuding-67','相和歌辭：江南弄','王勃','唐','御定全唐诗','yuding','','[]','江南弄，巫山連楚夢，行雨行雲幾相送。',42,'御定全唐詩/json/021.json','["江南弄，巫山連楚夢，行雨行雲幾相送。", "瑤軒金谷上春時，玉童仙女無見期。紫露香煙眇難托，"]'),
('yuding-68','相和歌辭：江南弄','李賀','唐','御定全唐诗','yuding','','[]','江中綠霧起涼波，天上疊巘紅嵯峨。水風浦雲生老竹，',40,'御定全唐詩/json/021.json','["江中綠霧起涼波，天上疊巘紅嵯峨。水風浦雲生老竹，", "吳歈越吟未終曲，江上團團帖寒玉。"]'),
('yuding-69','相和歌辭：採蓮曲','崔國輔','唐','御定全唐诗','yuding','','[]','玉漵花紅發，金塘水碧流。相逢畏相失，並著採蓮舟。',24,'御定全唐詩/json/021.json','["玉漵花紅發，金塘水碧流。相逢畏相失，並著採蓮舟。"]'),
('yuding-70','相和歌辭：採蓮曲','徐彥伯','唐','御定全唐诗','yuding','','[]','妾家越水邊，搖艇入江煙。既覓同心侶，複采同心蓮。',48,'御定全唐詩/json/021.json','["妾家越水邊，搖艇入江煙。既覓同心侶，複采同心蓮。", "折藕絲能脆，開花葉正圓。春歌弄明月，歸棹落花前。"]'),
('yuding-71','相和歌辭：採蓮曲','李白','唐','御定全唐诗','yuding','','[]','若耶溪邊採蓮女，笑隔荷花共人語。日照新妝水底明，',40,'御定全唐詩/json/021.json','["若耶溪邊採蓮女，笑隔荷花共人語。日照新妝水底明，", "紫騮嘶入落花去，見此踟躕空斷腸。"]'),
('yuding-72','相和歌辭：採蓮曲','賀知章','唐','御定全唐诗','yuding','','[]','稽山罷霧鬱嵯峨，鏡水無風也自波。',32,'御定全唐詩/json/021.json','["稽山罷霧鬱嵯峨，鏡水無風也自波。", "莫言春度芳菲盡，別有中流采芰荷。"]'),
('yuding-73','相和歌辭：採蓮曲三首','王昌齡','唐','御定全唐诗','yuding','','[]','吳姬越豔楚王妃，爭弄蓮舟水濕衣。',112,'御定全唐詩/json/021.json','["吳姬越豔楚王妃，爭弄蓮舟水濕衣。", "來時浦口花迎入，采罷江頭月送歸。", "荷葉羅裙一色裁，芙蓉向臉兩邊開。", "亂入池中看不見，聞歌始覺有人來。", "越女作桂舟，還將桂為楫。湖上水渺漫，清江初可涉。", "摘取芙蓉花，莫摘芙蓉葉。將歸問夫婿，顏色何如妾。"]'),
('yuding-74','相和歌辭：採蓮曲二首','戎昱','唐','御定全唐诗','yuding','','[]','雖聽採蓮曲，詎識採蓮心。漾楫愛花遠，回船愁浪深。',80,'御定全唐詩/json/021.json','["雖聽採蓮曲，詎識採蓮心。漾楫愛花遠，回船愁浪深。", "煙生極浦色，日落半江陰。同侶憐波靜，看妝墮玉簪。", "涔陽女兒花滿頭，毿毿同泛木蘭舟。", "春風日暮南湖裏，爭唱菱歌不肯休。"]'),
('yuding-75','相和歌辭：採蓮曲','儲光羲','唐','御定全唐诗','yuding','','[]','淺渚荷花繁，深塘菱葉疏。獨往方自得，恥邀淇上姝。',72,'御定全唐詩/json/021.json','["淺渚荷花繁，深塘菱葉疏。獨往方自得，恥邀淇上姝。", "廣江無術阡，大澤絕方隅。浪中海童語，流下鮫人居。", "春雁時隱舟，新荷複滿湖。采采乘日暮，不思賢與愚。"]'),
('yuding-76','相和歌辭：採蓮曲二首','鮑溶','唐','御定全唐诗','yuding','','[]','弄舟朅來南塘水，荷葉映身摘蓮子。暑衣清淨鴛鴦喜，',48,'御定全唐詩/json/021.json','["弄舟朅來南塘水，荷葉映身摘蓮子。暑衣清淨鴛鴦喜，", "採蓮朅來水無風，蓮潭如鏡松如龍。夏衫短袖交斜紅，"]'),
('yuding-77','相和歌辭：採蓮曲','張籍','唐','御定全唐诗','yuding','','[]','秋江岸邊蓮子多，採蓮女兒憑船歌。青房圓實齊戢戢，',48,'御定全唐詩/json/021.json','["秋江岸邊蓮子多，採蓮女兒憑船歌。青房圓實齊戢戢，", "白練束腰袖半卷，不插玉釵妝梳淺。船中未滿度前洲，"]'),
('yuding-78','相和歌辭：採蓮曲','白居易','唐','御定全唐诗','yuding','','[]','菱葉縈波荷颭風，荷花深處小船通。',32,'御定全唐詩/json/021.json','["菱葉縈波荷颭風，荷花深處小船通。", "逢郎欲語低頭笑，碧玉搔頭落水中。"]'),
('yuding-79','相和歌辭：採蓮曲','齊己','唐','御定全唐诗','yuding','','[]','越江女，越江蓮，齊菡萏，雙嬋娟。嬉游向何處，',22,'御定全唐詩/json/021.json','["越江女，越江蓮，齊菡萏，雙嬋娟。嬉游向何處，"]'),
('yuding-80','相和歌辭：採蓮歸','王勃','唐','御定全唐诗','yuding','','[]','採蓮歸，綠水芙蓉衣，秋風起浪鳧雁飛。',156,'御定全唐詩/json/021.json','["採蓮歸，綠水芙蓉衣，秋風起浪鳧雁飛。", "桂棹蘭橈下長浦，羅裙玉腕搖輕櫓。葉嶼花潭極望平，", "塞外征夫猶未還，江南採蓮今已暮。今已暮，摘蓮花，", "蓮花複蓮花，花葉何重疊。葉翠本羞眉，花紅強如頰。", "佳人不茲期，悵望別離時。牽花憐共蒂，折藕愛連絲。", "故情何處所，新物徒華滋。不惜南津交佩解，", "正逢浩蕩江上風，又值徘徊江上月。蓮浦夜相逢，"]'),
('yuding-81','相和歌辭：採蓮女','閻朝隱','唐','御定全唐诗','yuding','','[]','採蓮女，採蓮舟，春日春江碧水流。蓮衣承玉釧，',22,'御定全唐詩/json/021.json','["採蓮女，採蓮舟，春日春江碧水流。蓮衣承玉釧，"]'),
('yuding-82','相和歌辭：湖邊採蓮婦','李白','唐','御定全唐诗','yuding','','[]','小姑織白紵，未解將人語。大嫂采芙蓉，溪湖千萬重。',48,'御定全唐詩/json/021.json','["小姑織白紵，未解將人語。大嫂采芙蓉，溪湖千萬重。", "長兄行不在，莫使外人逢。願學秋胡婦，真心比古松。"]'),
('yuding-83','相和歌辭：張靜婉採蓮曲','溫庭筠','唐','御定全唐诗','yuding','','[]','蘭膏墜發紅玉春，燕釵拖頸拋盤雲。城西楊柳向嬌晚，',88,'御定全唐詩/json/021.json','["蘭膏墜發紅玉春，燕釵拖頸拋盤雲。城西楊柳向嬌晚，", "掌中無力舞衣輕，翦斷鮫綃破春碧。抱月飄煙一尺腰，", "鸂鶒膠膠塘水滿，綠萍如粟蓮莖短。一夜西風送雨來，", "郎心似月月易缺，十五十六清光圓。"]'),
('yuding-84','相和歌辭：鳳笙曲','沈佺期','唐','御定全唐诗','yuding','','[]','憶昔王子晉，鳳笙遊雲空。揮手弄白日，安能戀青宮。',48,'御定全唐詩/json/021.json','["憶昔王子晉，鳳笙遊雲空。揮手弄白日，安能戀青宮。", "豈無嬋娟子，結念羅帳中。憐壽不貴色，身世兩無窮。"]'),
('yuding-85','相和歌辭：鳳吹笙曲','李白','唐','御定全唐诗','yuding','','[]','仙人十五愛吹笙，學得昆丘彩鳳鳴。始聞煉氣餐金液，',72,'御定全唐詩/json/021.json','["仙人十五愛吹笙，學得昆丘彩鳳鳴。始聞煉氣餐金液，", "欲歎離聲發絳唇，更嗟別調流纖指。此時惜別詎堪聞，", "綠雲紫氣向函關，訪道應尋緱氏山。莫學吹笙王子晉，"]'),
('yuding-86','相和歌辭：采菱曲','儲光羲','唐','御定全唐诗','yuding','','[]','濁水菱葉肥，清水菱葉鮮。義不游濁水，志士多苦言。',96,'御定全唐詩/json/021.json','["濁水菱葉肥，清水菱葉鮮。義不游濁水，志士多苦言。", "潮沒具區藪，潦深雲夢田。朝隨北風去，暮逐南風還。", "浦口多漁家，相與邀我船。飯稻以終日，羹蓴將永年。", "方冬水物窮，又欲休山樊。盡室相隨從，所貴無憂患。"]'),
('yuding-87','相和歌辭：采菱行','劉禹錫','唐','御定全唐诗','yuding','','[]','白馬湖平秋日光，紫菱如錦彩鸞翔。蕩舟游女滿中央，',88,'御定全唐詩/json/021.json','["白馬湖平秋日光，紫菱如錦彩鸞翔。蕩舟游女滿中央，", "長鬟弱袂動參差，釵影釧文浮蕩漾。笑語哇咬顧晚暉，", "家家竹樓臨廣陌，下有連檣多估客。攜觴薦芰夜經過，", "一曲南音此地聞，長安北望三千里。"]'),
('yuding-88','相和歌辭：陽春歌','李白','唐','御定全唐诗','yuding','','[]','長安白日照春空，綠楊結煙桑嫋風。披香殿前花始紅，',24,'御定全唐詩/json/021.json','["長安白日照春空，綠楊結煙桑嫋風。披香殿前花始紅，"]'),
('yuding-89','相和歌辭：陽春曲','溫庭筠','唐','御定全唐诗','yuding','','[]','雲母空窗曉煙薄，香昏龍氣凝輝閣。霏霏霧雨杏花天，',40,'御定全唐詩/json/021.json','["雲母空窗曉煙薄，香昏龍氣凝輝閣。霏霏霧雨杏花天，", "廄馬何能齧芳草，路人不敢隨流塵。"]'),
('yuding-90','相和歌辭：陽春曲','莊南傑','唐','御定全唐诗','yuding','','[]','紫錦紅囊香滿風，金鸞玉軾搖丁冬。沙鷗白羽翦晴碧，',40,'御定全唐詩/json/021.json','["紫錦紅囊香滿風，金鸞玉軾搖丁冬。沙鷗白羽翦晴碧，", "鳳叫龍吟白日長，落花聲底仙娥醉。"]'),
('yuding-91','相和歌辭：陽春曲','貫休','唐','御定全唐诗','yuding','','[]','為口莫學阮嗣宗，不言是非非至公。為手須似朱雲輩，',60,'御定全唐詩/json/021.json','["為口莫學阮嗣宗，不言是非非至公。為手須似朱雲輩，", "歷數雍熙房與杜，魏公姚公宋開府。", "盡向天上仙宮閑處坐，何不卻辭上帝下下土，"]'),
('yuding-92','相和歌辭：朝雲引','郎大家宋氏','唐','御定全唐诗','yuding','','[]','巴西巫峽指巴東，朝雲觸石上朝空。巫山巫峽高何已，',24,'御定全唐詩/json/021.json','["巴西巫峽指巴東，朝雲觸石上朝空。巫山巫峽高何已，"]'),
('yuding-93','相和歌辭：上雲樂','李白','唐','御定全唐诗','yuding','','[]','金天之西，白日所沒。康老胡雛，生彼月窟。巉岩儀容，',251,'御定全唐詩/json/021.json','["金天之西，白日所沒。康老胡雛，生彼月窟。巉岩儀容，", "華蓋垂下睫，嵩嶽臨上唇。不睹譎詭貌，豈知造化神。", "大道是文康之嚴父，元氣乃文康之老親。撫頂弄盤古，", "陽烏未出谷，顧兔半藏身。女媧戲黃土，團作愚下人。", "散在六合間，濛濛若沙塵。生死了不盡，", "別來幾多時，枝葉萬里長。中國有七聖，半路頹鴻荒。", "陛下應運起，龍飛入咸陽。赤眉立盆子，白水興漢光。", "叱吒四海動，洪濤為簸揚。舉足蹋紫微，天關自開張。", "老胡感至德，東來進仙倡。五色師子，九苞鳳凰。", "是老胡雞犬，鳴舞飛帝鄉。淋漓颯遝，進退成行。能胡歌，", "天子九九八十一萬歲，長傾萬歲杯。"]'),
('yuding-94','相和歌辭：上雲樂','李賀','唐','御定全唐诗','yuding','','[]','飛香走紅滿天春，花龍盤盤上紫雲。三千宮女列金屋，',40,'御定全唐詩/json/021.json','["飛香走紅滿天春，花龍盤盤上紫雲。三千宮女列金屋，", "斷煙素，縫舞衣，八月一日君前舞。"]'),
('yuding-95','相和歌辭：鳳台曲','王無競','唐','御定全唐诗','yuding','','[]','鳳台何逶迤，嬴女管參差。一旦彩雲至，身去無還期。',48,'御定全唐詩/json/021.json','["鳳台何逶迤，嬴女管參差。一旦彩雲至，身去無還期。", "遺曲此臺上，世人多學吹。一吹一落淚，至今憐玉姿。"]'),
('yuding-96','相和歌辭：鳳台曲','李白','唐','御定全唐诗','yuding','','[]','嘗聞秦帝女，傳得鳳凰聲。是日逢仙子，當時別有情。',48,'御定全唐詩/json/021.json','["嘗聞秦帝女，傳得鳳凰聲。是日逢仙子，當時別有情。", "人吹彩簫去，天借綠雲迎。曲在身不返，空餘弄玉名。"]'),
('yuding-97','相和歌辭：鳳凰曲','李白','唐','御定全唐诗','yuding','','[]','嬴女吹玉簫，吟弄天上春。青鸞不獨去，更有攜手人。',36,'御定全唐詩/json/021.json','["嬴女吹玉簫，吟弄天上春。青鸞不獨去，更有攜手人。", "影滅彩雲斷，遺聲落西秦。"]'),
('yuding-98','相和歌辭：君道曲','李白','唐','御定全唐诗','yuding','','[]','大君若天覆，廣運無不至。軒後爪牙常先太山稽，',34,'御定全唐詩/json/021.json','["大君若天覆，廣運無不至。軒後爪牙常先太山稽，", "土扶可成牆，積德為厚地。"]'),
('yuding-0','舞曲歌辭：吳俞兒舞歌：劍俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','枝月喉，棹霜脊，北斗離離在寒碧。龍魂清，虎尾白，',24,'御定全唐詩/json/022.json','["枝月喉，棹霜脊，北斗離離在寒碧。龍魂清，虎尾白，"]'),
('yuding-1','舞曲歌辭：吳俞兒舞歌：矛俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','手盤風，頭背分，電光戰扇，欲刺敲心留半線。',62,'御定全唐詩/json/022.json','["手盤風，頭背分，電光戰扇，欲刺敲心留半線。", "纏肩繞脰，dl合眩旋，卓植赴列，奪避中節。", "前沖函禮穴，上指孛彗滅，與君一用來有截。"]'),
('yuding-2','舞曲歌辭：吳俞兒舞歌：弩俞','陸龜蒙','唐','御定全唐诗','yuding','','[]','牛來開弦，人為置鏃。捩機關，迸山谷。鹿駭澀，',22,'御定全唐詩/json/022.json','["牛來開弦，人為置鏃。捩機關，迸山谷。鹿駭澀，"]'),
('yuding-3','舞曲歌辭：東海有勇婦','李白','唐','御定全唐诗','yuding','','[]','梁山感杞妻，慟器為之傾。金石忽暫開，都由激深情。',228,'御定全唐詩/json/022.json','["梁山感杞妻，慟器為之傾。金石忽暫開，都由激深情。", "東海有勇婦，何慚蘇子卿。學劍越處子，超騰若流星。", "捐軀報夫仇，萬死不顧生。白刃耀素雪，蒼天感精誠。", "十步兩躩躍，三呼一交兵。斬首掉國門，蹴踏五藏行。", "割此伉儷憤，粲然大義明。北海李使君，飛章奏天庭。", "舍罪警風俗，流芳播滄瀛。志在列女籍，行帛已光榮。", "淳於免詔獄，漢主為緹縈。津妾一棹歌，脫父于嚴刑。", "十子若不肖，不如一女英。豫讓斬空衣，有心竟無成。", "要離殺慶忌，壯夫素所輕。妻子亦何辜，焚之買虛名。", "豈如東海婦，事立獨揚名。"]'),
('yuding-4','舞曲歌辭：章和二年中','李賀','唐','御定全唐诗','yuding','','[]','雲蕭索，風拂拂，麥芒如篲黍和粟。關中父老百領襦，',48,'御定全唐詩/json/022.json','["雲蕭索，風拂拂，麥芒如篲黍和粟。關中父老百領襦，", "殷勤為我下田鉏，百錢攜賞絲桐客。遊春漫光塢花白，"]'),
('yuding-5','舞曲歌辭：公莫舞歌','李賀','唐','御定全唐诗','yuding','','[]','方花古礎排九楹，刺豹淋血盛銀罌。華筵鼓吹無桐竹，',72,'御定全唐詩/json/022.json','["方花古礎排九楹，刺豹淋血盛銀罌。華筵鼓吹無桐竹，", "腰下三看寶玦光，項莊掉箾攔前起。材官小臣公莫舞，", "鐵樞鐵楗重束關，大旗五丈撞雙環。漢王今日須秦印，"]'),
('yuding-6','舞曲歌辭：拂舞辭','李賀','唐','御定全唐诗','yuding','','[]','吳娥聲絕天，空雲閑裴回。門外滿車馬，亦須生綠苔。',92,'御定全唐詩/json/022.json','["吳娥聲絕天，空雲閑裴回。門外滿車馬，亦須生綠苔。", "尊有烏程酒，勸君千萬壽。全勝漢武錦樓上，", "丹成作蛇乘白霧，千年重化玉井龜。從蛇作龜二千載。", "吳堤綠草年年在。背有八卦稱神仙，邪鱗頑甲滑腥涎。"]'),
('yuding-7','舞曲歌辭：白鳩辭','李白','唐','御定全唐诗','yuding','','[]','鏗鳴鐘，考朗鼓。歌白鳩，引拂舞。白鳩之白誰與鄰，',80,'御定全唐詩/json/022.json','["鏗鳴鐘，考朗鼓。歌白鳩，引拂舞。白鳩之白誰與鄰，", "首農政，鳴陽春。天子刻玉杖，鏤形賜耆人。", "白鷺亦白非純真，外潔其色心匪仁。闕五德，無司晨，", "鳳凰雖大聖，不願以為臣。"]'),
('yuding-8','舞曲歌辭：獨漉篇','李白','唐','御定全唐诗','yuding','','[]','獨漉水中泥，水濁不見月。不見月尚可，水深行人沒。',69,'御定全唐詩/json/022.json','["獨漉水中泥，水濁不見月。不見月尚可，水深行人沒。", "越鳥從南來，胡鷹亦北度。我欲彎弓向天射，", "雄劍掛壁，時時龍鳴。不斷犀象，繡澀苔生。國恥未雪，"]'),
('yuding-9','舞曲歌辭：獨漉歌','王建','唐','御定全唐诗','yuding','','[]','獨獨漉漉，鼠食貓肉。',26,'御定全唐詩/json/022.json','["獨獨漉漉，鼠食貓肉。", "烏日中，鶴露宿，黃河水直人心曲。"]'),
('yuding-10','舞曲歌辭：白紵辭二首','崔國輔','唐','御定全唐诗','yuding','','[]','洛陽梨花落如霰，河陽桃葉生複齊。',64,'御定全唐詩/json/022.json','["洛陽梨花落如霰，河陽桃葉生複齊。", "坐恐玉樓春欲盡，紅綿粉絮裛妝啼。", "董賢女弟在椒風，窈窕繁華貴後宮。", "璧帶金釭皆翡翠，一朝零落變成空。"]'),
('yuding-11','舞曲歌辭：白紵辭二首','楊衡','唐','御定全唐诗','yuding','','[]','玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，',72,'御定全唐詩/json/022.json','["玉纓翠佩雜輕羅，香汗微漬朱顏酡。為君起唱白紵歌，", "躡珠履，步瓊筵。輕身起舞紅燭前，芳姿豔態妖且妍。", "回眸轉袖暗催弦，涼風蕭蕭流水急。月華泛豔紅蓮濕，"]'),
('yuding-12','舞曲歌辭：白紵辭','李白','唐','御定全唐诗','yuding','','[]','揚清歌，發皓齒，北方佳人東鄰子。且吟白紵停淥水，',136,'御定全唐詩/json/022.json','["揚清歌，發皓齒，北方佳人東鄰子。且吟白紵停淥水，", "玉顏滿堂樂未終，館娃日落歌吹蒙。", "月寒江清夜沉沉，美人一笑千黃金，垂羅舞縠揚哀音。", "郢中白雪且莫吟，子夜吳歌動君心。動君心，冀君賞，", "吳刀翦彩縫舞衣，明妝麗服奪春輝，揚眉轉袖若雪飛。", "傾城獨立世所稀，激楚結風醉忘歸。高堂月落燭已微，"]'),
('yuding-13','舞曲歌辭：白紵歌二首','王建','唐','御定全唐诗','yuding','','[]','天河漫漫北斗粲，宮中烏啼知夜半。新縫白紵舞衣成，',96,'御定全唐詩/json/022.json','["天河漫漫北斗粲，宮中烏啼知夜半。新縫白紵舞衣成，", "酒多夜長夜未曉，月明燈光兩相照，後庭歌聲更窈窕。", "館娃宮中春日暮，荔枝木瓜花滿樹。城頭烏棲休擊鼓，", "美人醉起無次第，墮釵遺佩滿中庭。此時但願可君意，"]'),
('yuding-14','舞曲歌辭：白紵歌','張籍','唐','御定全唐诗','yuding','','[]','皎皎白紵白且鮮，將作春衫稱少年。裁縫長短不能定，',40,'御定全唐詩/json/022.json','["皎皎白紵白且鮮，將作春衫稱少年。裁縫長短不能定，", "衣裳著時寒食下，還把玉鞭鞭白馬。"]'),
('yuding-15','舞曲歌辭：白紵歌','柳宗元','唐','御定全唐诗','yuding','','[]','翠帷雙卷出傾城，龍劍破匣霜月明。朱唇掩抑悄無聲，',24,'御定全唐詩/json/022.json','["翠帷雙卷出傾城，龍劍破匣霜月明。朱唇掩抑悄無聲，"]'),
('yuding-16','舞曲歌辭：冬白紵歌','元稹','唐','御定全唐诗','yuding','','[]','吳宮夜長宮漏款，簾幕四垂燈焰暖。西施自舞王自管，',40,'御定全唐詩/json/022.json','["吳宮夜長宮漏款，簾幕四垂燈焰暖。西施自舞王自管，", "共笑越王窮惴惴，夜夜抱冰寒不睡。"]'),
('yuding-17','舞曲歌辭：霓裳辭十首','王建','唐','御定全唐诗','yuding','','[]','弟子部中留一色，聽風聽水作霓裳。',320,'御定全唐詩/json/022.json','["弟子部中留一色，聽風聽水作霓裳。", "散聲未足重來授，直到床前見上皇。", "中管五弦初半曲，遙教合上隔簾聽。", "一聲聲向天頭落，效得仙人夜唱經。", "自直梨園得出稀，更番上曲不教歸。", "一時跪拜霓裳徹，立地階前賜紫衣。", "旋翻新譜聲初足，除卻梨園未教人。", "宣與書家分手寫，中官走馬賜功臣。", "伴教霓裳有貴妃，從初直到曲成時。", "日長耳裏聞聲熟，拍數分毫錯總知。", "弦索摐摐隔彩雲，五更初發一山聞。", "武皇自送西王母，新換霓裳月色裙。", "敕賜宮人澡浴回，遙看美女院門開。", "一山星月霓裳動，好字先從殿裏來。", "傳呼法部按霓裳，新得承恩別作行。", "應是貴妃樓上看，內人舁下彩羅箱。", "朝元閣上山風起，夜聽霓裳玉露寒。", "宮女月中更替立，黃金梯滑並行難。", "知向華清年月滿，山頭山底種長生。", "去時留下霓裳曲，總是離宮別館聲。"]'),
('yuding-18','舞曲歌辭：柘枝詞','不詳','唐','御定全唐诗','yuding','','[]','將軍奉命即須行，塞外領強兵。',28,'御定全唐詩/json/022.json','["將軍奉命即須行，塞外領強兵。", "聞道烽煙動，腰間寶劍匣中鳴。"]'),
('yuding-19','舞曲歌辭：柘枝詞三首','薛能','唐','御定全唐诗','yuding','','[]','同營三十萬，震鼓伐西羌。戰血粘秋草，征塵攪夕陽。',108,'御定全唐詩/json/022.json','["同營三十萬，震鼓伐西羌。戰血粘秋草，征塵攪夕陽。", "歸來人不識，帝裏獨戎裝。", "懸軍征拓羯，內地隔蕭關。日色昆侖上，風聲朔漠間。", "何當千萬騎，颯颯貳師還。", "意氣成功日，春風起絮天。樓臺新邸第，歌舞小嬋娟。", "急破催搖曳，羅衫半脫肩。"]'),
('yuding-20','舞曲歌辭：屈柘詞','溫庭筠','唐','御定全唐诗','yuding','','[]','楊柳縈橋綠，玫瑰拂地紅。繡衫金騕褭，花髻玉瓏璁。',48,'御定全唐詩/json/022.json','["楊柳縈橋綠，玫瑰拂地紅。繡衫金騕褭，花髻玉瓏璁。", "宿雨香潛潤，春流水暗通。畫樓初夢斷，晴日照湘風。"]'),
('yuding-0','琴曲歌辭：白雪歌','貫休','唐','御定全唐诗','yuding','','[]','列鼎佩金章，淚眼看風枝。卻思食藜藿，身作屠沽兒。',72,'御定全唐詩/json/023.json','["列鼎佩金章，淚眼看風枝。卻思食藜藿，身作屠沽兒。", "負米無遠近，所希升鬥歸。為人無貴賤，莫學雞狗肥。", "斯言如不忘，別更無光輝。斯言如或忘，即安用人為。"]'),
('yuding-1','琴曲歌辭：湘妃','劉長卿','唐','御定全唐诗','yuding','','[]','帝子不可見，秋風來暮思。嬋娟湘江月，千載空蛾眉。',24,'御定全唐詩/json/023.json','["帝子不可見，秋風來暮思。嬋娟湘江月，千載空蛾眉。"]'),
('yuding-2','琴曲歌辭：湘妃','李賀','唐','御定全唐诗','yuding','','[]','筠竹千年老不死，長伴秦娥蓋湘水。蠻娘吟弄滿寒空，',40,'御定全唐詩/json/023.json','["筠竹千年老不死，長伴秦娥蓋湘水。蠻娘吟弄滿寒空，", "幽愁秋氣上青楓，涼夜波間吟古龍。"]'),
('yuding-3','琴曲歌辭：湘妃怨','孟郊','唐','御定全唐诗','yuding','','[]','南巡竟不返，帝子怨逾積。萬里喪蛾眉，瀟湘水空碧。',72,'御定全唐詩/json/023.json','["南巡竟不返，帝子怨逾積。萬里喪蛾眉，瀟湘水空碧。", "冥冥荒山下，古廟收貞魄。喬木深青春，清光滿瑤席。", "搴芳徒有薦，靈意殊脈脈。玉佩不可親，裴回煙波夕。"]'),
('yuding-4','琴曲歌辭：湘妃怨','陳羽','唐','御定全唐诗','yuding','','[]','二妃怨處雲沉沉，二妃哭處湘水深。',32,'御定全唐詩/json/023.json','["二妃怨處雲沉沉，二妃哭處湘水深。", "商人酒滴廟前草，蕭颯風生斑竹林。"]'),
('yuding-5','琴曲歌辭：湘妃列女操','鮑溶','唐','御定全唐诗','yuding','','[]','有虞夫人哭虞後，淑女何事又傷離。竹上淚跡生不盡，',96,'御定全唐詩/json/023.json','["有虞夫人哭虞後，淑女何事又傷離。竹上淚跡生不盡，", "三湘測測流急綠，秋夜露寒蜀帝飛。楓林月斜楚臣宿，", "終疑既遠雙悄悄，蒼梧舊雲豈難召，老猿心寒不可嘯。", "目眄眄兮意蹉跎，魂騰騰兮驚秋波。曲一盡兮憶再奏，"]'),
('yuding-6','琴曲歌辭：湘夫人','鄒紹先','唐','御定全唐诗','yuding','','[]','楓葉下秋渚，二妃愁渡湘。疑山空杳藹，何處望君王。',36,'御定全唐詩/json/023.json','["楓葉下秋渚，二妃愁渡湘。疑山空杳藹，何處望君王。", "日落水雲裏，油油心自傷。"]'),
('yuding-7','琴曲歌辭：湘夫人','李頎','唐','御定全唐诗','yuding','','[]','九嶷日已暮，三湘雲複愁。窅藹羅袂色，潺湲江水流。',36,'御定全唐詩/json/023.json','["九嶷日已暮，三湘雲複愁。窅藹羅袂色，潺湲江水流。", "佳期來北渚，捐玦在芳洲。"]'),
('yuding-8','琴曲歌辭：湘夫人','郎士元','唐','御定全唐诗','yuding','','[]','娥眉對湘水，遙哭蒼梧間。萬乘既已歿，孤舟誰忍還。',72,'御定全唐詩/json/023.json','["娥眉對湘水，遙哭蒼梧間。萬乘既已歿，孤舟誰忍還。", "至今楚山上，猶有淚痕斑。南有涔陽路，渺渺多新愁。", "昔神降回時，風波江上秋。彩雲忽無處，碧水空安流。"]'),
('yuding-9','琴曲歌辭：霹靂引','沈佺期','唐','御定全唐诗','yuding','','[]','歲七月，火伏而金生。客有鼓瑟於門者，奏霹靂之商聲。',70,'御定全唐詩/json/023.json','["歲七月，火伏而金生。客有鼓瑟於門者，奏霹靂之商聲。", "始戛羽以騞砉，終扣宮而砰駖。電耀耀兮龍躍，", "有如驅千旗，制五兵，截荒虺，斫長鯨。孰與廣陵比，"]'),
('yuding-10','琴曲歌辭：拘幽操','韓愈','唐','御定全唐诗','yuding','','[]','目掩掩兮其凝其盲，耳肅肅兮聽不聞聲。',53,'御定全唐詩/json/023.json','["目掩掩兮其凝其盲，耳肅肅兮聽不聞聲。", "朝不日出兮夜不見月與星，有知無知兮為死為生。", "嗚呼！臣罪當誅兮天王聖明。"]'),
('yuding-11','琴曲歌辭：越裳操','韓愈','唐','御定全唐诗','yuding','','[]','雨之施，物以孳。我何意於彼為？自周之先，其艱其勤。',70,'御定全唐詩/json/023.json','["雨之施，物以孳。我何意於彼為？自周之先，其艱其勤。", "以有疆宇，私我後人。我祖在上，四方在下。", "厥臨孔威，敢戲以侮。孰荒於門，孰治于田。四海既均，"]'),
('yuding-12','琴曲歌辭：岐山操','韓愈','唐','御定全唐诗','yuding','','[]','我家於豳，自我先公。伊我承緒，敢有不同。',60,'御定全唐詩/json/023.json','["我家於豳，自我先公。伊我承緒，敢有不同。", "今狄之人，將土我疆。民為我戰，誰使死傷。", "彼岐有岨，我往獨處。人莫餘追，無思我悲。"]'),
('yuding-13','琴曲歌辭：履霜操','韓愈','唐','御定全唐诗','yuding','','[]','父兮兒寒，母兮兒饑。兒罪當笞，逐兒何為。',80,'御定全唐詩/json/023.json','["父兮兒寒，母兮兒饑。兒罪當笞，逐兒何為。", "兒在中野，以宿以處。四無人聲，誰與兒語。", "兒寒何衣，兒饑何食。兒行于野，履霜以足。", "母生眾兒，有母憐之。獨無母憐，兒甯不悲。"]'),
('yuding-14','琴曲歌辭：雉朝飛操','李白','唐','御定全唐诗','yuding','','[]','麥隴青青三月時，白雉朝飛挾兩雌。錦衣綺翼何離褷，',48,'御定全唐詩/json/023.json','["麥隴青青三月時，白雉朝飛挾兩雌。錦衣綺翼何離褷，", "枯楊枯楊爾生荑，我獨七十而孤棲。彈弦寫恨意不盡，"]'),
('yuding-15','琴曲歌辭：雉朝飛操','韓愈','唐','御定全唐诗','yuding','','[]','雉之飛，於朝日。群雌孤雄，意氣橫出。當東而西，',23,'御定全唐詩/json/023.json','["雉之飛，於朝日。群雌孤雄，意氣橫出。當東而西，"]'),
('yuding-16','琴曲歌辭：雉朝飛操','張祜','唐','御定全唐诗','yuding','','[]','朝陽隴東泛暖景，雙啄雙飛雙顧影。朱冠錦襦聊日整，',48,'御定全唐詩/json/023.json','["朝陽隴東泛暖景，雙啄雙飛雙顧影。朱冠錦襦聊日整，", "雄飛在草雌在田，衷腸結憤氣呵天。聖人在上心不偏，"]'),
('yuding-17','琴曲歌辭：思歸引','張祜','唐','御定全唐诗','yuding','','[]','重重作閨清旦鐍，兩耳深聲長不徹。深宮坐愁百年身，',40,'御定全唐詩/json/023.json','["重重作閨清旦鐍，兩耳深聲長不徹。深宮坐愁百年身，", "故鄉不歸誰共穴，石上作蒲蒲九節。"]'),
('yuding-18','琴曲歌辭：猗蘭操','韓愈','唐','御定全唐诗','yuding','','[]','蘭之猗猗，揚揚其香。不采而佩，于蘭何傷。',80,'御定全唐詩/json/023.json','["蘭之猗猗，揚揚其香。不采而佩，于蘭何傷。", "今天之旋，其曷為然。我行四方，以日以年。", "雪霜貿貿，薺麥之茂。子如不傷，我不爾覯。", "薺麥之茂，薺麥之有。君子之傷，君子之守。"]'),
('yuding-19','琴曲歌辭：幽蘭','崔塗','唐','御定全唐诗','yuding','','[]','幽植眾能知，貞芳只暗持。自無君子佩，未是國香衰。',48,'御定全唐詩/json/023.json','["幽植眾能知，貞芳只暗持。自無君子佩，未是國香衰。", "白露沾長早，青春每到遲。不知當路草，芳馥欲何為。"]'),
('yuding-20','琴曲歌辭：將歸操','韓愈','唐','御定全唐诗','yuding','','[]','秋之水兮其色幽幽，我將濟兮不得其由。',61,'御定全唐詩/json/023.json','["秋之水兮其色幽幽，我將濟兮不得其由。", "涉其淺兮石齧我足，乘其深兮龍入我舟。", "我濟而悔兮將安歸尤。歸乎歸乎，無與石鬥兮無應龍求。"]'),
('yuding-21','琴曲歌辭：龜山操','韓愈','唐','御定全唐诗','yuding','','[]','龜之氣兮不能雲雨，龜之枿兮不中樑柱，',18,'御定全唐詩/json/023.json','["龜之氣兮不能雲雨，龜之枿兮不中樑柱，"]'),
('yuding-22','琴曲歌辭：殘形操','韓愈','唐','御定全唐诗','yuding','','[]','有獸維狸兮我夢得之，其身孔明兮而頭不知。',40,'御定全唐詩/json/023.json','["有獸維狸兮我夢得之，其身孔明兮而頭不知。", "吉凶何為兮覺坐而思，巫咸上天兮識者其誰。"]'),
('yuding-23','琴曲歌辭：雙燕離','李白','唐','御定全唐诗','yuding','','[]','雙燕複雙燕，雙飛令人羨。玉樓珠閣不獨棲，',56,'御定全唐詩/json/023.json','["雙燕複雙燕，雙飛令人羨。玉樓珠閣不獨棲，", "吳宮又焚蕩，雛盡巢亦空。憔悴一身在，孀雌憶故雄。", "雙飛難再得，傷我寸心中。"]'),
('yuding-24','琴曲歌辭：列女操','孟郊','唐','御定全唐诗','yuding','','[]','梧桐相待老，鴛鴦會雙死。貞婦貴殉夫，舍生亦如此。',36,'御定全唐詩/json/023.json','["梧桐相待老，鴛鴦會雙死。貞婦貴殉夫，舍生亦如此。", "波瀾誓不起，妾心井中水。"]'),
('yuding-25','琴曲歌辭：別鵠操','韓愈','唐','御定全唐诗','yuding','','[]','雄鵠銜枝來，雌鵠啄泥歸。巢成不生子，大義當乖離。',48,'御定全唐詩/json/023.json','["雄鵠銜枝來，雌鵠啄泥歸。巢成不生子，大義當乖離。", "江漢水之大，鵠身鳥之微。更無相逢日，安可相隨飛。"]'),
('yuding-26','琴曲歌辭：別鶴','楊巨源','唐','御定全唐诗','yuding','','[]','海鶴一為別，高程方杳然。影搖江海路，思結瀟湘天。',96,'御定全唐詩/json/023.json','["海鶴一為別，高程方杳然。影搖江海路，思結瀟湘天。", "皎然仰白日，真姿棲紫煙。含情九霄際，顧侶五雲前。", "遐心屬清都，淒響激朱弦。超搖間雲雨，迢遞各山川。", "東南信多水，會合當有年。雄飛戾冥寞，此意何由傳。"]'),
('yuding-27','琴曲歌辭：別鶴','王建','唐','御定全唐诗','yuding','','[]','主人一去池水絕，池鶴散飛不相別。青天漫漫碧海重，',40,'御定全唐詩/json/023.json','["主人一去池水絕，池鶴散飛不相別。青天漫漫碧海重，", "池邊巢破松樹死，樹頭年年烏生子。"]'),
('yuding-28','琴曲歌辭：別鶴','張籍','唐','御定全唐诗','yuding','','[]','雙鶴出雲溪，分飛各自迷。空巢在松杪，折羽落江泥。',48,'御定全唐詩/json/023.json','["雙鶴出雲溪，分飛各自迷。空巢在松杪，折羽落江泥。", "尋水終不飲，逢林亦未棲。別離應易老，萬里兩淒淒。"]'),
('yuding-29','琴曲歌辭：別鶴','杜牧','唐','御定全唐诗','yuding','','[]','分飛共所從，六翮勢摧風。聲斷碧雲外，影孤明月中。',48,'御定全唐詩/json/023.json','["分飛共所從，六翮勢摧風。聲斷碧雲外，影孤明月中。", "青田歸路遠，月桂舊巢空。矯翼知何處，天涯不可窮。"]'),
('yuding-30','琴曲歌辭：走馬引','李賀','唐','御定全唐诗','yuding','','[]','我有辭鄉劍，玉鋒堪截雲。襄陽走馬客，意氣自生春。',48,'御定全唐詩/json/023.json','["我有辭鄉劍，玉鋒堪截雲。襄陽走馬客，意氣自生春。", "朝嫌劍光靜，暮嫌劍花冷。能持劍向人，不解持照身。"]'),
('yuding-31','琴曲歌辭：昭君怨','白居易','唐','御定全唐诗','yuding','','[]','明妃風貌最娉婷，合在椒房應四星。只得當年備宮掖，',40,'御定全唐詩/json/023.json','["明妃風貌最娉婷，合在椒房應四星。只得當年備宮掖，", "自是君恩薄如紙，不須一向恨丹青。"]'),
('yuding-32','琴曲歌辭：昭君怨二首','張祜','唐','御定全唐诗','yuding','','[]','萬里邊城遠，千山行路難。舉頭惟見月，何處是長安。',48,'御定全唐詩/json/023.json','["萬里邊城遠，千山行路難。舉頭惟見月，何處是長安。", "漢庭無大議，戎虜幾先和。莫羨傾城色，昭君恨最多。"]'),
('yuding-33','琴曲歌辭：昭君怨','梁氏瓊','唐','御定全唐诗','yuding','','[]','自古無和親，貽災到妾身。胡風嘶去馬，漢月吊行輪。',48,'御定全唐詩/json/023.json','["自古無和親，貽災到妾身。胡風嘶去馬，漢月吊行輪。", "衣薄狼山雪，妝成虜塞春。回看父母國，生死畢胡塵。"]'),
('yuding-34','琴曲歌辭：明妃怨','楊淩','唐','御定全唐诗','yuding','','[]','漢國明妃去不還，馬駝弦管向陰山。',32,'御定全唐詩/json/023.json','["漢國明妃去不還，馬駝弦管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('yuding-35','琴曲歌辭：蔡氏五弄：游春曲二首','王涯','唐','御定全唐诗','yuding','','[]','萬樹江邊杏，新開一夜風。滿園深淺色，照在綠波中。',48,'御定全唐詩/json/023.json','["萬樹江邊杏，新開一夜風。滿園深淺色，照在綠波中。", "上苑何窮樹，花開次第新。香車與絲騎，風靜亦生塵。"]'),
('yuding-36','琴曲歌辭：蔡氏五弄：游春辭二首','王涯','唐','御定全唐诗','yuding','','[]','曲江絲柳變煙條，寒骨冰隨暖氣銷。',64,'御定全唐詩/json/023.json','["曲江絲柳變煙條，寒骨冰隨暖氣銷。", "才見春光生綺陌，已聞清樂動雲韶。", "經過柳陌與桃蹊，尋逐風光著處迷。", "鳥度時時沖絮起，花繁袞袞壓枝低。"]'),
('yuding-37','琴曲歌辭：蔡氏五弄：遊春辭三首','令狐楚','唐','御定全唐诗','yuding','','[]','晚遊臨碧殿，日上望春亭。芳樹羅仙仗，晴山展翠屏。',72,'御定全唐詩/json/023.json','["晚遊臨碧殿，日上望春亭。芳樹羅仙仗，晴山展翠屏。", "一夜好風吹，新花一萬枝。風前調玉管，花下簇金羈。", "閶闔春風起，蓬萊雪水消。相將折楊柳，爭取最長條。"]'),
('yuding-38','琴曲歌辭：蔡氏五弄：淥水曲','李白','唐','御定全唐诗','yuding','','[]','淥水明秋月，南湖采白蘋。荷花嬌欲語，愁殺蕩舟人。',24,'御定全唐詩/json/023.json','["淥水明秋月，南湖采白蘋。荷花嬌欲語，愁殺蕩舟人。"]'),
('yuding-39','琴曲歌辭：蔡氏五弄：淥水辭','李賀','唐','御定全唐诗','yuding','','[]','今宵好風月，阿侯在何處。為有傾城色，翻成足愁苦。',48,'御定全唐詩/json/023.json','["今宵好風月，阿侯在何處。為有傾城色，翻成足愁苦。", "東湖採蓮葉，南湖拔蒲根。未持寄小姑，且持感愁魂。"]'),
('yuding-40','琴曲歌辭：蔡氏五弄：幽居弄','顧況','唐','御定全唐诗','yuding','','[]','苔衣生，花露滴，月入西林蕩東壁。扣商占角兩三聲，',40,'御定全唐詩/json/023.json','["苔衣生，花露滴，月入西林蕩東壁。扣商占角兩三聲，", "關情命曲寄惆悵，久別江南山裏人。"]'),
('yuding-41','琴曲歌辭：蔡氏五弄：秋思二首','李白','唐','御定全唐诗','yuding','','[]','春陽如昨日，碧樹鳴黃鸝。蕪然蕙草暮，颯爾涼風吹。',96,'御定全唐詩/json/023.json','["春陽如昨日，碧樹鳴黃鸝。蕪然蕙草暮，颯爾涼風吹。", "天秋木葉下，月冷莎雞悲。坐愁群芳歇，白露凋華滋。", "閼氏黃葉落，妾望白登臺。月出碧雲斷，蟬聲秋色來。", "胡兵沙塞合，漢使玉關回。征客無歸日，空悲蕙草摧。"]'),
('yuding-42','琴曲歌辭：蔡氏五弄：秋思二首','鮑溶','唐','御定全唐诗','yuding','','[]','胡風吹雁翼，遠別無人鄉。君近雁來處，幾回斷君腸。',252,'御定全唐詩/json/023.json','["胡風吹雁翼，遠別無人鄉。君近雁來處，幾回斷君腸。", "昔奉千日書，撫心怨星霜。無書又千日，世路重茫茫。", "燕國有佳麗，蛾眉富春光。自然君歸晚，花落君空堂。", "君其若不然，歲晚雙鴛鴦。顧兔蝕殘月，幽光不如星。", "女兒晚事夫，顏色同秋螢。秋日邊馬思，武夫不遑甯。", "燕歌易水怨，劍舞蛟龍腥。風折連枝樹，水翻無蒂萍。", "立身多戶門，何必燕山銘。生世不如鳥，雙雙比翼翎。", "季秋天地間，萬物生意足。我憂長於生，安得及草木。", "試從古人願，致酒歌秉燭。燕趙皆世人，詎能長似玉。", "俯憐老期近，仰視日車速。蕭颯禦風君，魂夢願相逐。", "百年夜銷半，端為垂纓束。"]'),
('yuding-43','琴曲歌辭：蔡氏五弄：秋思','司空曙','唐','御定全唐诗','yuding','','[]','靜與懶相偶，年將衰共催。前途歡不集，往事恨空來。',48,'御定全唐詩/json/023.json','["靜與懶相偶，年將衰共催。前途歡不集，往事恨空來。", "晝景委紅葉，月華鋪綠苔。沉思更何有，結坐玉琴哀。"]'),
('yuding-44','琴曲歌辭：蔡氏五弄：秋思','司空圖','唐','御定全唐诗','yuding','','[]','身病時亦危，逢秋多慟哭。風波一搖盪，天地幾翻覆。',48,'御定全唐詩/json/023.json','["身病時亦危，逢秋多慟哭。風波一搖盪，天地幾翻覆。", "孤螢出荒池，落葉穿破屋。勢利長草草，何人訪幽獨。"]'),
('yuding-45','琴曲歌辭：蔡氏五弄：秋思二首','王涯','唐','御定全唐诗','yuding','','[]','網軒涼吹動輕衣，夜聽更長玉漏稀。',64,'御定全唐詩/json/023.json','["網軒涼吹動輕衣，夜聽更長玉漏稀。", "月渡天河光轉濕，鵲驚秋樹葉頻飛。", "宮連太液見蒼波，暑氣微清秋意多。", "一夜輕風蘋末起，露珠翻盡滿池荷。"]'),
('yuding-46','琴曲歌辭：胡笳十八拍','劉商','唐','御定全唐诗','yuding','','[]','漢室將衰兮四夷不賓，動干戈兮征戰頻。',482,'御定全唐詩/json/023.json','["漢室將衰兮四夷不賓，動干戈兮征戰頻。", "哀哀父母生育我，見離亂兮當此辰。紗窗對鏡未經事，", "忽將薄命委鋒鏑，可惜紅顏隨虜塵。", "馬上將余向絕域，厭生求死死不得。戎羯腥膻豈是人，", "萬里重陰鳥不飛，寒沙莽莽無南北。", "如羈囚兮在縲絏，憂慮萬端無處說。使餘力兮翦餘發，", "早被蛾眉累此身，空悲弱質柔如水。", "山川路長誰記得，何處天涯是鄉國。自從驚怖少精神，", "漫漫胡天叫不聞，明明漢月應相識。", "水頭宿兮草頭坐，風吹漢地衣裳破。羊脂沐發長不梳，", "氈帳時移無定居，日月長兮不可過。", "怪得春光不來久，胡中風土無花柳。天翻地覆誰得知，", "是非取與在指撝，言語傳情不如手。", "男兒婦人帶弓箭，塞馬蕃羊臥霜霰。寸步東西豈自由，", "竟夕無雲月上天，故鄉應得重相見。", "憶昔私家恣嬌小，遠取珍禽學馴擾。如今淪棄念故鄉，", "旦夕思歸不得歸，愁心想似籠中鳥。", "當日蘇武單于問，道是賓鴻解傳信。學他刺血寫得書，", "遂令邊雁轉怕人，絕域何由達方寸。", "恨淩辱兮惡腥膻，憎胡地兮怨胡天。生得胡兒欲棄捐，", "朝朝暮暮在眼前，腹生手養甯不憐。", "日來月往相推遷，迢迢星歲欲周天。無冬無夏臥霜霰，", "幾回鴻雁來又去，腸斷蟾蜍虧複圓。", "破瓶落井空永沉，故鄉望斷無歸心。寧知遠使問姓名，"]'),
('yuding-47','琴曲歌辭：飛龍引二首','李白','唐','御定全唐诗','yuding','','[]','黃帝鑄鼎于荊山，煉丹砂，丹砂成黃金。',106,'御定全唐詩/json/023.json','["黃帝鑄鼎于荊山，煉丹砂，丹砂成黃金。", "騎龍飛上太清家，雲愁海思令人嗟。宮中彩女顏如花，", "鼎湖流水清且閑，軒轅去時有弓劍。古人傳道留其間，", "造天關，聞天語，長雲河車載玉女。載玉女，過紫皇，", "下視瑤池見王母，蛾眉蕭颯如秋霜。"]'),
('yuding-48','琴曲歌辭：烏夜啼引','張籍','唐','御定全唐诗','yuding','','[]','秦烏啼啞啞，夜啼長安吏人家。吏人得罪囚在獄，',44,'御定全唐詩/json/023.json','["秦烏啼啞啞，夜啼長安吏人家。吏人得罪囚在獄，", "下床心喜不重寐，未明上堂賀舅姑。少婦語啼烏，"]'),
('yuding-49','琴曲歌辭：宛轉歌','郎大家宋氏','唐','御定全唐诗','yuding','','[]','風已清，月朗琴複鳴。掩抑非千態，殷勤是一聲。',74,'御定全唐詩/json/023.json','["風已清，月朗琴複鳴。掩抑非千態，殷勤是一聲。", "歌宛轉，宛轉和且長。願為雙鴻鵠，比翼共翱翔。", "日已暮，長簷鳥應度。此時望君君不來，", "願為形與影，出入恒相逐。"]'),
('yuding-50','琴曲歌辭：宛轉歌二首','劉方平','唐','御定全唐诗','yuding','','[]','星參差，月二八，燈五枝。黃鶴瑤琴將別去，',40,'御定全唐詩/json/023.json','["星參差，月二八，燈五枝。黃鶴瑤琴將別去，", "曉將近，黃姑織女銀河盡。九華錦衾無複情，"]'),
('yuding-51','琴曲歌辭：宛轉行','張籍','唐','御定全唐诗','yuding','','[]','華屋重翠幄，綺席雕象床。遠漏微更疏，薄衾中夜涼。',60,'御定全唐詩/json/023.json','["華屋重翠幄，綺席雕象床。遠漏微更疏，薄衾中夜涼。", "爐氳暗裴回，寒燈背斜光。妍姿結宵態，寢臂幽夢長。", "宛轉複宛轉，憶憶更未央。"]'),
('yuding-52','琴曲歌辭：王敬伯歌','李端','唐','御定全唐诗','yuding','','[]','妾本舟中客，聞君江上琴。君初感妾歎，妾亦感君心。',108,'御定全唐詩/json/023.json','["妾本舟中客，聞君江上琴。君初感妾歎，妾亦感君心。", "遂出合歡被，同為交頸禽。傳杯惟畏淺，接膝猶嫌遠。", "侍婢奏箜篌，女郎歌宛轉。宛轉怨如何，中庭霜漸多。", "霜多葉可惜，昨日非今夕。徒結萬里歡，終成一宵客。", "王敬伯，淥水青山從此隔。"]'),
('yuding-53','琴曲歌辭：三峽流泉歌','李季蘭','唐','御定全唐诗','yuding','','[]','妾家本住巫山雲，巫山流水常自聞。玉琴彈出轉寥夐，',72,'御定全唐詩/json/023.json','["妾家本住巫山雲，巫山流水常自聞。玉琴彈出轉寥夐，", "巨石奔崖指下生，飛波走浪弦中起。初疑噴湧含雷風，", "憶昔阮公為此曲，能使仲容聽不足。一彈既罷複一彈，"]'),
('yuding-54','琴曲歌辭：風入松歌','皎然','唐','御定全唐诗','yuding','','[]','西嶺松聲落日秋，千枝萬葉風颼飀。美人援琴弄成曲，',63,'御定全唐詩/json/023.json','["西嶺松聲落日秋，千枝萬葉風颼飀。美人援琴弄成曲，", "美人夜坐月明裏，含少商兮照清征。風何淒兮飄飉，", "何人此時不得意，意苦弦悲聞客堂。"]'),
('yuding-55','琴曲歌辭：秋風引','劉禹錫','唐','御定全唐诗','yuding','','[]','何處秋風至，蕭蕭送雁群。朝來入庭樹，孤客最先聞。',24,'御定全唐詩/json/023.json','["何處秋風至，蕭蕭送雁群。朝來入庭樹，孤客最先聞。"]'),
('yuding-56','琴曲歌辭：明月引','盧照鄰','唐','御定全唐诗','yuding','','[]','洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。',74,'御定全唐詩/json/023.json','["洞庭波起兮鴻雁翔，風瑟瑟兮野蒼蒼。", "浮雲卷靄，明月流光。荊南兮趙北，碣石兮瀟湘。", "澄清規於萬里，照離思於千行。橫桂枝於西第，", "試登高而極目，莫不變而回腸。"]'),
('yuding-57','琴曲歌辭：明月歌','閻朝隱','唐','御定全唐诗','yuding','','[]','梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠泠刻漏長。',40,'御定全唐詩/json/023.json','["梅花雪白柳葉黃，雲霧四起月蒼蒼，箭水泠泠刻漏長。", "揮玉指，拂羅裳，為君一奏楚明光。"]'),
('yuding-58','琴曲歌辭：綠竹引','宋之問','唐','御定全唐诗','yuding','','[]','青溪綠潭潭水側，修竹嬋娟同一色。徒生仙實鳳不遊，',39,'御定全唐詩/json/023.json','["青溪綠潭潭水側，修竹嬋娟同一色。徒生仙實鳳不遊，", "含情傲慰心目，何可一日無此君。"]'),
('yuding-59','琴曲歌辭：山人勸酒','李白','唐','御定全唐诗','yuding','','[]','蒼蒼雲松，落落綺皓。春風爾來為阿誰，',40,'御定全唐詩/json/023.json','["蒼蒼雲松，落落綺皓。春風爾來為阿誰，", "稱是秦時避世人，勸酒相歡不知老。各守兔鹿志，"]'),
('yuding-60','琴曲歌辭：幽澗泉','李白','唐','御定全唐诗','yuding','','[]','拂彼白石，彈吾素琴。幽澗愀兮流泉深，',67,'御定全唐詩/json/023.json','["拂彼白石，彈吾素琴。幽澗愀兮流泉深，", "中見愁猿吊影而危處兮，叫秋木而長吟。", "客有哀時失志而聽者，淚淋浪以沾襟。乃緝商綴羽，", "幽澗泉，鳴深林。"]'),
('yuding-61','琴曲歌辭：龍宮操','顧況','唐','御定全唐诗','yuding','','[]','龍宮月明光參差，精衛銜石東飛時，鮫人織綃采藕絲。',48,'御定全唐詩/json/023.json','["龍宮月明光參差，精衛銜石東飛時，鮫人織綃采藕絲。", "翻江倒海傾吳蜀，漢女江妃杳相續，龍王宮中水不足。"]'),
('yuding-62','琴曲歌辭：飛鳶操','劉禹錫','唐','御定全唐诗','yuding','','[]','鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。旗尾飄揚勢漸高，',96,'御定全唐詩/json/023.json','["鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。旗尾飄揚勢漸高，", "遊鶤翔雁出其下，慶雲清景相迴旋。忽聞饑烏一噪聚，", "畏人避犬投高處，俯啄無聲猶屢顧。青鳥自愛玉山禾，", "游童挾彈一麾肘，臆碎羽分人不悲。天生眾禽各有類，"]'),
('yuding-63','琴曲歌辭：升仙操','李群玉','唐','御定全唐诗','yuding','','[]','嬴女去秦宮，瓊簫生碧空。鳳台閉煙霧，鸞吹飄天風。',72,'御定全唐詩/json/023.json','["嬴女去秦宮，瓊簫生碧空。鳳台閉煙霧，鸞吹飄天風。", "複聞周太子，亦遇浮丘公。叢簧發仙弄，輕舉紫霞中。", "濁世不久住，清都路何窮。一去霄漢上，世人那得逢。"]'),
('yuding-64','琴曲歌辭：司馬相如琴歌','張祜','唐','御定全唐诗','yuding','','[]','鳳兮鳳兮非無凰，山重水闊不可量。',32,'御定全唐詩/json/023.json','["鳳兮鳳兮非無凰，山重水闊不可量。", "梧桐結陰在朝陽，濯羽弱水鳴高翔。"]'),
('yuding-65','琴曲歌辭：霍將軍','崔顥','唐','御定全唐诗','yuding','','[]','長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，',48,'御定全唐詩/json/023.json','["長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，", "莫言貧賤即可欺，人生富貴自有時。一朝天子賜顏色，"]'),
('yuding-66','琴曲歌辭：琴歌','顧況','唐','御定全唐诗','yuding','','[]','琴調秋些，胡風繞雪。峽泉聲咽，佳人愁些。',20,'御定全唐詩/json/023.json','["琴調秋些，胡風繞雪。峽泉聲咽，佳人愁些。"]'),
('yuding-0','雜曲歌辭：秦女休行','李白','唐','御定全唐诗','yuding','','[]','西門秦氏女，秀色如瓊花。手揮白楊刀，清晝殺仇家。',108,'御定全唐詩/json/024.json','["西門秦氏女，秀色如瓊花。手揮白楊刀，清晝殺仇家。", "羅袖灑赤血，英聲淩紫霞。直上西山去，關吏相邀遮。", "婿為燕國王，身被詔獄加。犯刑若履虎，不畏落爪牙。", "素頸未及斷，摧眉伏泥沙。金雞忽放赦，大辟得寬賒。", "何慚聶政姊，萬古共驚嗟。"]'),
('yuding-1','雜曲歌辭：出門行二首','孟郊','唐','御定全唐诗','yuding','','[]','長河悠悠去無極，百齡同此可歎息。秋風白露沾人衣，',96,'御定全唐詩/json/024.json','["長河悠悠去無極，百齡同此可歎息。秋風白露沾人衣，", "一聞陌上苦寒奏，使我佇立驚且悲。君今得意厭粱肉，", "海風蕭蕭天雨霜，窮愁獨坐夜何長。驅車舊憶太行險，", "手持琅玕欲有贈，愛而不見心斷絕。南山峨峨白石爛，"]'),
('yuding-2','雜曲歌辭：出門行','元稹','唐','御定全唐诗','yuding','','[]','兄弟同出門，同行不同志。淒淒分岐路，各各營所為。',408,'御定全唐詩/json/024.json','["兄弟同出門，同行不同志。淒淒分岐路，各各營所為。", "兄上荊山巔，翻石辨虹氣。弟沉滄海底，偷珠待龍睡。", "出門不數年，同歸亦同遂。俱用私所珍，升沉自茲異。", "獻珠龍王宮，值龍覓珠次。但喜複得珠，不求珠所自。", "酬客雙龍女，授客六龍轡。遣充行雨神，雨澤隨客意。", "雩夏鐘鼓繁，禜秋玉帛積。彩色畫廊廟，奴僮被珠翠。", "驥騄千萬雙，鴛鴦七十二。言者禾稼枯，無人敢輕議。", "其兄因獻璞，再刖不履地。門戶親戚疏，匡床妻妾棄。", "銘心有所待，視足無所愧。持璞自枕頭，淚痕雙血漬。", "一朝龍醒寤，本問偷珠事。因知行雨偏，妻子五刑備。", "仁兄捧屍哭，勢友掉頭諱。喪車黔首葬，吊客青蠅至。", "楚有望氣人，王前忽長跪。賀王得貴寶，不遠王所蒞。", "求之果如言，剖則浮雲膩。白珩無顏色，垂棘有瑕累。", "在楚列地封，入趙連城貴。秦遣李斯書，書為傳國瑞。", "秦亡漢魏傳，傳者得神器。卞和名永永，與寶不相墜。", "勸爾出門行，行難莫行易。易得還易失，難同亦難離。", "善賈識貪廉，良田無稙稚。磨劍莫磨錐，磨錐成小利。"]'),
('yuding-3','雜曲歌辭：出自薊北門行','李白','唐','御定全唐诗','yuding','','[]','虜陣橫北荒，胡星曜精芒。羽書速驚電，烽火晝連光。',144,'御定全唐詩/json/024.json','["虜陣橫北荒，胡星曜精芒。羽書速驚電，烽火晝連光。", "虎竹救邊急，戎車森已行。明主不安席，按劍心飛揚。", "推轂出猛將，連旗登戰場。兵威沖絕漠，殺氣淩穹蒼。", "列卒赤山下，開營紫塞傍。途冬沙風緊，旌旗颯凋傷。", "畫角悲海月，征衣卷天霜。揮刃斬樓蘭，彎弓射賢王。", "單于一平蕩，種落自奔亡。收功報天子，行歌歸咸陽。"]'),
('yuding-4','雜曲歌辭：薊門行五首','高適','唐','御定全唐诗','yuding','','[]','邊城十一月，雨雪亂霏霏。元戎號令嚴，人馬亦輕肥。',180,'御定全唐詩/json/024.json','["邊城十一月，雨雪亂霏霏。元戎號令嚴，人馬亦輕肥。", "羌胡無盡日，征戰幾人歸。", "幽州多騎射，結髮重橫行。一朝事將軍，出入有聲名。", "紛紛獵秋草，相向角弓鳴。", "薊門逢古老，獨立思氛氳。一身既零丁，頭鬢白紛紛。", "勳庸今已矣，不識霍將軍。", "茫茫長城外，日沒更煙塵。胡騎雖憑陵，漢兵不顧身。", "古樹滿空塞，黃雲愁殺人。", "漢家能用武，開拓窮異域。戍卒厭糠核，降胡飽衣食。", "開亭試一望，吾欲涕沾臆。"]'),
('yuding-5','雜曲歌辭：薊門行','李希仲','唐','御定全唐诗','yuding','','[]','旄頭有精芒，胡騎獵秋草。羽檄南渡河，邊庭用兵早。',96,'御定全唐詩/json/024.json','["旄頭有精芒，胡騎獵秋草。羽檄南渡河，邊庭用兵早。", "漢家愛征戰，宿將今已老。辛苦羽林兒，從戎榆關道。", "一身救邊速，烽火連薊門。前軍鳥飛斷，格鬥塵沙昏。", "寒日鼓聲急，單于夜火奔。當須徇忠義，身死報國恩。"]'),
('yuding-6','雜曲歌辭：君子有所思行','李白','唐','御定全唐诗','yuding','','[]','紫閣連終南，青冥天倪色。憑崖望咸陽，宮闕羅北極。',132,'御定全唐詩/json/024.json','["紫閣連終南，青冥天倪色。憑崖望咸陽，宮闕羅北極。", "萬井驚畫出，九衢如弦直。渭水清銀河，橫天流不息。", "朝野盛文物，衣冠何翕赩。廄馬散連山，軍容威絕域。", "伊皋運元化，衛霍輸筋力。歌鐘樂未休，榮去老還逼。", "圓光過滿缺，太陽移中昃。不散東海金，何爭西輝匿。", "無作牛山悲，惻愴淚沾臆。"]'),
('yuding-7','雜曲歌辭：君子有所思行','貫休','唐','御定全唐诗','yuding','','[]','我愛正考甫，思賢作商頌。我愛揚子雲，理亂皆如鳳。',113,'御定全唐詩/json/024.json','["我愛正考甫，思賢作商頌。我愛揚子雲，理亂皆如鳳。", "振衣中夜起，露花香旖旎。撲碎驪龍明月珠，", "寂寥千載不相逢，無限區區盡虛擲。君不見沉約道，", "安得龍猛筆，點石為黃金。散問酷吏家，使無貪殘心。", "甘棠密葉成翠幄，潁鳳不來天地塞。所以傾城人，"]'),
('yuding-8','雜曲歌辭：傷歌行','張籍','唐','御定全唐诗','yuding','','[]','黃門詔下促收捕，京兆君系禦史府。出門無複部曲隨，',64,'御定全唐詩/json/024.json','["黃門詔下促收捕，京兆君系禦史府。出門無複部曲隨，", "身著青衫騎惡馬，東門之東無送者。郵夫防吏急喧驅，", "高堂舞榭鎖管弦，美人遙望西南天。"]'),
('yuding-9','雜曲歌辭：傷歌行','孟郊','唐','御定全唐诗','yuding','','[]','眾毒蔓貞松，一枝難久榮。豈知黃庭客，仙骨生不成。',72,'御定全唐詩/json/024.json','["眾毒蔓貞松，一枝難久榮。豈知黃庭客，仙骨生不成。", "春色舍芳蕙，秋風繞枯莖。彈琴不成曲，始覺知音傾。", "館月改舊照，吊賓寫餘情。還舟空江上，波浪送銘旌。"]'),
('yuding-10','雜曲歌辭：傷歌行','莊南傑','唐','御定全唐诗','yuding','','[]','兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，',48,'御定全唐詩/json/024.json','["兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，", "秋雨無情不惜花，芙蓉一一驚香倒。勸君莫謾栽荊棘，"]'),
('yuding-11','雜曲歌辭：悲歌','李白','唐','御定全唐诗','yuding','','[]','悲來乎，悲來乎，主人有酒且莫斟，聽我一曲悲來吟。',156,'御定全唐詩/json/024.json','["悲來乎，悲來乎，主人有酒且莫斟，聽我一曲悲來吟。", "悲來不吟還不笑，天下無人知我心。君有數鬥酒，", "悲來乎，悲來乎，天雖長，地雖久，金玉滿堂應不守。", "富貴百年能幾何，死生一度人皆有。孤猿坐啼墳上月，", "悲來乎，悲來乎，秦家李斯早追悔，虛名撥向身之外。", "範子何曾愛五湖，功成名遂身自退。劍是一夫用，", "還須黑頭取方伯，莫謾白首為儒生。"]'),
('yuding-12','雜曲歌辭：悲哉行','孟雲卿','唐','御定全唐诗','yuding','','[]','孤兒去慈親，遠客喪主人。莫吟苦辛曲，誰忍聞可聞。',84,'御定全唐詩/json/024.json','["孤兒去慈親，遠客喪主人。莫吟苦辛曲，誰忍聞可聞。", "可聞不可說，去去無期別。行人念前程，不待參辰沒。", "朝亦常苦饑，暮亦常苦饑。飄飄萬餘裏，貧賤多是非。", "少年莫遠遊，遠遊多不歸。"]'),
('yuding-13','雜曲歌辭：悲哉行','白居易','唐','御定全唐诗','yuding','','[]','悲哉為儒者，力學不能疲。讀書眼欲暗，秉筆手生胝。',192,'御定全唐詩/json/024.json','["悲哉為儒者，力學不能疲。讀書眼欲暗，秉筆手生胝。", "十上方一第，成名常苦遲。縱有宦達者，兩鬢已成絲。", "可憐少壯日，適在窮賤時。丈夫老且病，焉用富貴為。", "沉沉朱門宅，中有乳臭兒。狀貌如婦人，光明膏粱肌。", "手不把書卷，身不擐戎衣。二十襲封爵，門承勳戚資。", "春來日日出，服禦何輕肥。朝從博徒飲，暮有倡樓期。", "評封還酒債，堆金選蛾眉。聲色狗馬外，其餘一無知。", "山苗與澗松，地勢隨高卑。古來無奈何，非君獨傷悲。"]'),
('yuding-14','雜曲歌辭：悲哉行','鮑溶','唐','御定全唐诗','yuding','','[]','促促晨複昏，死生同一源。貴年不懼老，賤老傷久存。',108,'御定全唐詩/json/024.json','["促促晨複昏，死生同一源。貴年不懼老，賤老傷久存。", "朗朗哭前歌，絳旌引幽魂。來為千金子，去臥百草根。", "黃土塞生路，悲風送回轅。金鞍舊良馬，四顧不出門。", "生結千歲念，榮及百代孫。黃金買性命，白刃仇一言。", "寧知北山上，松柏侵田園。"]'),
('yuding-15','雜曲歌辭：妾薄命','崔國輔','唐','御定全唐诗','yuding','','[]','雖入秦帝宮，不上秦帝床。夜夜玉窗裏，與他卷羅裳。',24,'御定全唐詩/json/024.json','["雖入秦帝宮，不上秦帝床。夜夜玉窗裏，與他卷羅裳。"]'),
('yuding-16','雜曲歌辭：妾薄命','武平一','唐','御定全唐诗','yuding','','[]','有女妖且麗，裴回湘水湄。水湄蘭杜芳，采之將寄誰。',144,'御定全唐詩/json/024.json','["有女妖且麗，裴回湘水湄。水湄蘭杜芳，采之將寄誰。", "瓠犀發皓齒，雙蛾嚬翠眉。紅臉如開蓮，素膚若凝脂。", "綽約多逸態，輕盈不自持。常矜絕代色，複恃傾城姿。", "子夫前入侍，飛燕複當時。正悅掌中舞，寧哀團扇詩。", "洛川昔雲遇，高唐今尚違。幽閣禽雀噪，閑階草露滋。", "流景一何速，年華不可追。解佩安所贈，怨咽空自悲。"]'),
('yuding-17','雜曲歌辭：妾薄命','李百藥','唐','御定全唐诗','yuding','','[]','團扇秋風起，長門夜月明。羞聞拊背入，恨說舞腰輕。',48,'御定全唐詩/json/024.json','["團扇秋風起，長門夜月明。羞聞拊背入，恨說舞腰輕。", "太常應已醉，劉君恒帶酲。橫陳每虛設，吉夢竟何成。"]'),
('yuding-18','雜曲歌辭：妾薄命','杜審言','唐','御定全唐诗','yuding','','[]','草綠長門閉，苔青永巷幽。寵移新愛奪，泣下故情留。',48,'御定全唐詩/json/024.json','["草綠長門閉，苔青永巷幽。寵移新愛奪，泣下故情留。", "啼鳥驚殘夢，飛花攪獨愁。自憐春色罷，團扇複迎秋。"]'),
('yuding-19','雜曲歌辭：妾薄命','劉元淑','唐','御定全唐诗','yuding','','[]','自從離別守空閨，遙聞征戰起雲梯。夜夜愁君遼海外，',96,'御定全唐詩/json/024.json','["自從離別守空閨，遙聞征戰起雲梯。夜夜愁君遼海外，", "彩鸞琴裏怨聲多，飛鵲鏡前妝梳斷。誰家夫婿不從征，", "且逐新人殊未歸，還令秋至夜霜飛。北斗星前橫度雁，", "暗啼羅帳空自憐，夢度陽關向誰說。每憐容貌宛如神，"]'),
('yuding-20','雜曲歌辭：妾薄命','李白','唐','御定全唐诗','yuding','','[]','漢帝重阿嬌，貯之黃金屋。咳唾落九天，隨風生珠玉。',96,'御定全唐詩/json/024.json','["漢帝重阿嬌，貯之黃金屋。咳唾落九天，隨風生珠玉。", "寵極愛還歇，妒深情卻疏。長門一步地，不肯暫回車。", "雨落不上天，水覆難再收。君情與妾意，各自東西流。", "昔日芙蓉花，今成斷根草。以色事他人，能得幾時好。"]'),
('yuding-21','雜曲歌辭：妾薄命','孟郊','唐','御定全唐诗','yuding','','[]','不惜十指弦，為君千萬彈。常恐新聲至，坐使故聲殘。',72,'御定全唐詩/json/024.json','["不惜十指弦，為君千萬彈。常恐新聲至，坐使故聲殘。", "棄置今日悲，即是昨日歡。將新變故易，持故為新難。", "青山有蘼蕪，淚葉長不幹。空令後代人，采掇幽思攢。"]'),
('yuding-22','雜曲歌辭：妾薄命','張籍','唐','御定全唐诗','yuding','','[]','薄命婦，良家子，無事從軍去萬里。漢家天子平四夷，',48,'御定全唐詩/json/024.json','["薄命婦，良家子，無事從軍去萬里。漢家天子平四夷，", "與君一日為夫婦，千年萬歲亦相守。君愛龍城征戰功，"]'),
('yuding-23','雜曲歌辭：妾薄命三首','李端','唐','御定全唐诗','yuding','','[]','憶妾初嫁君，花鬟如綠雲。回燈入綺帳，對面脫羅裙。',156,'御定全唐詩/json/024.json','["憶妾初嫁君，花鬟如綠雲。回燈入綺帳，對面脫羅裙。", "折步教人學，偷香與客熏。容顏南國重，名字北方聞。", "一從失恩意，轉覺身憔悴。對鏡不梳頭，倚窗空落淚。", "新人莫恃新，秋至會無春。從來閉在長門者，", "玉壘城邊爭走馬，銅蹄市里共乘舟。鳴環動佩思無盡，", "忍懷賤妾平生曲，獨上襄陽舊酒樓。", "自從君棄妾，憔悴不羞人。惟餘壞粉淚，未免映衫勻。"]'),
('yuding-24','雜曲歌辭：妾薄命','盧綸','唐','御定全唐诗','yuding','','[]','妾年初二八，兩度嫁狂夫。薄命今猶在，堅貞掃地無。',24,'御定全唐詩/json/024.json','["妾年初二八，兩度嫁狂夫。薄命今猶在，堅貞掃地無。"]'),
('yuding-25','雜曲歌辭：妾薄命','盧弼','唐','御定全唐诗','yuding','','[]','君恩已斷盡成空，追想嬌歡恨莫窮。長為蕣華光曉日，',40,'御定全唐詩/json/024.json','["君恩已斷盡成空，追想嬌歡恨莫窮。長為蕣華光曉日，", "閑憑玉欄思舊事，幾回春暮泣殘紅。"]'),
('yuding-26','雜曲歌辭：妾薄命','胡曾','唐','御定全唐诗','yuding','','[]','阿嬌初失漢皇恩，舊賜羅衣亦罷熏。欹枕夜悲金屋雨，',40,'御定全唐詩/json/024.json','["阿嬌初失漢皇恩，舊賜羅衣亦罷熏。欹枕夜悲金屋雨，", "龍騎不巡時漸久，長門長掩綠苔文。"]'),
('yuding-27','雜曲歌辭：妾薄命','王貞白','唐','御定全唐诗','yuding','','[]','薄命頭欲白，頻年嫁不成。秦娥未十五，昨夜事公卿。',48,'御定全唐詩/json/024.json','["薄命頭欲白，頻年嫁不成。秦娥未十五，昨夜事公卿。", "豈有機杼力，空傳歌舞名。妾專修婦德，媒氏卻相輕。"]'),
('yuding-28','雜曲歌辭：羽林行','王建','唐','御定全唐诗','yuding','','[]','長安惡少出名字，樓下劫商樓上醉。天明下直明光宮，',48,'御定全唐詩/json/024.json','["長安惡少出名字，樓下劫商樓上醉。天明下直明光宮，", "九衢一日消息定，鄉吏籍中重改姓。出來依舊屬羽林，"]'),
('yuding-29','雜曲歌辭：羽林行','孟郊','唐','御定全唐诗','yuding','','[]','朔雪寒斷指，朔風勁裂冰。胡中射雕者，此日猶不能。',48,'御定全唐詩/json/024.json','["朔雪寒斷指，朔風勁裂冰。胡中射雕者，此日猶不能。", "翩翩羽林兒，錦臂飛蒼鷹。揮鞭決白馬，走出黃河淩。"]'),
('yuding-30','雜曲歌辭：羽林行','鮑溶','唐','御定全唐诗','yuding','','[]','朝出羽林宮，入參雲台議。獨請萬里行，不奏和親事。',108,'御定全唐詩/json/024.json','["朝出羽林宮，入參雲台議。獨請萬里行，不奏和親事。", "君王重年少，深納開邊利。寶馬雕玉鞍，一朝從萬騎。", "煌煌都門外，祖帳光七貴。歌鐘樂行軍，雲物慘別地。", "簫笳整部曲，幢蓋動郊次。臨風親戚懷，滿袖兒女淚。", "行行複何贈，長劍報恩字。"]'),
('yuding-31','雜曲歌辭：白馬篇','李白','唐','御定全唐诗','yuding','','[]','龍馬花雪毛，金鞍五陵豪。秋霜切玉劍，落日明珠袍。',120,'御定全唐詩/json/024.json','["龍馬花雪毛，金鞍五陵豪。秋霜切玉劍，落日明珠袍。", "鬥雞事萬乘，軒蓋一何高。弓摧宜山虎，手接泰山猱。", "酒後競風彩，三杯弄寶刀。殺人如翦草，劇孟同遊遨。", "發憤去函谷，從軍向臨洮。叱吒萬戰場，匈奴盡波濤。", "歸來使酒氣，未肯拜蕭曹。羞入原憲室，荒徑隱蓬蒿。"]'),
('yuding-32','雜曲歌辭：升天行','齊己','唐','御定全唐诗','yuding','','[]','身不沉，骨不重。驅青鸞，駕白鳳。幢蓋飄飄入冷空，',48,'御定全唐詩/json/024.json','["身不沉，骨不重。驅青鸞，駕白鳳。幢蓋飄飄入冷空，", "五三仙子乘龍車，堂前碾爛蟠桃花。回頭卻顧蓬山頂，"]'),
('yuding-33','雜曲歌辭：神仙曲','李賀','唐','御定全唐诗','yuding','','[]','碧峰海面藏靈書，上帝揀作神仙居。晴時笑語聞空虛，',48,'御定全唐詩/json/024.json','["碧峰海面藏靈書，上帝揀作神仙居。晴時笑語聞空虛，", "鶴羽沖風過海遲，不如卻使青龍去。猶疑王母不相許，"]'),
('yuding-34','雜曲歌辭：北風行','李白','唐','御定全唐诗','yuding','','[]','燭龍棲寒門，光曜猶旦開。日月照之何不及此，',85,'御定全唐詩/json/024.json','["燭龍棲寒門，光曜猶旦開。日月照之何不及此，", "倚門望行人，念君長城苦寒良可哀。別時提劍救邊去，", "箭空在，人今戰死不復回。不忍見此物，焚之已成灰。", "黃河捧土尚可塞，北風雨雪恨難裁。"]'),
('yuding-35','雜曲歌辭：苦熱行','王維','唐','御定全唐诗','yuding','','[]','赤日滿天地，火雲成山嶽。草木盡焦卷，川澤皆竭涸。',96,'御定全唐詩/json/024.json','["赤日滿天地，火雲成山嶽。草木盡焦卷，川澤皆竭涸。", "輕紈覺衣重，密樹苦陰薄。莞簟不可近，絺綌再三濯。", "思出宇宙外，曠然在寥廓。長風萬里來，江海蕩煩濁。", "卻顧身為患，始知心未覺。忽入甘露門，宛然清涼樂。"]'),
('yuding-36','雜曲歌辭：苦熱行','王轂','唐','御定全唐诗','yuding','','[]','祝融南來鞭火龍，火旗焰焰燒天紅。日輪當午凝不去，',40,'御定全唐詩/json/024.json','["祝融南來鞭火龍，火旗焰焰燒天紅。日輪當午凝不去，", "何當一夕金風發，為我掃卻天下熱。"]'),
('yuding-37','雜曲歌辭：苦熱行','皎然','唐','御定全唐诗','yuding','','[]','六月金數伏，茲辰日在庚。炎曦曝肌膚，毒霧昏簷楹。',120,'御定全唐詩/json/024.json','["六月金數伏，茲辰日在庚。炎曦曝肌膚，毒霧昏簷楹。", "安得奮翅翮，超遙出雲征。不知天地心，如何匠生成。", "火德燒百卉，瑤草不及榮。省客當此時，忽貽懷中瓊。", "捧玩煩袂滌，嘯歌美風生。遲君佐元氣，調使四序平。", "中令霜不襖，火餘氣常貞。江南詩騷客，休吟苦熱行。"]'),
('yuding-38','雜曲歌辭：苦熱行','齊己','唐','御定全唐诗','yuding','','[]','離宮劃開赤帝怒，喝起六龍奔日馭。下土熬熬若煎煮，',40,'御定全唐詩/json/024.json','["離宮劃開赤帝怒，喝起六龍奔日馭。下土熬熬若煎煮，", "何當一雨蘇我苗，為君擊壤歌帝堯。"]'),
('yuding-39','雜曲歌辭：太行苦熱行','劉長卿','唐','御定全唐诗','yuding','','[]','迢迢太行路，自古稱險惡。千騎儼欲前，群峰望如削。',192,'御定全唐詩/json/024.json','["迢迢太行路，自古稱險惡。千騎儼欲前，群峰望如削。", "火雲從中起，仰視飛鳥落。汗馬臥高原，危旌倚長薄。", "清風何不至，赤日方煎爍。石露山木焦，鱗窮水泉涸。", "九重今旰食，萬里傳明略。諸將候軒車，元兇愁鼎鑊。", "何勞短兵接，自有長纓縛。通越事豈難，渡瀘功未博。", "朝辭羊腸阪，夕望貝丘郭。漳水斜繞營，常山遙入幕。", "永懷姑蘇下，因寄建安作。白雪和誠難，滄波意空托。", "陳琳書記好，王粲從軍樂。早晚歸漢庭，隨君上麟閣。"]'),
('yuding-40','雜曲歌辭：太行苦熱行','獨孤及','唐','御定全唐诗','yuding','','[]','駟馬上太行，修途亙遼碣。王程無留駕，日昃未遑歇。',192,'御定全唐詩/json/024.json','["駟馬上太行，修途亙遼碣。王程無留駕，日昃未遑歇。", "請問此何時，恢台朱明月。長蛇稽天討，上將方北伐。", "明主命使臣，皇華得時傑。已忘羊腸險，豈憚溫風入。", "搖策汗滂沱，登崖思紆結。炎雲如煙火，溪穀將恐竭。", "晝景赩可畏，涼飆何由發。山長飛鳥墮，目極行車絕。", "趙魏方俶擾，安危俟明哲。歸路豈不懷，飲冰有苦節。", "會同傳檄至，疑議立談決。況有阮元瑜，翩翩秉書劄。", "起予歌赤阪，永好逾白雪。維念剖竹人，無因執羈絏。"]'),
('yuding-41','雜曲歌辭：春日行','李白','唐','御定全唐诗','yuding','','[]','深宮高樓入紫清，金作蛟龍盤繡楹。佳人當窗弄白日，',92,'御定全唐詩/json/024.json','["深宮高樓入紫清，金作蛟龍盤繡楹。佳人當窗弄白日，", "因出天池泛蓬瀛，樓船蹙遝波浪驚。三千雙蛾獻歌笑，", "三十六帝欲相迎，仙人飄翩下雲輧。帝不去，留鎬京。", "安能為軒轅，獨往入窅冥。小臣拜獻南山壽，"]'),
('yuding-42','雜曲歌辭：春日行','張籍','唐','御定全唐诗','yuding','','[]','春日融融池上暖，竹牙出土蘭心短。草堂晨起酒半醒，',48,'御定全唐詩/json/024.json','["春日融融池上暖，竹牙出土蘭心短。草堂晨起酒半醒，", "樹樹殷勤盡繞行，舉枝未遍春日暝。不用積金著青天，"]'),
('yuding-43','雜曲歌辭：朗月行','李白','唐','御定全唐诗','yuding','','[]','小時不識月，呼作白玉盤。又疑瑤台鏡，飛在青雲端。',96,'御定全唐詩/json/024.json','["小時不識月，呼作白玉盤。又疑瑤台鏡，飛在青雲端。", "仙人垂兩足，桂樹作團團。白兔搗藥成，問言與誰餐。", "蟾蜍蝕圜影，天明夜已殘。羿昔落九烏，天人清且安。", "陰精此淪惑，去去不足觀。憂來其如何，惻愴摧心肝。"]'),
('yuding-44','雜曲歌辭：前有一尊酒行二首','李白','唐','御定全唐诗','yuding','','[]','春風東來忽相過，金尊綠酒生微波。落花紛紛稍覺多，',72,'御定全唐詩/json/024.json','["春風東來忽相過，金尊綠酒生微波。落花紛紛稍覺多，", "君起舞，日西夕，當年意氣不肯傾，白髮如絲歎何益。", "琴奏龍門之綠桐，玉壺美酒清若空。催弦拂柱與君飲，"]'),
('yuding-45','雜曲歌辭：緩歌行','李頎','唐','御定全唐诗','yuding','','[]','小來托身攀貴遊，傾財破產無所憂。暮擬經過石渠署，',88,'御定全唐詩/json/024.json','["小來托身攀貴遊，傾財破產無所憂。暮擬經過石渠署，", "一沉一浮會有時，棄我翻然如脫屣。男兒立身須自強，", "二八蛾眉梳墮馬，美酒清歌曲房下。文昌宮中賜錦衣，", "早知今日讀書是，悔作從來任俠非。"]'),
('yuding-46','雜曲歌辭：結客少年場行','虞世南','唐','御定全唐诗','yuding','','[]','韓魏多奇節，倜儻遺名利。共矜然諾心，各負縱橫志。',132,'御定全唐詩/json/024.json','["韓魏多奇節，倜儻遺名利。共矜然諾心，各負縱橫志。", "結友一言重，相思千里至。綠沈明月弦，金絡浮雲轡。", "吹簫入吳市，擊築游燕肆。尋源博望侯，結客遠相求。", "少年重一顧，長驅背隴頭。焰焰霜戈動，耿耿劍虹浮。", "天山冬夏雪，交河南北流。雲起龍沙暗，木落雁行秋。", "輕生殉知己，非是為身謀。"]'),
('yuding-47','雜曲歌辭：結客少年場行','虞羽客','唐','御定全唐诗','yuding','','[]','幽並俠少年，金絡控連錢。竊符方救趙，擊築正懷燕。',120,'御定全唐詩/json/024.json','["幽並俠少年，金絡控連錢。竊符方救趙，擊築正懷燕。", "輕生辭鳳闕，揮袂上祁連。陸離橫寶劍，出沒驚徂旃。", "蒙輪恒顧敵，超乘忽爭先。摧枯逾百戰，拓地遠三千。", "骨都魂已散，樓蘭首複傳。龍城含曉霧，瀚海隔遙天。", "歌吹金微返，振旅玉門旋。烽火今已息，非複照甘泉。"]'),
('yuding-48','雜曲歌辭：結客少年場行','盧照鄰','唐','御定全唐诗','yuding','','[]','長安重遊俠，洛陽富才雄。玉劍浮雲騎，金鞍明月弓。',132,'御定全唐詩/json/024.json','["長安重遊俠，洛陽富才雄。玉劍浮雲騎，金鞍明月弓。", "鬥雞過渭北，走馬向關東。孫賓遙見待，郭解暗相通。", "不受千金爵，誰論萬里功。將軍下天上，虜騎入雲中。", "烽火夜似月，兵氣曉成虹。橫行徇知己，負羽遠從戎。", "龍旌昏朔霧，鳥陣卷寒風。追奔瀚海咽，戰罷陰山空。", "歸來謝天子，何如馬上翁。"]'),
('yuding-49','雜曲歌辭：結客少年場行','李白','唐','御定全唐诗','yuding','','[]','紫燕黃金瞳，啾啾搖綠鬃。平明相馳逐，結客洛門東。',120,'御定全唐詩/json/024.json','["紫燕黃金瞳，啾啾搖綠鬃。平明相馳逐，結客洛門東。", "少年學劍術，淩轢白猿公。珠袍曳錦帶，匕首插吳鴻。", "由來萬夫勇，挾此生雄風。托交從劇孟，買醉入新豐。", "笑盡一杯酒，殺人都市中。羞道易水寒，從令日貫虹。", "燕丹事不立，虛沒秦帝宮。舞陽死灰人，安可與成功。"]'),
('yuding-50','雜曲歌辭：結客少年場行','沈彬','唐','御定全唐诗','yuding','','[]','重義輕生一劍知，白虹貫日報仇歸。',32,'御定全唐詩/json/024.json','["重義輕生一劍知，白虹貫日報仇歸。", "片心惆悵清平世，酒市無人問布衣。"]'),
('yuding-51','雜曲歌辭：少年子','李百藥','唐','御定全唐诗','yuding','','[]','少年飛翠蓋，上路動金鑣。始酌文君酒，新吹弄玉簫。',72,'御定全唐詩/json/024.json','["少年飛翠蓋，上路動金鑣。始酌文君酒，新吹弄玉簫。", "少年不歡樂，何以盡芳朝。千金笑裏面，一搦抱中腰。", "掛冠豈憚宿，迎拜不勝嬌。寄語少年子，無辭歸路遙。"]'),
('yuding-52','雜曲歌辭：少年子','李白','唐','御定全唐诗','yuding','','[]','青雲少年子，挾彈章台左。鞍馬四邊開，突如流星過。',48,'御定全唐詩/json/024.json','["青雲少年子，挾彈章台左。鞍馬四邊開，突如流星過。", "金丸落飛鳥，夜入瓊樓臥。夷齊是何人，獨守西山餓。"]'),
('yuding-53','雜曲歌辭：少年樂','李賀','唐','御定全唐诗','yuding','','[]','芳草落花如錦地，二十長遊醉鄉裏。紅纓不重白馬驕，',40,'御定全唐詩/json/024.json','["芳草落花如錦地，二十長遊醉鄉裏。紅纓不重白馬驕，", "陸郎倚醉牽羅袂，奪得寶釵金翡翠。"]'),
('yuding-54','雜曲歌辭：少年樂','張祜','唐','御定全唐诗','yuding','','[]','二十便封侯，名居第一流。綠鬟深小院，清管下高樓。',72,'御定全唐詩/json/024.json','["二十便封侯，名居第一流。綠鬟深小院，清管下高樓。", "醉把金船擲，閑敲玉鐙遊。帶盤紅鼴鼠，袍砑紫犀牛。", "錦袋歸調箭，羅鞋起撥球。眼前長貴盛，那信世間愁。"]'),
('yuding-55','雜曲歌辭：少年行三首','李白','唐','御定全唐诗','yuding','','[]','擊築飲美酒，劍歌易水湄。經過燕太子，結托並州兒。',219,'御定全唐詩/json/024.json','["擊築飲美酒，劍歌易水湄。經過燕太子，結托並州兒。", "少年負壯氣，奮烈自有時。因聲魯句踐，爭情勿相欺。", "五陵年少金市東，銀鞍白馬度春風。", "落花踏盡遊何處，笑入胡姬酒肆中。", "君不見淮南少年游俠客，白日球獵夜擁擲。", "呼盧百萬終不惜，報仇千里如咫尺。少年遊俠好經過，", "驕矜自言不可有，俠士堂中養來久。好鞍好馬乞與人，", "桃李栽來幾度春，一回花落一回新。府縣盡為門下客，", "男兒百年且榮身，何須徇節甘風塵。衣冠半是征戰士，", "遮莫姻親連帝城，不如當身自簪纓。看取富貴眼前者，"]'),
('yuding-56','雜曲歌辭：少年行四首','王維','唐','御定全唐诗','yuding','','[]','新豐美酒鬥十千，咸陽遊俠多少年。',128,'御定全唐詩/json/024.json','["新豐美酒鬥十千，咸陽遊俠多少年。", "相逢意氣為君飲，系馬高樓垂柳邊。", "漢家君臣歡宴終，高議雲台論戰功。", "天子臨軒賜侯印，將軍佩出明光宮。", "出身仕漢羽林郎，初隨驃騎戰漁陽。", "孰知不向邊庭苦，縱死猶聞俠骨香。", "一身能臂兩雕弧，虜騎千群只似無。", "偏坐金鞍調白羽，紛紛射殺五單于。"]'),
('yuding-57','雜曲歌辭：少年行二首','王昌齡','唐','御定全唐诗','yuding','','[]','西陵俠年少，送客過長亭。青槐夾兩路，白馬如流星。',96,'御定全唐詩/json/024.json','["西陵俠年少，送客過長亭。青槐夾兩路，白馬如流星。", "聞道羽書急，單于寇井陘。氣高輕赴難，誰顧燕山銘。", "走馬還相尋，西樓下夕陰。結交期一劍，留意贈千金。", "高閣歌聲遠，重關柳色深。夜閑須盡醉，莫負百年心。"]'),
('yuding-58','雜曲歌辭：少年行','張籍','唐','御定全唐诗','yuding','','[]','少年從出獵長楊，禁中新拜羽林郎。獨到輦前射雙虎，',64,'御定全唐詩/json/024.json','["少年從出獵長楊，禁中新拜羽林郎。獨到輦前射雙虎，", "百里報仇夜出城，平明還在倡樓醉。遙聞虜到平陵下，", "不為六郡良家子，百戰始取邊城功。"]'),
('yuding-59','雜曲歌辭：少年行三首','李嶷','唐','御定全唐诗','yuding','','[]','十八羽林郎，戎衣事漢王。臂鷹金殿側，挾彈玉輿旁。',108,'御定全唐詩/json/024.json','["十八羽林郎，戎衣事漢王。臂鷹金殿側，挾彈玉輿旁。", "馳道春風起，陪游出建章。", "侍獵長楊下，承恩更射飛。塵生馬影滅，箭落雁行稀。", "薄暮歸隨仗，聯翩入瑣闈。", "玉劍膝邊橫，金杯馬上傾。朝遊茂陵道，暮宿鳳凰城。", "豪吏多猜忌，無勞問姓名。"]'),
('yuding-60','雜曲歌辭：少年行','劉長卿','唐','御定全唐诗','yuding','','[]','射飛誇侍獵，行樂愛聯鑣。薦枕青娥豔，鳴鞭白馬驕。',48,'御定全唐詩/json/024.json','["射飛誇侍獵，行樂愛聯鑣。薦枕青娥豔，鳴鞭白馬驕。", "曲房珠翠合，深巷管弦調。日晚春風裏，衣香滿路飄。"]'),
('yuding-61','雜曲歌辭：少年行四首','令狐楚','唐','御定全唐诗','yuding','','[]','少小邊州慣放狂，驏騎蕃馬射黃羊。',128,'御定全唐詩/json/024.json','["少小邊州慣放狂，驏騎蕃馬射黃羊。", "如今年事無筋力，猶倚營門數雁行。", "家本清河住五城，須憑弓箭得功名。", "等閒飛鞚秋原上，獨向寒雲試射聲。", "弓背霞明劍照霜，秋風走馬出咸陽。", "未收天子河湟地，不擬回頭望故鄉。", "霜滿中庭月過樓，金尊玉柱對清秋。", "當年稱意須為樂，不到天明未肯休。"]'),
('yuding-62','雜曲歌辭：少年行二首','杜牧','唐','御定全唐诗','yuding','','[]','官為駿馬監，職帥羽林兒。兩綬藏不見，落花何處期。',104,'御定全唐詩/json/024.json','["官為駿馬監，職帥羽林兒。兩綬藏不見，落花何處期。", "獵敲白玉鐙，怒袖紫金錘。田竇長留醉，蘇辛曲護岐。", "豪持出塞節，笑別遠山眉。捷報雲台賀，公卿拜夀卮。", "連環羈玉聲光碎，綠錦蔽泥虯卷高。", "春風細雨走馬去，珠落璀璀白罽袍。"]'),
('yuding-63','雜曲歌辭：少年行三首','杜甫','唐','御定全唐诗','yuding','','[]','莫笑田家老瓦盆，自從盛酒長兒孫。',96,'御定全唐詩/json/024.json','["莫笑田家老瓦盆，自從盛酒長兒孫。", "傾銀注瓦驚人眼，共醉終同臥竹根。", "巢燕養雛渾去盡，紅花結子已無多。", "黃衫年少來宜數，不見堂前東逝波。", "馬上誰家白麵郎，臨階下馬坐人床。", "不通姓字粗豪甚，指點銀瓶索酒嘗。"]'),
('yuding-64','雜曲歌辭：少年行','張祜','唐','御定全唐诗','yuding','','[]','少年足風情，垂鞭賣眼行。帶金師子小，裘錦騏驎獰。',48,'御定全唐詩/json/024.json','["少年足風情，垂鞭賣眼行。帶金師子小，裘錦騏驎獰。", "選匠裝金鐙，推錢買鈿箏。李陵雖效死，時論得虛名。"]'),
('yuding-65','雜曲歌辭：少年行','韓翃','唐','御定全唐诗','yuding','','[]','千點斕斒噴玉驄，青絲結尾繡纏鬃。鳴鞭晚出章台路，葉葉春依楊柳風。',32,'御定全唐詩/json/024.json','["千點斕斒噴玉驄，青絲結尾繡纏鬃。鳴鞭晚出章台路，葉葉春依楊柳風。"]'),
('yuding-66','雜曲歌辭：少年行','施肩吾','唐','御定全唐诗','yuding','','[]','醉騎白馬走空衢，惡少皆稱電不如。',32,'御定全唐詩/json/024.json','["醉騎白馬走空衢，惡少皆稱電不如。", "五鳳街頭閑勒轡，半垂衫袖揖金吾。"]'),
('yuding-67','雜曲歌辭：少年行三首','貫休','唐','御定全唐诗','yuding','','[]','錦衣鮮華手擎鶻，閑行氣貌多輕忽。',80,'御定全唐詩/json/024.json','["錦衣鮮華手擎鶻，閑行氣貌多輕忽。", "稼穡艱難總不知，五帝三皇是何物。", "自拳五色球，迸入他人宅。卻捉蒼頭奴，玉鞭打一百。", "面白如削玉，倡狂曲江曲。馬上黃金鞍，適來新賭得。"]'),
('yuding-68','雜曲歌辭：少年行','韋莊','唐','御定全唐诗','yuding','','[]','五陵豪客多，買酒黃金賤。醉下酒家樓，美人雙翠幰。',48,'御定全唐詩/json/024.json','["五陵豪客多，買酒黃金賤。醉下酒家樓，美人雙翠幰。", "揮劍邯鄲市，走馬梁王苑。樂事殊未央，年華已雲晚。"]'),
('yuding-69','雜曲歌辭：漢宮少年行','李益','唐','御定全唐诗','yuding','','[]','君不見上宮警夜營八屯，冬冬街鼓朝朱軒。',139,'御定全唐詩/json/024.json','["君不見上宮警夜營八屯，冬冬街鼓朝朱軒。", "玉階霜仗擁未合，少年排入銅龍門。暗聞弦管九天上，", "玉籠金瑣養黃口，探雛取卵伴王孫。分曹六博快一擲，", "晚來香街經柳市，行過倡市宿桃根。相逢杯酒一言失，", "豈知人事無定勢，朝歡暮戚如掌翻。椒房寵移子愛奪，", "持杯收水水已覆，徙薪避火火更燔。欲求四老張丞相，"]'),
('yuding-70','雜曲歌辭：長樂少年行','崔國輔','唐','御定全唐诗','yuding','','[]','遺卻珊瑚鞭，白馬驕不行。章台折楊柳，春草路旁情。',24,'御定全唐詩/json/024.json','["遺卻珊瑚鞭，白馬驕不行。章台折楊柳，春草路旁情。"]'),
('yuding-71','雜曲歌辭：長安少年行十首','李廓','唐','御定全唐诗','yuding','','[]','金紫少年郎，繞街鞍馬光。身從左中尉，官屬右春坊。',480,'御定全唐詩/json/024.json','["金紫少年郎，繞街鞍馬光。身從左中尉，官屬右春坊。", "剗戴揚州帽，重熏異國香。垂鞭踏青草，來去杏園芳。", "追逐輕薄伴，閒遊不著緋。長攏出獵馬，數換打球衣。", "曉日尋花去，春風帶酒歸。青樓無晝夜，歌舞歇時稀。", "日高春睡足，帖馬賞年華。倒插銀魚袋，行隨金犢車。", "還攜新市酒，遠醉曲江花。幾度歸侵黑，金吾送到家。", "好勝耽長行，天明燭滿樓。留人看獨腳，賭馬換偏頭。", "樂奏曾無歇，杯巡不暫休。時時遙冷笑，怪客有春愁。", "遨遊攜豔妓，裝束似男兒。杯酒逢花住，笙歌簇馬吹。", "鶯聲催曲急，春色訝歸遲。不以聞街鼓，華筵待月移。", "賞春惟逐勝，大宅可曾歸。不樂還逃席，多狂慣衩衣。", "歌人踏月起，語燕捲簾飛。好婦惟相妒，倡樓不醉稀。", "戟門連日閉，苦飲惜殘春。開瑣通新客，教姬屈醉人。", "請歌牽白馬，自舞踏紅茵。時輩皆相許，平生不負身。", "新年高殿上，始見有光輝。玉雁排方帶，金鵝立仗衣。", "酒深和碗賜，馬疾打珂飛。朝下人爭看，香街意氣歸。", "遊市慵騎馬，隨姬入坐車。樓邊聽歌吹，簾外市釵花。", "樂眼從人鬧，歸心畏日斜。蒼頭來去報，飲伴到倡家。", "小婦教鸚鵡，頭邊喚醉醒。犬嬌眠玉簟，鷹掣撼金鈴。", "碧地攢花障，紅泥待客亭。雖然長按曲，不飲不曾聽。"]'),
('yuding-72','雜曲歌辭：長安少年行','皎然','唐','御定全唐诗','yuding','','[]','翠樓春酒蝦蟆陵，長安少年皆共矜。',32,'御定全唐詩/json/024.json','["翠樓春酒蝦蟆陵，長安少年皆共矜。", "紛紛半醉綠槐道，蹀躞花驄驕不勝。"]'),
('yuding-73','雜曲歌辭：渭城少年行','崔顥','唐','御定全唐诗','yuding','','[]','洛陽二月梨花飛，秦地行人春憶歸。揚鞭走馬城南陌，',120,'御定全唐詩/json/024.json','["洛陽二月梨花飛，秦地行人春憶歸。揚鞭走馬城南陌，", "棠梨宮中燕初至，葡萄館裏花正開。念此使人歸更早，", "萬戶樓臺臨渭水，五陵花柳滿秦川。秦川寒食盛繁華，", "章台帝城稱貴裏，青樓日晚歌鐘起。貴裏豪家白馬驕，", "渭城橋頭酒新熟，金鞍白馬誰家宿。可憐錦瑟箏琵琶，"]'),
('yuding-74','雜曲歌辭：邯鄲少年行','高適','唐','御定全唐诗','yuding','','[]','邯鄲城南遊俠子，自矜生長邯鄲裏。千場縱博家仍富，',65,'御定全唐詩/json/024.json','["邯鄲城南遊俠子，自矜生長邯鄲裏。千場縱博家仍富，", "未知肝膽向誰是，令人卻憶平原君。君不見今人交態薄，", "且與少年飲美酒，往來射獵西山頭。"]'),
('yuding-75','雜曲歌辭：邯鄲少年行','鄭錫','唐','御定全唐诗','yuding','','[]','霞鞍金口騮，豹袖紫貂裘。家住叢台下，門前漳水流。',48,'御定全唐詩/json/024.json','["霞鞍金口騮，豹袖紫貂裘。家住叢台下，門前漳水流。", "喚人呈楚舞，借客試吳鉤。見說秦兵至，甘心赴國仇。"]'),
('yuding-0','雜曲歌辭：輕薄篇','李益','唐','御定全唐诗','yuding','','[]','豪不必馳千騎，雄不在垂雙鞬。天生俊氣自相逐，',70,'御定全唐詩/json/025.json','["豪不必馳千騎，雄不在垂雙鞬。天生俊氣自相逐，", "忽聞燕雁一聲去，回鞭挾彈平陵園。歸來青樓曲未半，", "安知我有不平色，白日欲顧紅塵昏。死生容易如反掌，"]'),
('yuding-1','雜曲歌辭：輕薄篇二首','貫休','唐','御定全唐诗','yuding','','[]','繡林錦野，春態相壓。誰家少年，馬蹄蹋蹋。',89,'御定全唐詩/json/025.json','["繡林錦野，春態相壓。誰家少年，馬蹄蹋蹋。", "鬥雞走狗夜不歸，一擲賭卻如花妾。惟雲不顛不狂，", "木落蕭蕭，蛩鳴唧唧。不覺朱蔫臉紅，霜劫鬢漆。", "世途多事，泣向秋日。方吟少壯不努力，老大徒傷悲，"]'),
('yuding-2','雜曲歌辭：輕薄行','齊己','唐','御定全唐诗','yuding','','[]','玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。五陵春暖芳草齊，',40,'御定全唐詩/json/025.json','["玉鞭金鐙驊騮蹄，橫眉吐氣如虹霓。五陵春暖芳草齊，", "伯陽道德何涕唾，仲尼禮樂徒卑棲。"]'),
('yuding-3','雜曲歌辭：灞上輕薄行','孟郊','唐','御定全唐诗','yuding','','[]','長安無緩步，況值天景暮。相逢灞滻間，親戚不相顧。',60,'御定全唐詩/json/025.json','["長安無緩步，況值天景暮。相逢灞滻間，親戚不相顧。", "自歎方拙身，忽隨輕薄倫。常恐失所避，化為車轍塵。", "此中生白髮，疾走亦未歇。"]'),
('yuding-4','雜曲歌辭：遊俠篇','崔顥','唐','御定全唐诗','yuding','','[]','少年負膽氣，好勇複知機。仗劍出門去，孤城逢合圍。',96,'御定全唐詩/json/025.json','["少年負膽氣，好勇複知機。仗劍出門去，孤城逢合圍。", "殺人遼水上，走馬漁陽歸。錯落金鎖甲，蒙茸貂鼠衣。", "還家行且獵，弓矢速如飛。地迥鷹犬疾，草深狐兔肥。", "腰間懸兩綬，轉眄生光輝。顧謂今日戰，何如隨建威。"]'),
('yuding-5','雜曲歌辭：遊俠行','孟郊','唐','御定全唐诗','yuding','','[]','壯士性剛決，火中見石裂。殺人不回頭，輕生如暫別。',48,'御定全唐詩/json/025.json','["壯士性剛決，火中見石裂。殺人不回頭，輕生如暫別。", "豈知眼有淚，肯白頭上發。平生無恩酬，劍閑一百月。"]'),
('yuding-6','雜曲歌辭：俠客行','李白','唐','御定全唐诗','yuding','','[]','趙客縵胡纓，吳鉤霜雪明。銀鞍照白馬，颯遝如流星。',144,'御定全唐詩/json/025.json','["趙客縵胡纓，吳鉤霜雪明。銀鞍照白馬，颯遝如流星。", "十步殺一人，千里不留行。事了拂衣去，深藏身與名。", "閑過信陵飲，脫劍膝前橫。將炙啖朱亥，持觴勸侯嬴。", "三杯吐然諾，五嶽倒為輕。眼花耳熱後，意氣素霓生。", "救趙揮金槌，邯鄲先震驚。千秋二壯士，烜赫大樑城。", "縱死俠骨香，不慚世上英。誰能書閣下，白首太玄經。"]'),
('yuding-7','雜曲歌辭：俠客行','元稹','唐','御定全唐诗','yuding','','[]','俠客不怕死，怕在事不成。事成不肯藏姓名，',44,'御定全唐詩/json/025.json','["俠客不怕死，怕在事不成。事成不肯藏姓名，", "此客此心師海鯨，海鯨露背橫滄溟。海濱分作兩處生，"]'),
('yuding-8','雜曲歌辭：俠客行','溫庭筠','唐','御定全唐诗','yuding','','[]','欲出鴻都門，陰雲蔽城闕。寶劍黯如水，微紅濕餘血。',36,'御定全唐詩/json/025.json','["欲出鴻都門，陰雲蔽城闕。寶劍黯如水，微紅濕餘血。", "白馬夜頻嘶，三更霸陵雪。"]'),
('yuding-9','雜曲歌辭：行行遊且獵篇','李白','唐','御定全唐诗','yuding','','[]','邊城兒，生年不讀一字書，但知遊獵誇輕趫。',68,'御定全唐詩/json/025.json','["邊城兒，生年不讀一字書，但知遊獵誇輕趫。", "胡馬秋肥宜白草，騎來躡影何矜驕。金鞭拂雲揮鳴鞘，", "海邊觀者皆辟易，猛氣英風振沙磧。儒生不及遊俠人，"]'),
('yuding-10','雜曲歌辭：遊子吟','孟郊','唐','御定全唐诗','yuding','','[]','慈母手中線，遊子身上衣。臨行密密縫，意恐遲遲歸。',36,'御定全唐詩/json/025.json','["慈母手中線，遊子身上衣。臨行密密縫，意恐遲遲歸。", "誰言寸草心，報得三春暉。"]'),
('yuding-11','雜曲歌辭：遊子吟','顧況','唐','御定全唐诗','yuding','','[]','故櫪思疲馬，故巢思迷禽。浮雲蔽我鄉，躑躅遊子吟。',396,'御定全唐詩/json/025.json','["故櫪思疲馬，故巢思迷禽。浮雲蔽我鄉，躑躅遊子吟。", "遊子悲久滯，浮雲郁東岑。客堂無絲桐，落葉如秋霖。", "艱哉遠遊子，所以悲滯淫。一為浮雲詞，憤塞誰能禁。", "馳暉百年內，惟願展所欽。胡為不歸歟，坐使年病侵。", "未老霜繞鬢，非狂火燒心。太行何艱哉，北斗不可斟。", "夜晴星河出，耿耿辰與參。佳人夐青天，尺素重于金。", "泬寥群動異，眇默諸境森。苔衣上閑階，蜻蛚催寒砧。", "立身計幾誤，道險無容針。三年不還家，萬里遺錦衾。", "夢魂無重阻，離憂因古今。胡為不歸歟，孤負丘中琴。", "腰下是何物，牽纏曠登尋。朝與名山期，夕宿楚水陰。", "楚水殊演漾，名山杳嶇嶔。客從洞庭來，婉孌瀟湘深。", "橘柚在南國，鴻雁遺秋音。下有碧草洲，上有青橘林。", "引燭窺洞穴，淩波睥天琛。蒲荷影參差，鳧鶴雛淋涔。", "浩歌惜芳杜，散發輕華簪。胡為不歸歟，淚下沾衣襟。", "鳶飛戾霄漢，螻蟻制鱔鱘。赫赫大聖朝，日月光照臨。", "聖主雖啟迪，奇人分堙沉。層城發雲韶，玉府鏘球琳。", "鹿鳴志豐草，況複虞人箴。"]'),
('yuding-12','雜曲歌辭：遊子吟','李益','唐','御定全唐诗','yuding','','[]','女羞夫婿蕩，客恥主人賤。遭遇同眾流，低回愧相見。',72,'御定全唐詩/json/025.json','["女羞夫婿蕩，客恥主人賤。遭遇同眾流，低回愧相見。", "君非青銅鏡，何事空照面。莫以衣上塵，不謂心如練。", "人生當榮盛，待士勿言倦。君看白日馳，何異弦上箭。"]'),
('yuding-13','雜曲歌辭：壯士吟','賈島','唐','御定全唐诗','yuding','','[]','壯士不曾悲，悲即無回期。如何易水上，未歌先淚垂。',24,'御定全唐詩/json/025.json','["壯士不曾悲，悲即無回期。如何易水上，未歌先淚垂。"]'),
('yuding-14','雜曲歌辭：壯士行','劉禹錫','唐','御定全唐诗','yuding','','[]','陰風振寒郊，猛虎正咆哮。徐行出燒地，連吼入黃茆。',96,'御定全唐詩/json/025.json','["陰風振寒郊，猛虎正咆哮。徐行出燒地，連吼入黃茆。", "壯士走馬去，鐙前彎玉弰。叱之使人立，一發如鈹交。", "悍睛忽星墜，飛血濺林梢。彪炳為我席，膻腥充我庖。", "裏中欣害除，賀酒紛號呶。明日長橋上，傾城看斬蛟。"]'),
('yuding-15','雜曲歌辭：壯士行','鮑溶','唐','御定全唐诗','yuding','','[]','西方太白高，壯士羞病死。心知報恩處，對酒歌易水。',60,'御定全唐詩/json/025.json','["西方太白高，壯士羞病死。心知報恩處，對酒歌易水。", "砂鴻嗥天末，橫劍別妻子。蘇武執節歸，班超束書起。", "山河不足重，重在遇知己。"]'),
('yuding-16','雜曲歌辭：壯士行','施肩吾','唐','御定全唐诗','yuding','','[]','一鬥之膽撐臟腑，如磥之筋礙臂骨。有時誤入千人叢，',40,'御定全唐詩/json/025.json','["一鬥之膽撐臟腑，如磥之筋礙臂骨。有時誤入千人叢，", "凍梟殘蠆我不取，汙我匣裏青蛇鱗。"]'),
('yuding-17','雜曲歌辭：浩歌','李賀','唐','御定全唐诗','yuding','','[]','南風吹山作平地，帝遣天吳移海水。王母桃花千遍紅，',72,'御定全唐詩/json/025.json','["南風吹山作平地，帝遣天吳移海水。王母桃花千遍紅，", "箏人勸我金屈卮，神血未凝身問誰。不須浪飲丁督護，", "漏催水咽玉蟾蜍，衛娘發薄不勝梳。看見秋眉換深綠，"]'),
('yuding-18','雜曲歌辭：浩歌行','白居易','唐','御定全唐诗','yuding','','[]','天長地久無終畢，昨夜今朝又明日。鬢髮蒼浪牙齒疏，',96,'御定全唐詩/json/025.json','["天長地久無終畢，昨夜今朝又明日。鬢髮蒼浪牙齒疏，", "既無長繩系白日，又無大藥駐朱顏。朱顏日漸不如故，", "去複去兮如長河，東流赴海無回波。賢愚貴賤同歸盡，", "顏回短命伯夷餓，我今所得亦已多。功名富貴須待命，"]'),
('yuding-19','雜曲歌辭：歸去來引','張熾','唐','御定全唐诗','yuding','','[]','歸去來，歸期不可違。相見故明月，浮雲共我歸。',22,'御定全唐詩/json/025.json','["歸去來，歸期不可違。相見故明月，浮雲共我歸。"]'),
('yuding-20','雜曲歌辭：麗人曲','崔國輔','唐','御定全唐诗','yuding','','[]','紅顏稱絕代，欲並真無侶。獨有鏡中人，由來自相許。',24,'御定全唐詩/json/025.json','["紅顏稱絕代，欲並真無侶。獨有鏡中人，由來自相許。"]'),
('yuding-21','雜曲歌辭：麗人行','杜甫','唐','御定全唐诗','yuding','','[]','三月三日天氣新，長安水邊多麗人。態濃意遠淑且真，',109,'御定全唐詩/json/025.json','["三月三日天氣新，長安水邊多麗人。態濃意遠淑且真，", "頭上何所有，翠微zc葉垂鬢唇。背後何所見，", "紫駝之峰出翠釜，水晶之盤行素鱗。犀箸厭飫久未下，", "簫鼓哀吟感鬼神，賓從雜遝實要津。後來鞍馬何逡巡，", "炙手可熱勢絕倫，慎莫近前丞相嗔。"]'),
('yuding-22','雜曲歌辭：東飛伯勞歌','張柬之','唐','御定全唐诗','yuding','','[]','青田白鶴丹山鳳，婺女姮娥兩相送。誰家絕世綺帳前，',48,'御定全唐詩/json/025.json','["青田白鶴丹山鳳，婺女姮娥兩相送。誰家絕世綺帳前，", "絕世三五愛紅妝，冶袖長裾蘭麝香。春去花枝俄易改，"]'),
('yuding-23','雜曲歌辭：東飛伯勞歌','李嶠','唐','御定全唐诗','yuding','','[]','傳書青鳥迎簫鳳，巫嶺荊台數通夢。誰家窈窕住園樓，',48,'御定全唐詩/json/025.json','["傳書青鳥迎簫鳳，巫嶺荊台數通夢。誰家窈窕住園樓，", "佳人二八盛舞歌，羞將百萬呈雙娥。庭前芳樹朝夕改，"]'),
('yuding-24','雜曲歌辭：東飛伯勞歌','李暇','唐','御定全唐诗','yuding','','[]','秦王龍劍燕後琴，珊瑚寶匣鏤雙心。誰家女兒抱香枕，',48,'御定全唐詩/json/025.json','["秦王龍劍燕後琴，珊瑚寶匣鏤雙心。誰家女兒抱香枕，", "青綺幃中坐相憶，紅羅鏡裏見愁色。簷花照月鶯對棲，"]'),
('yuding-25','雜曲歌辭：鳴雁行','李白','唐','御定全唐诗','yuding','','[]','胡雁鳴，辭燕山，昨發委羽朝度關。一一銜蘆枝，',22,'御定全唐詩/json/025.json','["胡雁鳴，辭燕山，昨發委羽朝度關。一一銜蘆枝，"]'),
('yuding-26','雜曲歌辭：鳴雁行','韓愈','唐','御定全唐诗','yuding','','[]','嗷嗷鳴雁鳴且飛，窮秋南去春北歸。去寒就暖識所處，',48,'御定全唐詩/json/025.json','["嗷嗷鳴雁鳴且飛，窮秋南去春北歸。去寒就暖識所處，", "徘徊反顧群侶違，哀鳴欲下洲渚非。江南水闊朝雲多，"]'),
('yuding-27','雜曲歌辭：鳴雁行','鮑溶','唐','御定全唐诗','yuding','','[]','七月朔方雁心苦，聯影翻空落南土。八月江南陰複晴，',64,'御定全唐詩/json/025.json','["七月朔方雁心苦，聯影翻空落南土。八月江南陰複晴，", "楚童夜宿煙波側，沙上布羅連草色。月暗風悲欲下天，", "江南羽族本不少，寧得網羅此客鳥。"]'),
('yuding-28','雜曲歌辭：鳴雁行','陸龜蒙','唐','御定全唐诗','yuding','','[]','朔風動地來，吹起沙上聲。閨中有邊思，玉箸此時橫。',36,'御定全唐詩/json/025.json','["朔風動地來，吹起沙上聲。閨中有邊思，玉箸此時橫。", "莫怕兒女恨，主人烹不鳴。"]'),
('yuding-29','雜曲歌辭：空城雀','李白','唐','御定全唐诗','yuding','','[]','嗷嗷空城雀，身計何戚促。本與鷦鷯群，不隨鳳凰族。',72,'御定全唐詩/json/025.json','["嗷嗷空城雀，身計何戚促。本與鷦鷯群，不隨鳳凰族。", "提攜四黃口，飲乳未嘗足。食君糠秕餘，常恐烏鳶逐。", "恥涉太行險，羞營覆車粟。天命有定端，守分絕所欲。"]'),
('yuding-30','雜曲歌辭：空城雀','王建','唐','御定全唐诗','yuding','','[]','空城雀，何不飛來人家住，空城無人種禾黍。',68,'御定全唐詩/json/025.json','["空城雀，何不飛來人家住，空城無人種禾黍。", "土間生子草間長，滿地蓬蒿幸無主。近村雖有高樹枝，", "但能不出空城裏，秋時百草皆有子。黃口黃口莫啾啾，"]'),
('yuding-31','雜曲歌辭：空城雀','聶夷中','唐','御定全唐诗','yuding','','[]','一雀入官倉，所食能損幾。所慮往損頻，官倉乃害爾。',48,'御定全唐詩/json/025.json','["一雀入官倉，所食能損幾。所慮往損頻，官倉乃害爾。", "魚網不在天，鳥網不在水。飲啄要自然，何必空城裏。"]'),
('yuding-32','雜曲歌辭：空城雀','劉駕','唐','御定全唐诗','yuding','','[]','饑啄空城土，莫近太倉粟。一粒未充腸，卻入公子腹。',48,'御定全唐詩/json/025.json','["饑啄空城土，莫近太倉粟。一粒未充腸，卻入公子腹。", "且吊城上骨，幾曾害爾族。不聞莊辛語，今日寒蕪綠。"]'),
('yuding-33','雜曲歌辭：車遙遙','孟郊','唐','御定全唐诗','yuding','','[]','路喜到江盡，江上又通舟。舟車兩無阻，何處不得遊。',96,'御定全唐詩/json/025.json','["路喜到江盡，江上又通舟。舟車兩無阻，何處不得遊。", "丈夫四方志，女子安可留。郎自別日言，無令生遠愁。", "旅雁忽叫月，斷猿寒啼秋。此夕夢君夢，君在百城樓。", "寄淚無因波，寄恨無因輈。願為馭者手，與郎回馬頭。"]'),
('yuding-34','雜曲歌辭：車遙遙','張籍','唐','御定全唐诗','yuding','','[]','征人遙遙出古城，雙輪齊動駟馬鳴。山川無處無歸路，',64,'御定全唐詩/json/025.json','["征人遙遙出古城，雙輪齊動駟馬鳴。山川無處無歸路，", "驚麏遊兔在我傍，獨唱鄉歌對僮僕。君家大宅鳳城隅，", "門前舊轍久已平，無由複得君消息。"]'),
('yuding-35','雜曲歌辭：車遙遙','張祜','唐','御定全唐诗','yuding','','[]','東方曨曨車軋軋，地色不分新去轍。閨門半掩床半空，',48,'御定全唐詩/json/025.json','["東方曨曨車軋軋，地色不分新去轍。閨門半掩床半空，", "碧川迢迢山宛宛，馬蹄在耳輪在眼。桑間女兒情不淺，"]'),
('yuding-36','雜曲歌辭：車遙遙','胡曾','唐','御定全唐诗','yuding','','[]','自從車馬出門朝，便入空房守寂寥。玉枕夜殘魚信絕，',40,'御定全唐詩/json/025.json','["自從車馬出門朝，便入空房守寂寥。玉枕夜殘魚信絕，", "芳草又衰還不至，碧天霜冷轉無憀。"]'),
('yuding-37','雜曲歌辭：自君之出矣','辛弘智','唐','御定全唐诗','yuding','','[]','自君之出矣，梁塵靜不飛。思君如滿月，夜夜減容暉。',24,'御定全唐詩/json/025.json','["自君之出矣，梁塵靜不飛。思君如滿月，夜夜減容暉。"]'),
('yuding-38','雜曲歌辭：自君之出矣','李康成','唐','御定全唐诗','yuding','','[]','自君之出矣，弦吹絕無聲。思君如百草，撩亂逐春生。',24,'御定全唐詩/json/025.json','["自君之出矣，弦吹絕無聲。思君如百草，撩亂逐春生。"]'),
('yuding-39','雜曲歌辭：自君之出矣','盧仝','唐','御定全唐诗','yuding','','[]','自君之出矣，壁上蜘蛛織。近取見妾心，夜夜無休息。',96,'御定全唐詩/json/025.json','["自君之出矣，壁上蜘蛛織。近取見妾心，夜夜無休息。", "妾有雙玉環，寄君表相憶。環是妾之心，玉是君之德。", "馳情增悴容，蓄思損精力。玉簟寒淒淒，延想心惻惻。", "風含霜月明，水泛碧天色。此水有盡時，此情無終極。"]'),
('yuding-40','雜曲歌辭：自君之出矣','雍裕之','唐','御定全唐诗','yuding','','[]','自君之出矣，寶鏡為誰明。思君如隴水，長聞嗚咽聲。',24,'御定全唐詩/json/025.json','["自君之出矣，寶鏡為誰明。思君如隴水，長聞嗚咽聲。"]'),
('yuding-41','雜曲歌辭：自君之出矣','張祜','唐','御定全唐诗','yuding','','[]','自君之出矣，萬物看成古。千尋葶藶枝，爭奈長長苦。',24,'御定全唐詩/json/025.json','["自君之出矣，萬物看成古。千尋葶藶枝，爭奈長長苦。"]'),
('yuding-42','雜曲歌辭：長相思','郎大家宋氏','唐','御定全唐诗','yuding','','[]','長相思，久離別。關山阻，風煙絕。',40,'御定全唐詩/json/025.json','["長相思，久離別。關山阻，風煙絕。", "臺上鏡文銷，袖中書字滅。不見君形影，何曾有歡悅。"]'),
('yuding-43','雜曲歌辭：長相思','蘇頲','唐','御定全唐诗','yuding','','[]','君不見天津橋下東流水，東望龍門北朝市。',43,'御定全唐詩/json/025.json','["君不見天津橋下東流水，東望龍門北朝市。", "楊柳青青宛地垂，桃紅李白花參差。花參差，柳堪結，"]'),
('yuding-44','雜曲歌辭：長相思三首','李白','唐','御定全唐诗','yuding','','[]','長相思，在長安。絡緯秋啼金井欄，微霜淒淒簟色寒。',166,'御定全唐詩/json/025.json','["長相思，在長安。絡緯秋啼金井欄，微霜淒淒簟色寒。", "孤燈不明思欲絕，卷帷望月空長歎，美人如花隔雲端。", "上有青冥之長天，下有綠水之波瀾。天長路遠魂飛苦，", "日色已盡花含煙，月明欲素愁不眠。趙瑟初停鳳凰柱，", "憶君迢迢隔青天，昔日橫波目，今成流淚泉。", "不信妾腸斷，歸來看取明鏡前。", "美人在時花滿堂，美人去後花餘床。床中繡被卷不寢，", "相思黃葉落，白露點青苔。"]'),
('yuding-45','雜曲歌辭：長相思','張繼','唐','御定全唐诗','yuding','','[]','遼陽望河縣，白首無由見。海上珊瑚枝，年年寄春燕。',24,'御定全唐詩/json/025.json','["遼陽望河縣，白首無由見。海上珊瑚枝，年年寄春燕。"]'),
('yuding-46','雜曲歌辭：長相思二首','令狐楚','唐','御定全唐诗','yuding','','[]','君行登隴上，妾夢在閨中。玉箸千行落，銀床一半空。',48,'御定全唐詩/json/025.json','["君行登隴上，妾夢在閨中。玉箸千行落，銀床一半空。", "綺席春眠覺，紗窗曉望迷。朦朧殘夢裏，猶自在遼西。"]'),
('yuding-47','雜曲歌辭：長相思','白居易','唐','御定全唐诗','yuding','','[]','九月西風興，月冷霜華凝。思君秋夜長，一夜魂九升。',132,'御定全唐詩/json/025.json','["九月西風興，月冷霜華凝。思君秋夜長，一夜魂九升。", "二月東風來，草坼花心開。思君春日遲，一日腸九回。", "妾住洛橋北，君住洛橋南。十五即相識，今年二十三。", "有如女蘿草，生在松之側。蔓短枝苦高，縈回上不得。", "人言人有願，願至天必成。願作遠方獸，步步比肩行。", "願作深山木，枝枝連理生。"]'),
('yuding-48','雜曲歌辭：千里思','李白','唐','御定全唐诗','yuding','','[]','李陵沒胡沙，蘇武還漢家。迢迢五原關，朔雪亂邊花。',48,'御定全唐詩/json/025.json','["李陵沒胡沙，蘇武還漢家。迢迢五原關，朔雪亂邊花。", "一去隔絕域，思歸但長嗟。鴻雁向西北，飛書報天涯。"]'),
('yuding-49','雜曲歌辭：千里思','李端','唐','御定全唐诗','yuding','','[]','涼州風月美，遙望居延路。泛泛下天雲，青青緣塞樹。',48,'御定全唐詩/json/025.json','["涼州風月美，遙望居延路。泛泛下天雲，青青緣塞樹。", "燕山蘇武上，海島田橫住。更是草生時，行人出門去。"]'),
('yuding-50','雜曲歌辭：行路難','盧照鄰','唐','御定全唐诗','yuding','','[]','君不見長安城北渭橋邊，枯木橫槎臥古田。',179,'御定全唐詩/json/025.json','["君不見長安城北渭橋邊，枯木橫槎臥古田。", "昔日含紅複含紫，常時留霧亦留煙。春景春風花似雪，", "倡家寶襪蛟龍帔，公子銀鞍千萬騎。黃鶯一向花嬌春，", "珊瑚葉上鴛鴦鳥，鳳凰巢裏雛鵷兒。巢傾枝折鳳歸去，", "人生貴賤無終始，倏忽須臾難久恃。誰家能駐西山日，", "自昔公卿二千石，咸擬榮華一萬年。不見朱唇將白貌，", "寄言坐客神仙署，一生一死交情處。蒼龍闕下君不來，", "但願堯年一百萬，長作巢由也不辭。"]'),
('yuding-51','雜曲歌辭：行路難','張紘','唐','御定全唐诗','yuding','','[]','君不見溫家玉鏡臺，提攜抱握九重來。',90,'御定全唐詩/json/025.json','["君不見溫家玉鏡臺，提攜抱握九重來。", "君不見相如綠綺琴，一撫一拍鳳凰音。人生意氣須及早，", "朱樓銀閣正平生，碧草青苔坐蕪漫。當春對酒不須疑，", "秋露萎草鴻始歸，此時衰暮與君違。人生翻覆何常足，"]'),
('yuding-52','雜曲歌辭：行路難五首','賀蘭進明','唐','御定全唐诗','yuding','','[]','君不見岩下井，百尺不及泉。君不見山上蒿，',192,'御定全唐詩/json/025.json','["君不見岩下井，百尺不及泉。君不見山上蒿，", "但願親友長含笑，相逢莫吝杖頭錢。寒夜邀歡須秉燭，", "君不見門前柳，榮曜暫時蕭索久。君不見陌上花，", "盛年夫婿長別離，歲暮相逢色凋換。", "君不見荒樹枝，春花落盡蜂不窺。君不見梁上泥，", "獨宿自然堪下淚，況複時聞烏夜啼。", "君不見雲間月，暫盈還複缺。君不見林下風，", "自歎青青陵上柏，歲寒能與幾人同。", "君不見東流水，一去無窮已。君不見西郊雲，", "人生結交在終始，莫為升沉中路分。"]'),
('yuding-53','雜曲歌辭：行路難','崔顥','唐','御定全唐诗','yuding','','[]','君不見建章宮中金明枝，萬萬長條拂地垂。',91,'御定全唐詩/json/025.json','["君不見建章宮中金明枝，萬萬長條拂地垂。", "二月三月花如霰，九重幽深君不見。豔彩朝含四寶宮，", "看去看來心不忘，攀折將安鏡臺上。雙雙素手剪不成，", "長信麗人見花泣，憶此珍樹何嗟及。我昔初在昭陽時，"]'),
('yuding-54','雜曲歌辭：行路難三首','李白','唐','御定全唐诗','yuding','','[]','金尊清酒鬥十千，玉盤珍羞直萬錢。停杯投箸不能食，',234,'御定全唐詩/json/025.json','["金尊清酒鬥十千，玉盤珍羞直萬錢。停杯投箸不能食，", "閑來垂釣坐溪上，忽複乘舟夢日邊。行路難，行路難，", "大道如青天，我獨不得出。羞逐長安社中兒，", "淮陰市井笑韓信，漢朝公卿忌賈生。", "君不見昔時燕家重郭隗，擁篲折腰無嫌猜。", "劇辛樂毅感恩分，輸肝剖膽效英才。昭王白骨縈蔓草，", "有耳莫洗潁川水，有口莫食首陽蕨。含光混世貴無名。", "何用孤高比雲月。吾觀自古賢達人，功成不退皆殞身。", "子胥既棄吳江上，屈原終投湘水濱。陸機才多豈自保，", "君不見吳中張翰稱達士，秋風忽憶江東行。", "且樂生前一杯酒，何須身後千載名。"]'),
('yuding-55','雜曲歌辭：行路難三首','顧況','唐','御定全唐诗','yuding','','[]','君不見古來燒水銀，變作北邙山上塵。藕絲掛身在虛空，',179,'御定全唐詩/json/025.json','["君不見古來燒水銀，變作北邙山上塵。藕絲掛身在虛空，", "行路難，行路難，生死皆由天。秦皇漢武遭下脫，", "君不見擔雪塞井徒用力，炊砂作飯豈堪吃。", "一生肝膽向人盡，相識不如不相識。冬青樹上掛淩霄，", "行路難，行路難，何處是平道。中心無事當富貴，", "君不見少年頭上如雲發，少壯如雲老如雪。", "豈知灌頂有醍醐，能使清涼頭不熱。呂梁之水掛飛流，", "行路難，行路難，昔少年，今已老。前朝竹帛事皆空，"]'),
('yuding-56','雜曲歌辭：行路難','李頎','唐','御定全唐诗','yuding','','[]','漢家名臣楊德祖，四代五公享茅土。父兄子弟綰銀黃，',88,'御定全唐詩/json/025.json','["漢家名臣楊德祖，四代五公享茅土。父兄子弟綰銀黃，", "賓客填街複滿坐，片言出口生輝光。世人逐勢爭奔走，", "一朝謝病還鄉里，窮巷蒼茫絕知己。秋風落葉閉重門，", "魯連所以蹈滄海，古往今來稱達人。"]'),
('yuding-57','雜曲歌辭：行路難二首','高適','唐','御定全唐诗','yuding','','[]','君不見富家翁，昔時貧賤誰比數。一朝金多結豪貴，',87,'御定全唐詩/json/025.json','["君不見富家翁，昔時貧賤誰比數。一朝金多結豪貴，", "自矜一朝忽如此，卻笑傍人獨悲苦。東鄰少年安所如，", "長安少年不少錢，能騎駿馬鳴金鞭。五侯相逢大道邊，", "安知憔悴讀書者，暮宿虛台私自憐。"]'),
('yuding-58','雜曲歌辭：行路難','張籍','唐','御定全唐诗','yuding','','[]','湘東行人長歎息，十年離家歸未得。弊裘羸馬苦難行，',40,'御定全唐詩/json/025.json','["湘東行人長歎息，十年離家歸未得。弊裘羸馬苦難行，", "龍蟠泥中未有雲，不能生彼升天翼。"]'),
('yuding-59','雜曲歌辭：行路難','聶夷中','唐','御定全唐诗','yuding','','[]','莫言行路難，夷狄如中國。謂言骨肉親，中門如異域。',48,'御定全唐詩/json/025.json','["莫言行路難，夷狄如中國。謂言骨肉親，中門如異域。", "出處全在人，路亦無通塞。門前兩條轍，何處去不得。"]'),
('yuding-60','雜曲歌辭：行路難','韋應物','唐','御定全唐诗','yuding','','[]','荊山之白玉兮，良工雕琢雙環連，月蝕中央鏡心穿。',67,'御定全唐詩/json/025.json','["荊山之白玉兮，良工雕琢雙環連，月蝕中央鏡心穿。", "故人贈妾初相結，恩在環中尋不絕。人情厚薄苦須臾，", "上客勿遽歡，聽妾歌路難。傍人見環環可憐，"]'),
('yuding-61','雜曲歌辭：行路難三首','柳宗元','唐','御定全唐诗','yuding','','[]','君不見夸父追日窺虞淵，跳踉北海超昆侖。',198,'御定全唐詩/json/025.json','["君不見夸父追日窺虞淵，跳踉北海超昆侖。", "披霄決漢出沆漭，瞥裂左右遺星辰。須臾力盡道渴死，", "啾啾飲食滴與粒，生死亦足終天年。睢盱大志少成遂，", "虞衡斤斧羅千山，工命采斫杙與椽。深林土翦十取一，", "遺餘毫末不見保，躝躒澗壑何當存。群材未成質已夭，", "君不見南山棟樑益稀少，愛材養育誰複論。", "飛雪斷道冰成梁，侯家熾炭雕玉房。蟠龍吐耀虎喙張，", "美人四向回明璫，雪山冰穀晞太陽。星躔奔走不得止，", "盛時一去貴反賤，桃笙葵扇安可常。"]'),
('yuding-62','雜曲歌辭：行路難','鮑溶','唐','御定全唐诗','yuding','','[]','玉堂向夕如無人，絲竹儼然宮商死。細人何言入君耳，',48,'御定全唐詩/json/025.json','["玉堂向夕如無人，絲竹儼然宮商死。細人何言入君耳，", "華燈青凝久照夜，彩童窈窕虛垂羅。入宮見妒君不察，"]'),
('yuding-63','雜曲歌辭：行路難五首','貫休','唐','御定全唐诗','yuding','','[]','不會當時作天地，剛有多般愚與智。到頭還用真宰心，',261,'御定全唐詩/json/025.json','["不會當時作天地，剛有多般愚與智。到頭還用真宰心，", "義不義兮仁不仁，擬學長生更容易。負心為爐複為火，", "君不見道傍廢井生古木，本是驕奢貴人屋。", "幾度美人照影來，素綆銀瓶濯纖玉。雲飛雨散今如此，", "休說遺編行者幾，至竟終須合天理。敗他成此亦何功，", "九有茫茫共堯日，浪死虛生亦非一。清淨玄音竟不聞，", "君不見道傍樹有寄生枝，青青鬱鬱同榮衰。", "無情之物尚如此，為人不及還堪悲。父歸墳兮未朝夕，", "我聞忽如負芒刺，不獨為君空歎息。古人尺布猶可縫，", "若如此，不遄死兮更何俟。", "君不見山高海深人不測，古往今來轉青碧。", "淺近輕浮莫與交，池卑只解生荊棘。誰道黃金如糞土，"]'),
('yuding-64','雜曲歌辭：行路難二首','齊己','唐','御定全唐诗','yuding','','[]','行路難，君好看，驚波不在黤黮間，',87,'御定全唐詩/json/025.json','["行路難，君好看，驚波不在黤黮間，", "未似是非唇舌危，暗中潛毀平人骨。君不見楚靈均，", "下浸與高盤，不為行路難。是非真險惡，翻覆作峰巒。", "漆愧同時黑，朱慚巧處丹。令人畏相識，欲畫白雲看。"]'),
('yuding-65','雜曲歌辭：行路難','翁綬','唐','御定全唐诗','yuding','','[]','行路艱難不復歌，故人榮達我蹉跎。雙輪晚上銅梁雪，',40,'御定全唐詩/json/025.json','["行路艱難不復歌，故人榮達我蹉跎。雙輪晚上銅梁雪，", "君看西漢翟丞相，鳳沼朝辭暮雀羅。"]'),
('yuding-66','雜曲歌辭：行路難','薛能','唐','御定全唐诗','yuding','','[]','何處力堪殫，人心險萬端。藏山難測度，暗水自波瀾。',72,'御定全唐詩/json/025.json','["何處力堪殫，人心險萬端。藏山難測度，暗水自波瀾。", "對面如千里，回腸似七盤。已經吳阪困，欲向雁門難。", "南北誠須泣，高深不可幹。無因善行止，車轍得平安。"]'),
('yuding-67','雜曲歌辭：從軍中行路難二首','駱賓王','唐','御定全唐诗','yuding','','[]','君不見封狐雄虺自成群，馮深負固結妖氛。',446,'御定全唐詩/json/025.json','["君不見封狐雄虺自成群，馮深負固結妖氛。", "玉璽分兵征惡少，金壇受律動將軍。將軍擁旄宣廟略，", "閣道岧嶢上戍樓，劍門遙裔俯靈丘。邛關九折無平路，", "杳杳丘陵出，蒼蒼林薄遠。途危紫蓋峰，路澀青泥阪。", "去去指哀牢，行行入不毛。絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。交趾枕南荒，昆彌臨北戶。", "川源饒毒霧，溪穀多淫雨。行潦四時流，崩查千歲古。", "漂梗飛蓬不自安，捫藤引葛度危巒。昔時聞道從軍樂，", "南中南斗映星河，秦川秦塞阻煙波。三春邊地風光少，", "向月彎繁弱，連星轉太阿。重義輕生懷一顧，", "灞城隅，滇池水，天涯望轉積，地際行無已。", "徒覺炎涼節物非，不知關山千萬里。棄置勿重陳，", "絳節朱旗分白羽，丹心白刃酬明主。但令一技君王識，", "無複歸雲憑短翰，望日想長安。", "君不見玉關塵色暗邊亭，銅鞮雜虜寇長城。", "天子按劍征餘勇，將軍受脤事橫行。七德龍韜開玉帳，", "連營去去無窮極，擁旆遙遙過絕國。陣雲朝結晦天山，", "長驅萬里讋祁連，分麾三命武功宣。百發烏號遙碎柳，", "雁門迢遞尺書稀，鴛被相思雙帶緩。行路難。", "誓令氛祲靜皋蘭。但使封侯龍額貴，詎隨中婦鳳樓寒。"]'),
('yuding-68','雜曲歌辭：變行路難','王昌齡','唐','御定全唐诗','yuding','','[]','向晚橫吹悲，風動馬嘶合。前驅引旗節，千重陣雲匝。',48,'御定全唐詩/json/025.json','["向晚橫吹悲，風動馬嘶合。前驅引旗節，千重陣雲匝。", "單于下陰山，砂礫空颯颯。封侯取一戰，豈複念閨閣。"]'),
('yuding-0','雜曲歌辭：古別離','沈佺期','唐','御定全唐诗','yuding','','[]','白水東悠悠，中有西行舟。舟行有返棹，水去無還流。',96,'御定全唐詩/json/026.json','["白水東悠悠，中有西行舟。舟行有返棹，水去無還流。", "奈何生別者，戚戚懷遠遊。遠遊誰當惜，所悲會難收。", "自君間芳屣，青陽四五遒。皓月掩蘭室，光風虛蕙樓。", "相思無明晦，長歎累冬秋。離居分遲暮，駕高何淹留。"]'),
('yuding-1','雜曲歌辭：古別離','孟雲卿','唐','御定全唐诗','yuding','','[]','朝日上高臺，離人怨秋草。但見萬里天，不見萬里道。',108,'御定全唐詩/json/026.json','["朝日上高臺，離人怨秋草。但見萬里天，不見萬里道。", "君行本遙遠，苦樂良難保。宿昔夢同衾，憂心夢顛倒。", "含酸欲誰訴，轉轉傷懷抱。結髮年已遲，征行去何早。", "寒暄有時謝，憔悴難再好。人皆算年壽，死者何曾老。", "少壯無見期，水深風浩浩。"]'),
('yuding-2','雜曲歌辭：古別離','李益','唐','御定全唐诗','yuding','','[]','雙劍欲別風淒然，雌沉水底雄上天。江回漢轉兩不見，',24,'御定全唐詩/json/026.json','["雙劍欲別風淒然，雌沉水底雄上天。江回漢轉兩不見，"]'),
('yuding-3','雜曲歌辭：古別離二首','於濆','唐','御定全唐诗','yuding','','[]','入室少情意，出門多路岐。黃鶴有歸日，蕩子無還時。',132,'御定全唐詩/json/026.json','["入室少情意，出門多路岐。黃鶴有歸日，蕩子無還時。", "人誰無分命，妾身何太奇。君為東南風，妾作西北枝。", "青樓鄰里婦，終年畫長眉。自倚對良匹，笑妾空羅幃。", "郎本東家兒，妾本西家女。對門中道間，終謂無離阻。", "豈知中道間，遣作空閨主。自是愛封侯，非關備胡虜。", "知子去從軍，何處無良人。"]'),
('yuding-4','雜曲歌辭：古別離二首','李端','唐','御定全唐诗','yuding','','[]','水國葉黃時，洞庭霜落夜。行舟聞商估，宿在楓林下。',228,'御定全唐詩/json/026.json','["水國葉黃時，洞庭霜落夜。行舟聞商估，宿在楓林下。", "此地送君還，茫茫似夢間。後期知幾日，前路轉多山。", "巫峽通湘浦，迢迢隔雲雨。天晴見海檣，月落聞津鼓。", "人老自多愁，水深難急流。清宵歌一曲，白首對汀洲。", "與君桂陽別，令君岳陽待。後事忽差池，前期日空在。", "木落雁嗷嗷，洞庭波浪高。遠山雲似蓋，極浦樹如毫。", "朝發能幾裏，暮來風又起。如何兩處愁，皆在孤舟裏。", "昨夜天月明，長川寒且清。菊花開欲盡，薺菜拍來生。", "下江帆勢速，五兩遙相逐。欲問去時人，知投何處宿。", "空令猿嘯時，泣對湘潭竹。"]'),
('yuding-5','雜曲歌辭：古別離','王縉','唐','御定全唐诗','yuding','','[]','下階欲離別，相對映蘭叢。含辭未及吐，淚落蘭叢中。',48,'御定全唐詩/json/026.json','["下階欲離別，相對映蘭叢。含辭未及吐，淚落蘭叢中。", "高堂靜秋日，羅衣飄暮風。誰能待明月，回首見床空。"]'),
('yuding-6','雜曲歌辭：古別離','皎然','唐','御定全唐诗','yuding','','[]','太湖三山口，吳王在時道。寂寞千載心，無人見春草。',85,'御定全唐詩/json/026.json','["太湖三山口，吳王在時道。寂寞千載心，無人見春草。", "誰堪緘怨者，持此傷懷抱。孤舟畏狂風，一點宿煙島。", "望所思兮若何，月蕩漾兮空波。雲離離兮北斷，", "春山胡為兮塞路，使我歸夢兮撩亂。"]'),
('yuding-7','雜曲歌辭：古別離','聶夷中','唐','御定全唐诗','yuding','','[]','欲別牽郎衣，問郎遊何處。不恨歸日遲，莫向臨邛去。',24,'御定全唐詩/json/026.json','["欲別牽郎衣，問郎遊何處。不恨歸日遲，莫向臨邛去。"]'),
('yuding-8','雜曲歌辭：古別離二首','施肩吾','唐','御定全唐诗','yuding','','[]','古人謾歌西飛燕，十年不見狂夫面。三更風作切夢刀，',68,'御定全唐詩/json/026.json','["古人謾歌西飛燕，十年不見狂夫面。三更風作切夢刀，", "老母別愛子，少妻送征郎。血流既四面，乃亦斷二腸。", "不愁寒無衣，不怕饑無糧。惟恐征戰不還鄉，"]'),
('yuding-9','雜曲歌辭：古別離','吳融','唐','御定全唐诗','yuding','','[]','紫燕黃鵠雖別離，一舉千里何難追。猶聞啼風與叫月，',48,'御定全唐詩/json/026.json','["紫燕黃鵠雖別離，一舉千里何難追。猶聞啼風與叫月，", "蟾蜍正向清夜流，蛺蝶須教墮絲罥。莫道斷絲不可續，"]'),
('yuding-10','雜曲歌辭：古離別','王適','唐','御定全唐诗','yuding','','[]','昔歲驚楊柳，高樓悲獨守。今年芳樹枝，孤棲怨別離。',88,'御定全唐詩/json/026.json','["昔歲驚楊柳，高樓悲獨守。今年芳樹枝，孤棲怨別離。", "珠簾晝不卷，羅幔曉長垂。苦調琴先覺，愁容鏡獨知。", "頻來雁度無消息，罷去鴛文何用織。夜還羅帳空有情，", "已能憔悴今如此，更複含情一待君。"]'),
('yuding-11','雜曲歌辭：古離別','常理','唐','御定全唐诗','yuding','','[]','君禦狐白裘，妾居緗綺幬。粟鈿金夾膝，花錯玉搔頭。',72,'御定全唐詩/json/026.json','["君禦狐白裘，妾居緗綺幬。粟鈿金夾膝，花錯玉搔頭。", "離別生庭草，征行斷戍樓。蠨蛸網清曙，菡萏落紅秋。", "小膽空房怯，長眉滿鏡愁。為傳兒女意，不用遠封侯。"]'),
('yuding-12','雜曲歌辭：古離別','姚系','唐','御定全唐诗','yuding','','[]','涼風已嫋嫋，露重木蘭枝。獨上高樓望，行人遠不知。',48,'御定全唐詩/json/026.json','["涼風已嫋嫋，露重木蘭枝。獨上高樓望，行人遠不知。", "輕寒入洞戶，明月滿秋池。燕去鴻方至，年年是別離。"]'),
('yuding-13','雜曲歌辭：古離別','張彪','唐','御定全唐诗','yuding','','[]','離別無遠近，事歡情亦悲。不聞車輪聲，後會將何時。',48,'御定全唐詩/json/026.json','["離別無遠近，事歡情亦悲。不聞車輪聲，後會將何時。", "去日忘寄書，來日乖前期。縱知明當還，一夕千萬思。"]'),
('yuding-14','雜曲歌辭：古離別','趙微明','唐','御定全唐诗','yuding','','[]','違別未幾日，一日如三秋。猶疑望可見，日日上高樓。',48,'御定全唐詩/json/026.json','["違別未幾日，一日如三秋。猶疑望可見，日日上高樓。", "惟見分手處，白蘋滿芳洲。寸心寧死別，不忍生離愁。"]'),
('yuding-15','雜曲歌辭：古離別二首','孟郊','唐','御定全唐诗','yuding','','[]','松山雲繚繞，萍路水分離。雲去有歸日，水分無合時。',144,'御定全唐詩/json/026.json','["松山雲繚繞，萍路水分離。雲去有歸日，水分無合時。", "春芳役雙眼，春色柔四支。楊柳織別愁，千條萬條絲。", "山川古今路，縱橫無斷絕。來往天地間，人皆有離別。", "行衣未束帶，中腸已先結。不用看鏡中，自知生白髮。", "欲陳去留意，聲向言前咽。愁結填心胸，茫茫若為說。", "荒郊煙莽蒼，曠野風淒切。處處得相隨，人那不如月。"]'),
('yuding-16','雜曲歌辭：古離別','顧況','唐','御定全唐诗','yuding','','[]','西江上，風動麻姑嫁時浪。',28,'御定全唐詩/json/026.json','["西江上，風動麻姑嫁時浪。", "西山為水水為塵，不是人間離別人。"]'),
('yuding-17','雜曲歌辭：古離別','貫休','唐','御定全唐诗','yuding','','[]','離恨如旨酒，古今飲皆醉。只恐長江水，儘是兒女淚。',48,'御定全唐詩/json/026.json','["離恨如旨酒，古今飲皆醉。只恐長江水，儘是兒女淚。", "伊餘非此輩，送人空把臂。他日再相逢，清風動天地。"]'),
('yuding-18','雜曲歌辭：古離別','韋莊','唐','御定全唐诗','yuding','','[]','晴煙漠漠柳毿毿，不那離情酒半酣。',32,'御定全唐詩/json/026.json','["晴煙漠漠柳毿毿，不那離情酒半酣。", "更把馬鞭雲外指，斷腸春色在江南。"]'),
('yuding-19','雜曲歌辭：生別離','孟雲卿','唐','御定全唐诗','yuding','','[]','結髮生別離，相思複相保。何知日已久，五變庭中草。',96,'御定全唐詩/json/026.json','["結髮生別離，相思複相保。何知日已久，五變庭中草。", "眇眇天海途，悠悠吳江島。但恐不出門，出門無遠道。", "遠道行既難，家貧衣服單。嚴風吹積雪，晨起鼻何酸。", "人生各有戀，豈不懷所安。分明天上日，生死誓同歡。"]'),
('yuding-20','雜曲歌辭：生別離','白居易','唐','御定全唐诗','yuding','','[]','食檗不易食梅難，檗能苦兮梅能酸。未如生別之為難，',72,'御定全唐詩/json/026.json','["食檗不易食梅難，檗能苦兮梅能酸。未如生別之為難，", "回看骨肉哭一聲，梅酸檗苦甘如蜜。黃河水白黃雲秋，", "生離別，生離別，憂從中來無斷絕。憂積心勞血氣衰，"]'),
('yuding-21','雜曲歌辭：遠別離','李白','唐','御定全唐诗','yuding','','[]','遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。',130,'御定全唐詩/json/026.json','["遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。", "海水直下萬里深，誰人不言此離苦。日慘慘兮雲冥冥，", "皇穹竊恐不照余之忠誠，雷馮馮兮欲吼怒。", "堯舜當之亦禪禹。君失臣兮龍為魚，權歸臣兮鼠變虎。", "或雲堯幽囚，舜野死，九疑聯綿皆相似，", "慟哭兮遠望，見蒼梧之深山。蒼梧山崩湘水絕，"]'),
('yuding-22','雜曲歌辭：遠別離','張籍','唐','御定全唐诗','yuding','','[]','蓮葉團團杏花拆，長江鯉魚鰭鬣赤。念君少年棄親戚，',40,'御定全唐詩/json/026.json','["蓮葉團團杏花拆，長江鯉魚鰭鬣赤。念君少年棄親戚，", "幾時斷得城南陌，勿使居人有行役。"]'),
('yuding-23','雜曲歌辭：遠別離二首','令狐楚','唐','御定全唐诗','yuding','','[]','楊柳黃金穗，梧桐碧玉枝。春來消息斷，早晚是歸時。',48,'御定全唐詩/json/026.json','["楊柳黃金穗，梧桐碧玉枝。春來消息斷，早晚是歸時。", "玳織鴛鴦履，金裝翡翠簪。畏人相問著，不擬到城南。"]'),
('yuding-24','雜曲歌辭：久別離','李白','唐','御定全唐诗','yuding','','[]','別來幾春未還家，玉窗五見櫻桃花。況有錦字書，',42,'御定全唐詩/json/026.json','["別來幾春未還家，玉窗五見櫻桃花。況有錦字書，", "胡為東風為我吹行雲，使西來；待來竟不來，"]'),
('yuding-25','雜曲歌辭：新別離','戴叔倫','唐','御定全唐诗','yuding','','[]','手把杏花枝，未曾經別離。黃昏掩閨後，寂寞自心知。',24,'御定全唐詩/json/026.json','["手把杏花枝，未曾經別離。黃昏掩閨後，寂寞自心知。"]'),
('yuding-26','雜曲歌辭：今別離','崔國輔','唐','御定全唐诗','yuding','','[]','送別未能旋，相望連水口。船行欲映洲，幾度急搖手。',24,'御定全唐詩/json/026.json','["送別未能旋，相望連水口。船行欲映洲，幾度急搖手。"]'),
('yuding-27','雜曲歌辭：暗別離','劉氏瑤','唐','御定全唐诗','yuding','','[]','槐花結子桐葉焦，單飛越鳥啼青霄。翠軒輾雲輕遙遙，',48,'御定全唐詩/json/026.json','["槐花結子桐葉焦，單飛越鳥啼青霄。翠軒輾雲輕遙遙，", "朱弦暗斷不見人，風動花枝月中影。青鸞脈脈西飛去，"]'),
('yuding-28','雜曲歌辭：潛別離','白居易','唐','御定全唐诗','yuding','','[]','不得哭，潛別離。不得語，暗相思。兩心之外無人知。',48,'御定全唐詩/json/026.json','["不得哭，潛別離。不得語，暗相思。兩心之外無人知。", "深籠夜鎖獨棲鳥，利劍春斷連理枝。河水雖濁有清日，"]'),
('yuding-29','雜曲歌辭：別離曲','張籍','唐','御定全唐诗','yuding','','[]','行人結束出門去，馬蹄幾時踏門路。憶昔君初納彩時，',48,'御定全唐詩/json/026.json','["行人結束出門去，馬蹄幾時踏門路。憶昔君初納彩時，", "男兒生身自有役，那得誤我少年時。不如逐君征戰死，"]'),
('yuding-30','雜曲歌辭：別離曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','丈夫非無淚，不灑離別間。仗劍對尊酒，恥為遊子顏。',48,'御定全唐詩/json/026.json','["丈夫非無淚，不灑離別間。仗劍對尊酒，恥為遊子顏。", "蝮蛇一螫手，壯士疾解腕。所思在功名，離別何足歎。"]'),
('yuding-31','雜曲歌辭：西洲曲','溫庭筠','唐','御定全唐诗','yuding','','[]','悠悠複悠悠，昨日下西洲。西洲風色好，遙見武昌樓。',168,'御定全唐詩/json/026.json','["悠悠複悠悠，昨日下西洲。西洲風色好，遙見武昌樓。", "武昌何鬱鬱，儂家定無匹。小婦被流黃，登樓撫瑤瑟。", "朱弦繁複輕，素手直淒清。一彈三四解，掩抑似含情。", "南樓登且望，西江廣複平。艇子搖兩槳，催過石頭城。", "門前烏臼樹，慘澹天將曙。鶤鵊飛複還，郎隨早帆去。", "回頭語同伴，定複負情儂。去帆不安幅，作抵使西風。", "他日相尋索，莫作西洲客。西洲人不歸，春草年年碧。"]'),
('yuding-32','雜曲歌辭：荊州樂','李白','唐','御定全唐诗','yuding','','[]','白帝城邊足風波，瞿塘五月誰敢過。荊州麥熟繭成蛾，',24,'御定全唐詩/json/026.json','["白帝城邊足風波，瞿塘五月誰敢過。荊州麥熟繭成蛾，"]'),
('yuding-33','雜曲歌辭：荊州樂二首','劉禹錫','唐','御定全唐诗','yuding','','[]','渚宮楊柳暗，麥城朝雉飛。可憐踏青伴，乘暖著輕衣。',48,'御定全唐詩/json/026.json','["渚宮楊柳暗，麥城朝雉飛。可憐踏青伴，乘暖著輕衣。", "今日好南風，商旅相催發。沙頭檣竿上，始見春江闊。"]'),
('yuding-34','雜曲歌辭：荊州泊','李端','唐','御定全唐诗','yuding','','[]','南樓西下時，月裏聞來棹。桂水舳艫回，荊州津濟鬧。',48,'御定全唐詩/json/026.json','["南樓西下時，月裏聞來棹。桂水舳艫回，荊州津濟鬧。", "移帷望星漢，引帶思容貌。今夜一江人，惟應妾身覺。"]'),
('yuding-35','雜曲歌辭：紀南歌','劉禹錫','唐','御定全唐诗','yuding','','[]','風煙紀南城，塵土荊門路。天寒獵獸者，走上樊姬墓。',24,'御定全唐詩/json/026.json','["風煙紀南城，塵土荊門路。天寒獵獸者，走上樊姬墓。"]'),
('yuding-36','雜曲歌辭：宜城歌','劉禹錫','唐','御定全唐诗','yuding','','[]','野水繞空城，行塵起孤驛。花台側生樹，石碣陽鐫額。',36,'御定全唐詩/json/026.json','["野水繞空城，行塵起孤驛。花台側生樹，石碣陽鐫額。", "靡靡度行人，溫風吹宿麥。"]'),
('yuding-37','雜曲歌辭：長幹曲四首','崔顥','唐','御定全唐诗','yuding','','[]','君家定何處，妾住在橫塘。停舟暫借問，或恐是同鄉。',96,'御定全唐詩/json/026.json','["君家定何處，妾住在橫塘。停舟暫借問，或恐是同鄉。", "家臨九江水，去來九江側。同是長幹人，生小不相識。", "下渚多風浪，蓮舟漸覺稀。那能不相待，獨自逆潮歸。", "三江潮水急，五湖風浪湧。由來花性輕，莫畏蓮舟重。"]'),
('yuding-38','雜曲歌辭：長幹行二首','李白','唐','御定全唐诗','yuding','','[]','妾發初覆額，折花門前劇。郎騎竹馬來，繞床弄青梅。',348,'御定全唐詩/json/026.json','["妾發初覆額，折花門前劇。郎騎竹馬來，繞床弄青梅。", "同居長幹裏，兩小無嫌猜。十四為君婦，羞顏尚不開。", "低頭向暗壁，千喚不一回。十五始展眉，願同塵與灰。", "常存抱柱信，豈上望夫台。十六君遠行，瞿塘灩預堆。", "五月不可觸，猿鳴天上哀。門前遲行跡，一一生綠苔。", "苔深不能掃，落葉秋風早。八月蝴蝶來，雙飛西園草。", "感此傷妾心，坐愁紅顏老。早晚下三巴，預將書報家。", "相迎不道遠，直至長風沙。", "憶妾深閨裏，煙塵不曾識。嫁與長幹人，沙頭候風色。", "五月南風興，思君在巴陵。八月西風起，想君發揚子。", "去來悲如何，見少別離多。湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。淼淼暗無邊，行人在何處。", "北客真王公，朱衣滿江中。日暮來投宿，數朝不肯東。", "好乘浮雲驄，佳期蘭渚東。鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃李紅。那作商人婦，愁水複愁風。"]'),
('yuding-39','雜曲歌辭：長幹行','張潮','唐','御定全唐诗','yuding','','[]','婿貧如珠玉，婿富如埃塵。貧時不忘舊，富貴多寵新。',144,'御定全唐詩/json/026.json','["婿貧如珠玉，婿富如埃塵。貧時不忘舊，富貴多寵新。", "妾本富家女，與君為偶匹。惠好一何深，中門不曾出。", "妾有繡衣裳，葳蕤金縷光。念君貧且賤，易此從遠方。", "遠方三千里，發去悔不已。日暮情更來，空望去時水。", "孟夏麥始秀，江上多南風。商賈歸欲盡，君今尚巴東。", "巴東有巫山，窈窕神女顏。常恐遊此山，果然不知還。"]'),
('yuding-40','雜曲歌辭：小長幹曲','崔國輔','唐','御定全唐诗','yuding','','[]','月暗送湖風，相尋路不通。菱歌唱不輟，知在此塘中。',24,'御定全唐詩/json/026.json','["月暗送湖風，相尋路不通。菱歌唱不輟，知在此塘中。"]'),
('yuding-41','雜曲歌辭：杞梁妻','貫休','唐','御定全唐诗','yuding','','[]','秦之無道兮四海枯，築長城兮遮北胡。築人築土一萬里，',49,'御定全唐詩/json/026.json','["秦之無道兮四海枯，築長城兮遮北胡。築人築土一萬里，", "一號城崩塞色苦，再號杞梁骨出土。疲魂饑魄相逐歸，"]'),
('yuding-42','雜曲歌辭：盧女曲','崔顥','唐','御定全唐诗','yuding','','[]','二月春來半，宮中日漸長。柳垂金屋暖，花覆玉樓香。',48,'御定全唐詩/json/026.json','["二月春來半，宮中日漸長。柳垂金屋暖，花覆玉樓香。", "拂匣先臨鏡，調笙更炙簧。還將盧女曲，夜夜奉君王。"]'),
('yuding-43','雜曲歌辭：盧姬篇','崔顥','唐','御定全唐诗','yuding','','[]','盧姬小小魏王家，綠鬢紅唇桃李花。魏玉綺樓十二重，',64,'御定全唐詩/json/026.json','["盧姬小小魏王家，綠鬢紅唇桃李花。魏玉綺樓十二重，", "前堂後堂羅袖人，南窗北窗花發春。翠幌珠簾鬥弦管，", "人生今日得驕貴，誰道盧姬身細微。"]'),
('yuding-44','雜曲歌辭：邯鄲才人嫁為廝養卒婦','李白','唐','御定全唐诗','yuding','','[]','妾本叢台女，揚蛾入丹闕。自倚顏如花，寧知有凋歇。',60,'御定全唐詩/json/026.json','["妾本叢台女，揚蛾入丹闕。自倚顏如花，寧知有凋歇。", "一辭玉階下，去若朝雲沒。每憶邯鄲城，深宮夢秋月。", "君王不可見，惆悵至明發。"]'),
('yuding-45','雜曲歌辭：楊白花','柳宗元','唐','御定全唐诗','yuding','','[]','楊白花，風吹度江水。坐令宮樹無顏色，',18,'御定全唐詩/json/026.json','["楊白花，風吹度江水。坐令宮樹無顏色，"]'),
('yuding-46','雜曲歌辭：茱萸女','萬楚','唐','御定全唐诗','yuding','','[]','山陰柳家女，九日采茱萸。複得東鄰伴，雙為陌上姝。',84,'御定全唐詩/json/026.json','["山陰柳家女，九日采茱萸。複得東鄰伴，雙為陌上姝。", "插花向高髻，結子置長裾。作性恒遲緩，非關詫丈夫。", "平明折林樹，日入反城隅。俠客邀羅袖，行人挑短書。", "蛾眉自有主，年少莫踟躕。"]'),
('yuding-47','雜曲歌辭：於闐采花','李白','唐','御定全唐诗','yuding','','[]','於闐采花人，自言花相似。明妃一朝西入胡，',48,'御定全唐詩/json/026.json','["於闐采花人，自言花相似。明妃一朝西入胡，", "丹青能令醜者妍，無鹽翻在深宮裏。", "自古妒蛾眉，胡沙埋皓齒。"]'),
('yuding-48','雜曲歌辭：秦女卷衣','李白','唐','御定全唐诗','yuding','','[]','天子居未央，妾侍卷衣裳。顧無紫宮寵，敢拂黃金床。',60,'御定全唐詩/json/026.json','["天子居未央，妾侍卷衣裳。顧無紫宮寵，敢拂黃金床。", "水至亦不去，熊來尚可當。微身奉日月，飄若螢火光。", "願君采葑菲，無以下體妨。"]'),
('yuding-49','雜曲歌辭：愛妾換馬','張祜','唐','御定全唐诗','yuding','','[]','一面妖桃千里蹄，嬌姿駿骨價應齊。乍牽玉勒辭金棧，',80,'御定全唐詩/json/026.json','["一面妖桃千里蹄，嬌姿駿骨價應齊。乍牽玉勒辭金棧，", "嬋娟躞蹀春風裏，揮手搖鞭楊柳堤。", "綺閣香銷華廄空，忍將行雨換追風。休憐柳葉雙眉翠，", "恩勞未盡情先盡，暗泣嘶風兩意同。"]'),
('yuding-50','雜曲歌辭：枯魚過河泣','李白','唐','御定全唐诗','yuding','','[]','白龍改常服，偶被豫且制。誰使爾為魚，徒勞訴天帝。',60,'御定全唐詩/json/026.json','["白龍改常服，偶被豫且制。誰使爾為魚，徒勞訴天帝。", "作書報鯨鯢，勿恃風濤勢。濤落歸泥沙，翻遭螻蟻噬。", "萬乘慎出入，柏人以為誡。"]'),
('yuding-51','雜曲歌辭：飲酒樂','聶夷中','唐','御定全唐诗','yuding','','[]','日月似有事，一夜行一周。草木猶須老，人生得無愁。',72,'御定全唐詩/json/026.json','["日月似有事，一夜行一周。草木猶須老，人生得無愁。", "一飲解百結，再飲破百憂。白髮欺貧賤，不入醉人頭。", "我願東海水，盡向杯中流。安得阮步兵，同入醉鄉遊。"]'),
('yuding-52','雜曲歌辭：王孫游','崔國輔','唐','御定全唐诗','yuding','','[]','自與王孫別，頻看黃鳥飛。應由春草誤，著處不成歸。',24,'御定全唐詩/json/026.json','["自與王孫別，頻看黃鳥飛。應由春草誤，著處不成歸。"]'),
('yuding-53','雜曲歌辭：發白馬','李白','唐','御定全唐诗','yuding','','[]','將軍發白馬，旌節渡黃河。簫鼓聒川嶽，滄溟湧洪波。',96,'御定全唐詩/json/026.json','["將軍發白馬，旌節渡黃河。簫鼓聒川嶽，滄溟湧洪波。", "武安有振瓦，易水無寒歌。鐵騎若雪山，飲流涸滹沱。", "揚兵獵月窟，轉戰略朝那。倚劍登燕然，邊峰列嵯峨。", "蕭條萬里外，耕作五原多。一掃清大漠，包虎戢金戈。"]'),
('yuding-54','雜曲歌辭：結襪子','李白','唐','御定全唐诗','yuding','','[]','燕南壯士吳門豪，築中置鉛魚隱刀。',32,'御定全唐詩/json/026.json','["燕南壯士吳門豪，築中置鉛魚隱刀。", "感君恩重許君命，泰山一擲輕鴻毛。"]'),
('yuding-55','雜曲歌辭：沐浴子','李白','唐','御定全唐诗','yuding','','[]','沐芳莫彈冠，浴蘭莫振衣。處世忌太潔，志人貴藏輝。',36,'御定全唐詩/json/026.json','["沐芳莫彈冠，浴蘭莫振衣。處世忌太潔，志人貴藏輝。", "滄浪有釣叟，吾與爾同歸。"]'),
('yuding-56','雜曲歌辭：三台二首','韋應物','唐','御定全唐诗','yuding','','[]','一年一年老去，明日後日花開。',56,'御定全唐詩/json/026.json','["一年一年老去，明日後日花開。", "未報長安平定，萬國豈得銜杯。", "冰泮寒塘始綠，雨餘百草皆生。", "朝來門合無事，晚下高齋有情。"]'),
('yuding-57','雜曲歌辭：上皇三台','韋應物','唐','御定全唐诗','yuding','','[]','不寐倦長更，披衣出戶行。月寒秋竹冷，風切夜窗聲。',24,'御定全唐詩/json/026.json','["不寐倦長更，披衣出戶行。月寒秋竹冷，風切夜窗聲。"]'),
('yuding-58','雜曲歌辭：突厥三台','韋應物','唐','御定全唐诗','yuding','','[]','雁門山上雁初飛，馬邑闌中馬正肥。',32,'御定全唐詩/json/026.json','["雁門山上雁初飛，馬邑闌中馬正肥。", "日旰山西逢驛使，殷勤南北送征衣。"]'),
('yuding-59','雜曲歌辭：宮中三台二首','王建','唐','御定全唐诗','yuding','','[]','魚藻池邊射鴨，芙蓉園裏看花。',56,'御定全唐詩/json/026.json','["魚藻池邊射鴨，芙蓉園裏看花。", "日色柘袍相似，不著紅鸞扇遮。", "池北池南草綠，殿前殿后花紅。", "天子千年萬歲，未央明月清風。"]'),
('yuding-60','雜曲歌辭：江南三台四首','王建','唐','御定全唐诗','yuding','','[]','揚州橋邊小婦，長幹市里商人。',112,'御定全唐詩/json/026.json','["揚州橋邊小婦，長幹市里商人。", "三年不得消息，各自拜鬼求神。", "青草湖邊草色，飛猿嶺上猿聲。", "萬里三湘客到，有風有雨人行。", "樹頭花落花開，道上人去人來。", "朝愁暮愁即老，百年幾度三台。", "聞身強健且為，頭白齒落難追。", "准擬百年千歲，能得幾許多時。"]'),
('yuding-61','雜曲歌辭：築城曲','張籍','唐','御定全唐诗','yuding','','[]','築城去，千人萬人齊抱杵。重重土堅試行錐，',44,'御定全唐詩/json/026.json','["築城去，千人萬人齊抱杵。重重土堅試行錐，", "力盡不得拋杵聲，杵聲未定人皆死。家家養男當門戶，"]'),
('yuding-62','雜曲歌辭：築城曲五解','元稹','唐','御定全唐诗','yuding','','[]','年年塞下丁，長作出塞兵。自從冒頓強，官築遮虜城。',120,'御定全唐詩/json/026.json','["年年塞下丁，長作出塞兵。自從冒頓強，官築遮虜城。", "築城須努力，城高遮得賊。但恐賊路多，有城遮不得。", "丁口傳父口，莫問城堅不。平城被虜圍，漢劚城牆走。", "因茲虜請和，虜往騎來多。半疑兼半信，築城猶嵯峨。", "築城安敢煩，願聽丁一言。請築鴻臚寺，兼愁虜出關。"]'),
('yuding-63','雜曲歌辭：築城曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','城上一掊土，手中千萬杵。築城畏不堅，堅城在何處。',48,'御定全唐詩/json/026.json','["城上一掊土，手中千萬杵。築城畏不堅，堅城在何處。", "莫歎築城勞，將軍要卻敵。城高功亦高，爾命何處惜。"]'),
('yuding-64','雜曲歌辭：湖陰曲','溫庭筠','唐','御定全唐诗','yuding','','[]','祖龍黃須珊瑚鞭，鐵驄金面青連錢。虎髯拔劍欲成夢，',72,'御定全唐詩/json/026.json','["祖龍黃須珊瑚鞭，鐵驄金面青連錢。虎髯拔劍欲成夢，", "蒼黃追騎塵外歸，森索妖星陣前死。五陵愁碧春萋萋，", "白虯天子金煌鋩，高臨帝座回龍章。吳波不動楚山晚，"]'),
('yuding-65','雜曲歌辭：無愁果有愁曲','李商隱','唐','御定全唐诗','yuding','','[]','東有青龍西白虎，中含福皇包世度。玉壺渭水笑清潭，',64,'御定全唐詩/json/026.json','["東有青龍西白虎，中含福皇包世度。玉壺渭水笑清潭，", "秋娥點滴不成淚，十二玉樓無故釘。推煙唾月拋千里，", "日暮向風牽短絲，血凝血散今誰是。"]'),
('yuding-66','雜曲歌辭：起夜來','施肩吾','唐','御定全唐诗','yuding','','[]','香銷連理帶，塵覆合歡杯。懶臥相思枕，愁吟起夜來。',24,'御定全唐詩/json/026.json','["香銷連理帶，塵覆合歡杯。懶臥相思枕，愁吟起夜來。"]'),
('yuding-67','雜曲歌辭：起夜半','聶夷中','唐','御定全唐诗','yuding','','[]','念遠心如燒，不覺中夜起。桃花帶露泛，立在月明裏。',24,'御定全唐詩/json/026.json','["念遠心如燒，不覺中夜起。桃花帶露泛，立在月明裏。"]'),
('yuding-68','雜曲歌辭：獨不見','沈佺期','唐','御定全唐诗','yuding','','[]','盧家小婦郁金堂，海燕雙棲玳瑁梁。九月寒砧催下葉，',40,'御定全唐詩/json/026.json','["盧家小婦郁金堂，海燕雙棲玳瑁梁。九月寒砧催下葉，", "誰知含愁獨不見，使妾明月照流黃。"]'),
('yuding-69','雜曲歌辭：獨不見','王訓','唐','御定全唐诗','yuding','','[]','日晚宜春暮，風軟上林朝。對酒近初節，開樓蕩夜嬌。',48,'御定全唐詩/json/026.json','["日晚宜春暮，風軟上林朝。對酒近初節，開樓蕩夜嬌。", "石橋通小澗，竹路上青霄。持底誰見許，長愁成細腰。"]'),
('yuding-70','雜曲歌辭：獨不見','楊巨源','唐','御定全唐诗','yuding','','[]','東風豔陽色，柳綠花如霰。競理同心鬟，爭持合歡扇。',48,'御定全唐詩/json/026.json','["東風豔陽色，柳綠花如霰。競理同心鬟，爭持合歡扇。", "香傳賈娘手，粉離何郎面。最恨捲簾時，含情獨不見。"]'),
('yuding-71','雜曲歌辭：獨不見','李白','唐','御定全唐诗','yuding','','[]','白馬誰家子，黃龍邊塞兒。天山三丈雪，豈是遠行時。',84,'御定全唐詩/json/026.json','["白馬誰家子，黃龍邊塞兒。天山三丈雪，豈是遠行時。", "春蕙忽秋草，莎雞鳴曲池。風催寒棕響，月入霜閨悲。", "憶與君別年，種桃齊蛾眉。桃今百餘尺，花落成枯枝。", "終然獨不見，流淚空自知。"]'),
('yuding-72','雜曲歌辭：獨不見','戴叔倫','唐','御定全唐诗','yuding','','[]','前宮路非遠，舊苑春將遍。玉戶看早梅，雕梁數歸燕。',60,'御定全唐詩/json/026.json','["前宮路非遠，舊苑春將遍。玉戶看早梅，雕梁數歸燕。", "身輕逐舞袖，香暖傳歌扇。自和秋風詞，長侍昭陽殿。", "誰信後庭人，年年獨不見。"]'),
('yuding-73','雜曲歌辭：獨不見','胡曾','唐','御定全唐诗','yuding','','[]','玉關一自有氛埃，年少從軍竟未回。門外塵凝張樂榭，',40,'御定全唐詩/json/026.json','["玉關一自有氛埃，年少從軍竟未回。門外塵凝張樂榭，", "萬里寂寥音信絕，寸心爭忍不成灰。"]'),
('yuding-74','雜曲歌辭：攜手曲','田娥','唐','御定全唐诗','yuding','','[]','攜手共惜芳菲節，鶯啼錦花滿城闕。行樂逶迤念容色，',24,'御定全唐詩/json/026.json','["攜手共惜芳菲節，鶯啼錦花滿城闕。行樂逶迤念容色，"]'),
('yuding-75','雜曲歌辭：大垂手','聶夷中','唐','御定全唐诗','yuding','','[]','金刀翦輕雲，盤用黃金縷。裝束趙飛燕，教來掌上舞。',36,'御定全唐詩/json/026.json','["金刀翦輕雲，盤用黃金縷。裝束趙飛燕，教來掌上舞。", "舞罷飛燕死，片片隨風去。"]'),
('yuding-76','雜曲歌辭：夜夜曲','田娥','唐','御定全唐诗','yuding','','[]','愁人夜獨傷，滅燭臥蘭房。只恐多情月，旋來照妾床。',24,'御定全唐詩/json/026.json','["愁人夜獨傷，滅燭臥蘭房。只恐多情月，旋來照妾床。"]'),
('yuding-77','雜曲歌辭：夜夜曲','王偃','唐','御定全唐诗','yuding','','[]','北斗星移銀漢低，班姬愁思鳳城西。',32,'御定全唐詩/json/026.json','["北斗星移銀漢低，班姬愁思鳳城西。", "青槐陌上人行絕，明月樓前烏夜啼。"]'),
('yuding-78','雜曲歌辭：夜夜曲','貫休','唐','御定全唐诗','yuding','','[]','蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。',32,'御定全唐詩/json/026.json','["蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。", "孤燈耿耿征婦勞，更深撲落金錯刀。"]'),
('yuding-79','雜曲歌辭：秋夜長','王勃','唐','御定全唐诗','yuding','','[]','秋夜長，殊未央，月明白露澄清光，層城綺閣遙相望。',82,'御定全唐詩/json/026.json','["秋夜長，殊未央，月明白露澄清光，層城綺閣遙相望。", "遙相望，川無梁，北風受節雁南翔，崇蘭委質時菊芳。", "鳴環曳履出長廊，為君秋夜搗衣裳。纖羅對鳳凰，", "所在天一方，寒衣徒自香。"]'),
('yuding-80','雜曲歌辭：秋夜長','張籍','唐','御定全唐诗','yuding','','[]','秋天如水夜未央，天漢東西月色光。愁人不寐畏枕席，',40,'御定全唐詩/json/026.json','["秋天如水夜未央，天漢東西月色光。愁人不寐畏枕席，", "白露滿田風褭褭，千聲萬聲鶡鳥鳴。"]'),
('yuding-81','雜曲歌辭：秋夜曲二首','王建','唐','御定全唐诗','yuding','','[]','天清漏長霜泊泊，蘭綠收榮桂膏涸。高樓雲鬟弄嬋娟，',80,'御定全唐詩/json/026.json','["天清漏長霜泊泊，蘭綠收榮桂膏涸。高樓雲鬟弄嬋娟，", "香囊火死香氣少，向帷合眼何時曉。城烏作營啼野月，", "秋燈向壁掩洞房，良人此夜直明光。", "天河悠悠漏水長，南樓北斗兩相當。"]'),
('yuding-82','雜曲歌辭：秋夜曲','張仲素','唐','御定全唐诗','yuding','','[]','丁丁漏水夜何長，漫漫輕雲露月光。',32,'御定全唐詩/json/026.json','["丁丁漏水夜何長，漫漫輕雲露月光。", "秋壁暗蟲通夕響，寒衣未寄莫飛霜。"]'),
('yuding-83','雜曲歌辭：秋夜曲','王涯','唐','御定全唐诗','yuding','','[]','桂魄初生秋露微，輕羅已薄未更衣。',32,'御定全唐詩/json/026.json','["桂魄初生秋露微，輕羅已薄未更衣。", "銀箏夜久殷勤弄，心怯空房不忍歸。"]'),
('yuding-84','雜曲歌辭：夜坐吟','李白','唐','御定全唐诗','yuding','','[]','冬夜夜寒覺夜長，沉吟久坐坐北堂。冰合井泉月入閨，',54,'御定全唐詩/json/026.json','["冬夜夜寒覺夜長，沉吟久坐坐北堂。冰合井泉月入閨，", "歌有聲，妾有情。情聲合，兩無違。", "一語不入意，從君萬曲梁塵飛。"]'),
('yuding-85','雜曲歌辭：夜坐吟','李白','唐','御定全唐诗','yuding','','[]','踏踏馬頭誰見過，眼看北斗直天河。西風羅幕生翠波，',24,'御定全唐詩/json/026.json','["踏踏馬頭誰見過，眼看北斗直天河。西風羅幕生翠波，"]'),
('yuding-86','雜曲歌辭：夜寒吟','鮑溶','唐','御定全唐诗','yuding','','[]','九衢金吾夜行行，上宮玉漏遙分明。霜飆乘陰掃地起，',48,'御定全唐詩/json/026.json','["九衢金吾夜行行，上宮玉漏遙分明。霜飆乘陰掃地起，", "細腰楚姬絲竹間，白紵長袖歌閑閑，豈識苦寒損朱顏。"]'),
('yuding-87','雜曲歌辭：定情篇','喬知之','唐','御定全唐诗','yuding','','[]','共君結新婚，歲寒心未蔔。相與遊春園，各隨情所逐。',517,'御定全唐詩/json/026.json','["共君結新婚，歲寒心未蔔。相與遊春園，各隨情所逐。", "君念菖蒲花，妾感苦寒竹。菖花多豔姿，寒竹有貞葉。", "此時妾比君，君心不如妾。簪玉步河堤，妖韶援綠pH。", "鳧雁將子游，鶯燕從雙棲。君念春光好，妾向春光啼。", "君時不得意，妾棄還金閨。結言本同心，悲歡何未齊。", "怨咽前致辭，願得中所悲。人間丈夫易，世路婦難為。", "始經天月照，終若流星馳。長信佳麗人，失意非蛾眉。", "廬江小吏婦，非關織作遲。本願長相對，今已長相思。", "複有遊宦子，結援從梁陳。燕居崇三朝，去來歷九春。", "誓心妾終始，蠶桑奉所親。歸願未克從，黃金贈路人。", "潔婦懷明義，從泛河之津。於今千萬年，誰當問水濱。", "更憶倡家樓，夫婿事封侯。去時思灼灼，去罷心悠悠。", "不憐妾歲晏，千載隴西頭。以茲常惕惕，百慮恒盈積。", "由來共結褵，幾人同匪石。故歲雕梁燕，雙去今來隻。", "今日玉庭梅，朝紅暮成碧。碧榮始芬敷，黃葉已淅瀝。", "何用念芳春，芳春有流易。何用重歡娛，歡娛俄戚戚。", "家本巫山陽，歸去路何長。敘言情未盡，采菉已盈筐。", "桑榆日映物，草色盈高岡。下有碧流水，上有丹桂香。", "桂枝不須折，碧流清且潔。贈君比芳菲，受惠常不滅。", "贈君淚潺湲，相思無斷絕。妾有秦家鏡，寶匣裝珠璣。", "鑒來年二八，不記易陰暉。妾無光寂寂，委照影依依。", "今日持為贈，相識莫相違。"]'),
('yuding-88','雜曲歌辭：定情樂','施肩吾','唐','御定全唐诗','yuding','','[]','敢嗟君不憐，自是命不諧。著破三條裾，卻還雙股釵。',24,'御定全唐詩/json/026.json','["敢嗟君不憐，自是命不諧。著破三條裾，卻還雙股釵。"]'),
('yuding-89','雜曲歌辭：春江曲','郭元振','唐','御定全唐诗','yuding','','[]','江水春沉沉，上有雙竹林。竹葉壞水色，郎亦壞人心。',24,'御定全唐詩/json/026.json','["江水春沉沉，上有雙竹林。竹葉壞水色，郎亦壞人心。"]'),
('yuding-90','雜曲歌辭：春江曲','張籍','唐','御定全唐诗','yuding','','[]','春江無雲潮水平，蒲心出水鳧雛鳴。長幹夫婿愛遠行，',48,'御定全唐詩/json/026.json','["春江無雲潮水平，蒲心出水鳧雛鳴。長幹夫婿愛遠行，", "春來未到父母家，舟小風多渡不得。欲辭舅姑先問人，"]'),
('yuding-91','雜曲歌辭：春江曲','王涯','唐','御定全唐诗','yuding','','[]','搖漾越江春，相將看白蘋。歸時不覺夜，出浦月隨人。',24,'御定全唐詩/json/026.json','["搖漾越江春，相將看白蘋。歸時不覺夜，出浦月隨人。"]'),
('yuding-92','雜曲歌辭：春江曲二首','張仲素','唐','御定全唐诗','yuding','','[]','家寄征江岸，征人幾歲遊。不知潮水信，每日到沙頭。',48,'御定全唐詩/json/026.json','["家寄征江岸，征人幾歲遊。不知潮水信，每日到沙頭。", "乘曉南湖去，參差疊浪橫。前洲在何處，霧裏雁嚶嚶。"]'),
('yuding-93','雜曲歌辭：江上曲','李嘉佑','唐','御定全唐诗','yuding','','[]','江上澹澹芙蓉花，江口蛾眉獨浣紗。可憐應是陽臺女，',56,'御定全唐詩/json/026.json','["江上澹澹芙蓉花，江口蛾眉獨浣紗。可憐應是陽臺女，", "蒼梧秋色不堪論，千載依依帝子魂。", "君看峰上斑斑竹，儘是湘妃泣淚痕。"]'),
('yuding-94','雜曲歌辭：桃花曲','顧況','唐','御定全唐诗','yuding','','[]','魏帝宮人舞鳳樓，隋家天子泛龍舟。',32,'御定全唐詩/json/026.json','["魏帝宮人舞鳳樓，隋家天子泛龍舟。", "君王夜醉春眠晏，不覺桃花逐水流。"]'),
('yuding-95','雜曲歌辭：樹中草','李白','唐','御定全唐诗','yuding','','[]','鳥銜野田草，誤入枯桑裏。客土植危根，逢春猶不死。',48,'御定全唐詩/json/026.json','["鳥銜野田草，誤入枯桑裏。客土植危根，逢春猶不死。", "草木雖無情，因依尚可生。如何同枝葉，各自有枯榮。"]'),
('yuding-96','雜曲歌辭：樹中草','張祜','唐','御定全唐诗','yuding','','[]','青青樹中草，托根非不危。草生樹卻死，榮枯君可知。',24,'御定全唐詩/json/026.json','["青青樹中草，托根非不危。草生樹卻死，榮枯君可知。"]'),
('yuding-97','雜曲歌辭：春遊吟','李章','唐','御定全唐诗','yuding','','[]','初春遍芳甸，千里靄盈矚。美人摘新英，步步玩春綠。',44,'御定全唐詩/json/026.json','["初春遍芳甸，千里靄盈矚。美人摘新英，步步玩春綠。", "所思杳何處，宛在吳江曲。可憐不得共芳菲，"]'),
('yuding-98','雜曲歌辭：春遊樂','施肩吾','唐','御定全唐诗','yuding','','[]','一年三百六十日，賞心那似春中物。',32,'御定全唐詩/json/026.json','["一年三百六十日，賞心那似春中物。", "草迷曲塢花滿園，東家少年西家出。"]'),
('yuding-99','雜曲歌辭：春遊樂二首','李端','唐','御定全唐诗','yuding','','[]','游童蘇合帶，倡女蒲葵扇。初日映城時，相思忽相見。',96,'御定全唐詩/json/026.json','["游童蘇合帶，倡女蒲葵扇。初日映城時，相思忽相見。", "褰裳踏露草，理鬢回花面。薄暮不同歸，留情此芳甸。", "柘彈連錢馬，銀鉤妥墮鬟。采桑春陌上，踏草夕陽間。", "意合辭先露，心誠貌卻閑。明朝若相憶，雲雨出巫山。"]'),
('yuding-100','雜曲歌辭：春遊曲三首','張仲素','唐','御定全唐诗','yuding','','[]','煙柳飛輕絮，風榆落小錢。濛濛百花裏，羅綺競秋千。',72,'御定全唐詩/json/026.json','["煙柳飛輕絮，風榆落小錢。濛濛百花裏，羅綺競秋千。", "騁望登香閣，爭高下砌台。林間踏青去，席上意錢來。", "行樂三春節，林花百和香。當年重意氣，先占鬥雞場。"]'),
('yuding-101','雜曲歌辭：樂府二首','劉言史','唐','御定全唐诗','yuding','','[]','花頷紅鬃一向偏，綠槐香陌欲朝天。',64,'御定全唐詩/json/026.json','["花頷紅鬃一向偏，綠槐香陌欲朝天。", "仍嫌眾裏嬌行疾，傍鐙深藏白玉鞭。", "噴珠團香小桂條，玉鞭兼賜霍嫖姚。", "弄影便從天禁出，碧蹄聲碎五門橋。"]'),
('yuding-102','雜曲歌辭：樂府','顧況','唐','御定全唐诗','yuding','','[]','暖谷春光至，宸游近甸榮。雲隨天仗轉，風入禦簾輕。',144,'御定全唐詩/json/026.json','["暖谷春光至，宸游近甸榮。雲隨天仗轉，風入禦簾輕。", "翠蓋浮佳氣，朱樓倚太清。朝臣冠劍退，宮女管弦迎。", "細草承雕輦，繁花入幔城。文房開聖藻，武衛宿天營。", "玉醴隨觴至，銅壺逐漏行。五星含土德，萬姓徹中聲。", "親祀先崇典，躬推示勸耕。國風新正樂，農器近消兵。", "道德關河固，刑章日月明。野人同鳥獸，率舞感升平。"]'),
('yuding-103','雜曲歌辭：樂府','權德輿','唐','御定全唐诗','yuding','','[]','光風澹蕩百花吐，樓上朝朝學歌舞。身年二八婿侍中，',40,'御定全唐詩/json/026.json','["光風澹蕩百花吐，樓上朝朝學歌舞。身年二八婿侍中，", "鶯啼日出不知曙，寂寂羅幃春夢長。"]'),
('yuding-104','雜曲歌辭：樂府三首','孟郊','唐','御定全唐诗','yuding','','[]','蓮子不可得，荷花生水中。猶勝道傍柳，無事蕩春風。',72,'御定全唐詩/json/026.json','["蓮子不可得，荷花生水中。猶勝道傍柳，無事蕩春風。", "淥萍與荷葉，同此一水中。風吹荷葉在，淥萍西複東。", "蓮花未開時，苦心終日卷。春水徒蕩漾，荷花未開展。"]'),
('yuding-105','雜曲歌辭：樂府','陸長源','唐','御定全唐诗','yuding','','[]','芙蓉初出水，菡萏露中花。風吹著枯木，無奈值空槎。',24,'御定全唐詩/json/026.json','["芙蓉初出水，菡萏露中花。風吹著枯木，無奈值空槎。"]'),
('yuding-106','雜曲歌辭：雜曲','王勃','唐','御定全唐诗','yuding','','[]','智瓊神女，來訪文君。蛾眉始約，羅袖初熏。歌齊曲韻，',25,'御定全唐詩/json/026.json','["智瓊神女，來訪文君。蛾眉始約，羅袖初熏。歌齊曲韻，"]'),
('yuding-107','雜曲歌辭：古曲五首','施肩吾','唐','御定全唐诗','yuding','','[]','可憐江北女，慣唱江南曲。搖盪木蘭舟，雙鳧不成浴。',120,'御定全唐詩/json/026.json','["可憐江北女，慣唱江南曲。搖盪木蘭舟，雙鳧不成浴。", "郎為匕上香，妾為籠上灰。歸時雖暖熱，去罷生塵埃。", "夜裁鴛鴦綺，朝織蒲桃綾。欲試一寸心，待縫三尺冰。", "憐時魚得水，怨罷商與參。不如山支子，卻解結同心。", "紅顏感暮花，白日同流水。思君如孤燈，一夜一心死。"]'),
('yuding-108','雜曲歌辭：高句麗','李白','唐','御定全唐诗','yuding','','[]','金花折風帽，白馬小遲回。翩翩舞廣袖，似鳥海東來。',24,'御定全唐詩/json/026.json','["金花折風帽，白馬小遲回。翩翩舞廣袖，似鳥海東來。"]'),
('yuding-109','雜曲歌辭：摩多樓子','李賀','唐','御定全唐诗','yuding','','[]','玉塞去金人，二萬四千里。風吹沙作雲，一時渡遼水。',72,'御定全唐詩/json/026.json','["玉塞去金人，二萬四千里。風吹沙作雲，一時渡遼水。", "天白水如練，甲絲雙串斷。行行莫苦辛，城月猶殘半。", "曉氣朔煙上，趢趗胡馬蹄。行人聽水別，隔隴長東西。"]'),
('yuding-0','雜曲歌辭：遼東行','王建','唐','御定全唐诗','yuding','','[]','遼東萬里遼水曲，古戍無城複無屋。黃雲蓋地雪作山，',48,'御定全唐詩/json/027.json','["遼東萬里遼水曲，古戍無城複無屋。黃雲蓋地雪作山，", "年年郡縣送征人，將與遼東作丘阪。寧為草木鄉中生，"]'),
('yuding-1','雜曲歌辭：渡遼水','王建','唐','御定全唐诗','yuding','','[]','渡遼水，此去咸陽五千里。來時父母知隔生，',36,'御定全唐詩/json/027.json','["渡遼水，此去咸陽五千里。來時父母知隔生，", "身在應無回渡日，駐馬相看遼水傍。"]'),
('yuding-2','雜曲歌辭：昔昔鹽：垂柳覆金堤','趙嘏','唐','御定全唐诗','yuding','','[]','新年垂柳色，嫋嫋對空閨。不畏芳菲好，自緣離別啼。',48,'御定全唐詩/json/027.json','["新年垂柳色，嫋嫋對空閨。不畏芳菲好，自緣離別啼。", "因風飄玉戶，向日映金堤。驛使何時度，還將贈隴西。"]'),
('yuding-3','雜曲歌辭：昔昔鹽：蘼蕪葉複齊','趙嘏','唐','御定全唐诗','yuding','','[]','提筐紅葉下，度日采蘼蕪。掬翠香盈袖，看花憶故夫。',48,'御定全唐詩/json/027.json','["提筐紅葉下，度日采蘼蕪。掬翠香盈袖，看花憶故夫。", "葉齊誰複見，風暖恨偏孤。一被春光累，容顏與昔殊。"]'),
('yuding-4','雜曲歌辭：昔昔鹽：水溢芙蓉沼','趙嘏','唐','御定全唐诗','yuding','','[]','淥沼春光後，青青草色濃。綺羅驚翡翠，暗粉妒芙蓉。',48,'御定全唐詩/json/027.json','["淥沼春光後，青青草色濃。綺羅驚翡翠，暗粉妒芙蓉。", "雲遍窗前見，荷翻鏡裏逢。將心托流水，終日渺無從。"]'),
('yuding-5','雜曲歌辭：昔昔鹽：花飛桃李蹊','趙嘏','唐','御定全唐诗','yuding','','[]','遠期難可托，桃李自依依。花徑無容跡，戎裘未下機。',48,'御定全唐詩/json/027.json','["遠期難可托，桃李自依依。花徑無容跡，戎裘未下機。", "隨風開又落，度日掃還飛。欲折枝枝贈，那知歸不歸。"]'),
('yuding-6','雜曲歌辭：昔昔鹽：采桑秦氏女','趙嘏','唐','御定全唐诗','yuding','','[]','南陌采桑出，誰知妾姓秦。獨憐傾國貌，不負早鶯春。',48,'御定全唐詩/json/027.json','["南陌采桑出，誰知妾姓秦。獨憐傾國貌，不負早鶯春。", "珠履蕩花濕，龍鉤折桂新。使君那駐馬，自有侍中人。"]'),
('yuding-7','雜曲歌辭：昔昔鹽：織錦竇家妻','趙嘏','唐','御定全唐诗','yuding','','[]','當年誰不羨，分作竇家妻。錦字行行苦，羅帷日日啼。',48,'御定全唐詩/json/027.json','["當年誰不羨，分作竇家妻。錦字行行苦，羅帷日日啼。", "豈知登隴遠，只恨下機迷。直候陽關使，殷勤寄海西。"]'),
('yuding-8','雜曲歌辭：昔昔鹽：關山別蕩子','趙嘏','唐','御定全唐诗','yuding','','[]','那堪聞蕩子，迢遞涉關山。腸為馬嘶斷，衣從淚滴斑。',48,'御定全唐詩/json/027.json','["那堪聞蕩子，迢遞涉關山。腸為馬嘶斷，衣從淚滴斑。", "愁看塞上路，詎惜鏡中顏。儻見征西雁，應傳一字還。"]'),
('yuding-9','雜曲歌辭：昔昔鹽：風月守空閨','趙嘏','唐','御定全唐诗','yuding','','[]','良人猶遠戍，耿耿夜閨空。繡戶流宵月，羅帷坐曉風。',48,'御定全唐詩/json/027.json','["良人猶遠戍，耿耿夜閨空。繡戶流宵月，羅帷坐曉風。", "魂飛沙帳北，腸斷玉關中。尚自無消息，錦衾那得同。"]'),
('yuding-10','雜曲歌辭：昔昔鹽：恒斂千金笑','趙嘏','唐','御定全唐诗','yuding','','[]','玉顏恒自斂，羞出鏡臺前。早惑陽城客，今悲華錦筵。',48,'御定全唐詩/json/027.json','["玉顏恒自斂，羞出鏡臺前。早惑陽城客，今悲華錦筵。", "從軍人更遠，投喜鵲空傳。夫婿交河北，迢迢路幾千。"]'),
('yuding-11','雜曲歌辭：昔昔鹽：長垂雙玉啼','趙嘏','唐','御定全唐诗','yuding','','[]','雙雙紅淚墮，度日暗中啼。雁出居延北，人猶遼海西。',48,'御定全唐詩/json/027.json','["雙雙紅淚墮，度日暗中啼。雁出居延北，人猶遼海西。", "向燈垂玉枕，對月灑金閨。不惜羅衣濕，惟愁歸意迷。"]'),
('yuding-12','雜曲歌辭：昔昔鹽：蟠龍隨鏡隱','趙嘏','唐','御定全唐诗','yuding','','[]','鸞鏡無由照，蛾眉豈忍看。不知愁發換，空見隱龍蟠。',48,'御定全唐詩/json/027.json','["鸞鏡無由照，蛾眉豈忍看。不知愁發換，空見隱龍蟠。", "那愜紅顏改，偏傷白日殘。今朝窺玉匣，雙淚落闌幹。"]'),
('yuding-13','雜曲歌辭：昔昔鹽：彩鳳逐帷低','趙嘏','唐','御定全唐诗','yuding','','[]','巧繡雙飛鳳，朝朝伴下帷。春花那見照，暮色已頻欺。',48,'御定全唐詩/json/027.json','["巧繡雙飛鳳，朝朝伴下帷。春花那見照，暮色已頻欺。", "欲卷思君處，將啼裛淚時。何年征戍客，傳語報佳期。"]'),
('yuding-14','雜曲歌辭：昔昔鹽：驚魂同夜鵲','趙嘏','唐','御定全唐诗','yuding','','[]','萬里無人見，眾情難與論。思君常入夢，同鵲屢驚魂。',48,'御定全唐詩/json/027.json','["萬里無人見，眾情難與論。思君常入夢，同鵲屢驚魂。", "孤寢紅羅帳，雙啼玉箸痕。妾心甘自保，豈複暫忘恩。"]'),
('yuding-15','雜曲歌辭：昔昔鹽：倦寢聽晨雞','趙嘏','唐','御定全唐诗','yuding','','[]','去去邊城騎，愁眠掩夜閨。披衣窺落月，拭淚待鳴雞。',48,'御定全唐詩/json/027.json','["去去邊城騎，愁眠掩夜閨。披衣窺落月，拭淚待鳴雞。", "不憤連年別，那堪長夜啼。功成應自恨，早晚發遼西。"]'),
('yuding-16','雜曲歌辭：昔昔鹽：暗牖懸蛛網','趙嘏','唐','御定全唐诗','yuding','','[]','暗中蛛網織，曆亂綺窗前。萬里終無信，一條徒自懸。',48,'御定全唐詩/json/027.json','["暗中蛛網織，曆亂綺窗前。萬里終無信，一條徒自懸。", "分從珠露滴，愁見隙風牽。妾意何聊賴，看看劇斷弦。"]'),
('yuding-17','雜曲歌辭：昔昔鹽：空梁落燕泥','趙嘏','唐','御定全唐诗','yuding','','[]','春至今朝燕，花時伴獨啼。飛斜珠箔隔，語近畫梁低。',48,'御定全唐詩/json/027.json','["春至今朝燕，花時伴獨啼。飛斜珠箔隔，語近畫梁低。", "帷卷閑窺戶，床空暗落泥。誰能長對此，雙去複雙棲。"]'),
('yuding-18','雜曲歌辭：昔昔鹽：前年過代北','趙嘏','唐','御定全唐诗','yuding','','[]','代北幾千里，前年又複經。燕山雲自合，胡塞草應青。',48,'御定全唐詩/json/027.json','["代北幾千里，前年又複經。燕山雲自合，胡塞草應青。", "鐵馬喧鼙鼓，蛾眉怨錦屏。不知羌笛曲，掩淚若為聽。"]'),
('yuding-19','雜曲歌辭：昔昔鹽：今歲往遼西','趙嘏','唐','御定全唐诗','yuding','','[]','萬里飛書至，聞君已渡遼。只諳新別苦，忘卻舊時嬌。',48,'御定全唐詩/json/027.json','["萬里飛書至，聞君已渡遼。只諳新別苦，忘卻舊時嬌。", "烽戍年將老，紅顏日向凋。胡沙兼漢苑，相望幾迢迢。"]'),
('yuding-20','雜曲歌辭：昔昔鹽：一去無還意','趙嘏','唐','御定全唐诗','yuding','','[]','良人征絕域，一去不言還。百戰攻胡虜，三冬阻玉關。',48,'御定全唐詩/json/027.json','["良人征絕域，一去不言還。百戰攻胡虜，三冬阻玉關。", "蕭蕭邊馬思，獵獵戍旗閑。獨把千重恨，連年未解顏。"]'),
('yuding-21','雜曲歌辭：昔昔鹽：那能惜馬蹄','趙嘏','唐','御定全唐诗','yuding','','[]','雲中路杳杳，江畔草萋萋。妾久垂珠淚，君何惜馬蹄。',48,'御定全唐詩/json/027.json','["雲中路杳杳，江畔草萋萋。妾久垂珠淚，君何惜馬蹄。", "邊風悲曉角，營月怨春鼙。未道休征戰，愁眉又複低。"]'),
('yuding-22','雜曲歌辭：水調歌第一','不詳','唐','御定全唐诗','yuding','','[]','平沙落日大荒西，隴上明星高複低。',32,'御定全唐詩/json/027.json','["平沙落日大荒西，隴上明星高複低。", "孤山幾處看烽火，壯士連營候鼓鼙。"]'),
('yuding-23','雜曲歌辭：水調歌第二','不詳','唐','御定全唐诗','yuding','','[]','猛將關西意氣多，能騎駿馬弄雕戈。',32,'御定全唐詩/json/027.json','["猛將關西意氣多，能騎駿馬弄雕戈。", "金鞍寶鉸精神出，笛倚新翻水調歌。"]'),
('yuding-24','雜曲歌辭：水調歌第三','不詳','唐','御定全唐诗','yuding','','[]','王孫別上綠珠輪，不羨名公樂此身。',32,'御定全唐詩/json/027.json','["王孫別上綠珠輪，不羨名公樂此身。", "戶外碧潭春洗馬，樓前紅燭夜迎人。"]'),
('yuding-25','雜曲歌辭：水調歌第四','不詳','唐','御定全唐诗','yuding','','[]','隴頭一段氣長秋，舉目蕭條總是愁。',32,'御定全唐詩/json/027.json','["隴頭一段氣長秋，舉目蕭條總是愁。", "只為征人多下淚，年年添作斷腸流。"]'),
('yuding-26','雜曲歌辭：水調歌第五','不詳','唐','御定全唐诗','yuding','','[]','雙帶仍分影，同心巧結香。不應須換彩，意欲媚濃妝。',24,'御定全唐詩/json/027.json','["雙帶仍分影，同心巧結香。不應須換彩，意欲媚濃妝。"]'),
('yuding-27','雜曲歌辭：入破第一','不詳','唐','御定全唐诗','yuding','','[]','細草河邊一雁飛，黃龍關裏掛戎衣。',32,'御定全唐詩/json/027.json','["細草河邊一雁飛，黃龍關裏掛戎衣。", "為受明王恩寵甚，從事經年不復歸。"]'),
('yuding-28','雜曲歌辭：入破第二','不詳','唐','御定全唐诗','yuding','','[]','錦城絲管日紛紛，半入江風半入雲。',32,'御定全唐詩/json/027.json','["錦城絲管日紛紛，半入江風半入雲。", "此曲只應天上去，人間能得幾回聞。"]'),
('yuding-29','雜曲歌辭：入破第三','不詳','唐','御定全唐诗','yuding','','[]','昨夜遙歡出建章，今朝綴賞度昭陽。',32,'御定全唐詩/json/027.json','["昨夜遙歡出建章，今朝綴賞度昭陽。", "傳聲莫閉黃金屋，為報先開白玉堂。"]'),
('yuding-30','雜曲歌辭：入破第四','不詳','唐','御定全唐诗','yuding','','[]','日晚笳聲咽戍樓，隴雲漫漫水東流。',32,'御定全唐詩/json/027.json','["日晚笳聲咽戍樓，隴雲漫漫水東流。", "行人萬里向西去，滿目關山空恨愁。"]'),
('yuding-31','雜曲歌辭：入破第五','不詳','唐','御定全唐诗','yuding','','[]','千年一遇聖明朝，願對君王舞細腰。',32,'御定全唐詩/json/027.json','["千年一遇聖明朝，願對君王舞細腰。", "乍可當熊任生死，誰能伴鳳上雲霄。"]'),
('yuding-32','雜曲歌辭：第六徹','不詳','唐','御定全唐诗','yuding','','[]','閨燭無人影，羅屏有夢魂。近來音耗絕，終日望君門。',24,'御定全唐詩/json/027.json','["閨燭無人影，羅屏有夢魂。近來音耗絕，終日望君門。"]'),
('yuding-33','雜曲歌辭：水調','吳融','唐','御定全唐诗','yuding','','[]','鑿河千里走黃沙，浮殿西來動日華。',32,'御定全唐詩/json/027.json','["鑿河千里走黃沙，浮殿西來動日華。", "可道新聲是亡國，且貪惆悵後庭花。"]'),
('yuding-34','雜曲歌辭：堂堂','李義府','唐','御定全唐诗','yuding','','[]','鏤月成歌扇，裁雲作舞衣。自憐回雪影，好取洛川歸。',48,'御定全唐詩/json/027.json','["鏤月成歌扇，裁雲作舞衣。自憐回雪影，好取洛川歸。", "懶正鴛鴦被，羞褰玳瑁床。春風別有意，密處也尋香。"]'),
('yuding-35','雜曲歌辭：堂堂','李義府','唐','御定全唐诗','yuding','','[]','堂堂複堂堂，紅脫梅灰香。十年粉蠹生畫梁，',37,'御定全唐詩/json/027.json','["堂堂複堂堂，紅脫梅灰香。十年粉蠹生畫梁，", "華清源中iJ石湯，裴回百鳳隨君王。"]'),
('yuding-36','雜曲歌辭：涼州歌第一','不詳','唐','御定全唐诗','yuding','','[]','漢家宮裏柳如絲，上苑桃花連碧池。',32,'御定全唐詩/json/027.json','["漢家宮裏柳如絲，上苑桃花連碧池。", "聖壽已傳千歲酒，天文更賞百僚詩。"]'),
('yuding-37','雜曲歌辭：涼州歌第二','不詳','唐','御定全唐诗','yuding','','[]','朔風吹葉雁門秋，萬里煙塵昏戍樓。',32,'御定全唐詩/json/027.json','["朔風吹葉雁門秋，萬里煙塵昏戍樓。", "征馬長思青海北，胡笳夜聽隴山頭。"]'),
('yuding-38','雜曲歌辭：涼州歌第三','不詳','唐','御定全唐诗','yuding','','[]','開篋淚沾襦，見君前日書。夜台空寂寞，猶見紫雲車。',24,'御定全唐詩/json/027.json','["開篋淚沾襦，見君前日書。夜台空寂寞，猶見紫雲車。"]'),
('yuding-39','雜曲歌辭：排遍第一','不詳','唐','御定全唐诗','yuding','','[]','三秋陌上早霜飛，羽獵平田淺草齊。',32,'御定全唐詩/json/027.json','["三秋陌上早霜飛，羽獵平田淺草齊。", "錦背蒼鷹初出按，五花驄馬喂來肥。"]'),
('yuding-40','雜曲歌辭：排遍第二','不詳','唐','御定全唐诗','yuding','','[]','鴛鴦殿裏笙歌起，翡翠樓前出舞人。',32,'御定全唐詩/json/027.json','["鴛鴦殿裏笙歌起，翡翠樓前出舞人。", "喚上紫微三五夕，聖明方壽一千春。"]'),
('yuding-41','雜曲歌辭：涼州詞','耿湋','唐','御定全唐诗','yuding','','[]','國使翩翩隨旆旌，隴西岐路足荒城。',32,'御定全唐詩/json/027.json','["國使翩翩隨旆旌，隴西岐路足荒城。", "氈裘牧馬胡雛小，日暮蕃歌三兩聲。"]'),
('yuding-42','雜曲歌辭：涼州詞','張籍','唐','御定全唐诗','yuding','','[]','邊城暮雨雁飛低，蘆筍初生漸欲齊。',96,'御定全唐詩/json/027.json','["邊城暮雨雁飛低，蘆筍初生漸欲齊。", "無數鈴聲遙過磧，應馱白練到安西。", "古鎮城門白磧開，胡兵往往傍沙堆。", "巡邊使客行應早，每待平安火到來。", "鳳林關裏水東流，白草黃榆六十秋。", "邊將皆承主恩澤，無人解道取涼州。"]'),
('yuding-43','雜曲歌辭：涼州詞','薛逢','唐','御定全唐诗','yuding','','[]','昨夜蕃兵報國仇，沙州都護破涼州。',32,'御定全唐詩/json/027.json','["昨夜蕃兵報國仇，沙州都護破涼州。", "黃河九曲今歸漢，塞外縱橫戰血流。"]'),
('yuding-44','雜曲歌辭：太和第一','不詳','唐','御定全唐诗','yuding','','[]','國門卿相舊山莊，聖主移來宴綠芳。',32,'御定全唐詩/json/027.json','["國門卿相舊山莊，聖主移來宴綠芳。", "簾外輾為車馬路，花間踏出舞人場。"]'),
('yuding-45','雜曲歌辭：太和第二','不詳','唐','御定全唐诗','yuding','','[]','國鳥尚含天樂轉，寒風猶帶禦衣香。',32,'御定全唐詩/json/027.json','["國鳥尚含天樂轉，寒風猶帶禦衣香。", "為報碧潭明月夜，會須留賞待君王。"]'),
('yuding-46','雜曲歌辭：太和第三','不詳','唐','御定全唐诗','yuding','','[]','庭前鵲繞相思樹，井上鶯歌爭刺桐。',32,'御定全唐詩/json/027.json','["庭前鵲繞相思樹，井上鶯歌爭刺桐。", "含情少婦悲春草，多是良人學轉蓬。"]'),
('yuding-47','雜曲歌辭：太和第四','不詳','唐','御定全唐诗','yuding','','[]','塞北江南共一家，何須淚落怨黃沙。',32,'御定全唐詩/json/027.json','["塞北江南共一家，何須淚落怨黃沙。", "春酒半酣千日醉，庭前還有落梅花。"]'),
('yuding-48','雜曲歌辭：太和第五徹','不詳','唐','御定全唐诗','yuding','','[]','我皇膺運太平年，四海朝宗會百川。',32,'御定全唐詩/json/027.json','["我皇膺運太平年，四海朝宗會百川。", "自古幾多明聖主，不如今帝勝堯天。"]'),
('yuding-49','雜曲歌辭：伊川歌第一','不詳','唐','御定全唐诗','yuding','','[]','秋風明月獨離居，蕩子從戎十載餘。',32,'御定全唐詩/json/027.json','["秋風明月獨離居，蕩子從戎十載餘。", "征人去日殷勤屬，歸雁來時數寄書。"]'),
('yuding-50','雜曲歌辭：伊川歌第二','不詳','唐','御定全唐诗','yuding','','[]','彤闈曉辟萬鞍回，玉輅春遊薄晚開。',32,'御定全唐詩/json/027.json','["彤闈曉辟萬鞍回，玉輅春遊薄晚開。", "渭北清光搖草樹，州南嘉景入樓臺。"]'),
('yuding-51','雜曲歌辭：伊川歌第三','不詳','唐','御定全唐诗','yuding','','[]','聞道黃花戍，頻年不解兵。可憐閨裏月，偏照漢家營。',24,'御定全唐詩/json/027.json','["聞道黃花戍，頻年不解兵。可憐閨裏月，偏照漢家營。"]'),
('yuding-52','雜曲歌辭：伊川歌第四','不詳','唐','御定全唐诗','yuding','','[]','千里東歸客，無心憶舊遊。掛帆遊白水，高枕到青州。',24,'御定全唐詩/json/027.json','["千里東歸客，無心憶舊遊。掛帆遊白水，高枕到青州。"]'),
('yuding-53','雜曲歌辭：伊川歌第五','不詳','唐','御定全唐诗','yuding','','[]','桂殿江烏對，雕屏海燕重。只應多釀酒，醉罷樂高鐘。',24,'御定全唐詩/json/027.json','["桂殿江烏對，雕屏海燕重。只應多釀酒，醉罷樂高鐘。"]'),
('yuding-54','雜曲歌辭：入破第一','不詳','唐','御定全唐诗','yuding','','[]','千門今夜曉初晴，萬里天河徹帝京。',32,'御定全唐詩/json/027.json','["千門今夜曉初晴，萬里天河徹帝京。", "璨璨繁星駕秋色，棱棱霜氣韻鐘聲。"]'),
('yuding-55','雜曲歌辭：入破第二','不詳','唐','御定全唐诗','yuding','','[]','長安二月柳依依，西出流沙路漸微。',32,'御定全唐詩/json/027.json','["長安二月柳依依，西出流沙路漸微。", "閼氏山上春光少，相府庭邊驛使稀。"]'),
('yuding-56','雜曲歌辭：入破第三','不詳','唐','御定全唐诗','yuding','','[]','三秋大漠冷溪山，八月嚴霜變草顏。',32,'御定全唐詩/json/027.json','["三秋大漠冷溪山，八月嚴霜變草顏。", "卷旆風行宵渡磧，銜枚電掃曉應還。"]'),
('yuding-57','雜曲歌辭：入破第四','不詳','唐','御定全唐诗','yuding','','[]','行樂三陽早，芳菲二月春。閨中紅粉態，陌上看花人。',24,'御定全唐詩/json/027.json','["行樂三陽早，芳菲二月春。閨中紅粉態，陌上看花人。"]'),
('yuding-58','雜曲歌辭：入破第五','不詳','唐','御定全唐诗','yuding','','[]','君住孤山下，煙深夜徑長。轅門渡綠水，游苑繞垂楊。',24,'御定全唐詩/json/027.json','["君住孤山下，煙深夜徑長。轅門渡綠水，游苑繞垂楊。"]'),
('yuding-59','雜曲歌辭：陸州歌第一','不詳','唐','御定全唐诗','yuding','','[]','分野中峰變，陰晴眾壑殊。欲投人處宿，隔浦問樵夫。',24,'御定全唐詩/json/027.json','["分野中峰變，陰晴眾壑殊。欲投人處宿，隔浦問樵夫。"]'),
('yuding-60','雜曲歌辭：陸州歌第二','不詳','唐','御定全唐诗','yuding','','[]','共得煙霞徑，東歸山水遊。蕭蕭望林夜，寂寂坐中秋。',24,'御定全唐詩/json/027.json','["共得煙霞徑，東歸山水遊。蕭蕭望林夜，寂寂坐中秋。"]'),
('yuding-61','雜曲歌辭：陸州歌第三','不詳','唐','御定全唐诗','yuding','','[]','香氣傳空滿，妝花映薄紅。歌聲天仗外，舞態禦樓中。',24,'御定全唐詩/json/027.json','["香氣傳空滿，妝花映薄紅。歌聲天仗外，舞態禦樓中。"]'),
('yuding-62','雜曲歌辭：排遍第一','不詳','唐','御定全唐诗','yuding','','[]','樹發花如錦，鶯啼柳若絲。更逢歡宴地，愁見別離時。',24,'御定全唐詩/json/027.json','["樹發花如錦，鶯啼柳若絲。更逢歡宴地，愁見別離時。"]'),
('yuding-63','雜曲歌辭：排遍第二','不詳','唐','御定全唐诗','yuding','','[]','明月照秋葉，西風響夜砧。強言徒自亂，往事不堪尋。',24,'御定全唐詩/json/027.json','["明月照秋葉，西風響夜砧。強言徒自亂，往事不堪尋。"]'),
('yuding-64','雜曲歌辭：排遍第三','不詳','唐','御定全唐诗','yuding','','[]','坐對銀釭曉，停留玉箸痕。君門常不見，無處謝前恩。',24,'御定全唐詩/json/027.json','["坐對銀釭曉，停留玉箸痕。君門常不見，無處謝前恩。"]'),
('yuding-65','雜曲歌辭：排遍第四','不詳','唐','御定全唐诗','yuding','','[]','曙月當窗滿，征人出塞遙。畫樓終日閉，清管為誰調。',24,'御定全唐詩/json/027.json','["曙月當窗滿，征人出塞遙。畫樓終日閉，清管為誰調。"]'),
('yuding-66','雜曲歌辭：簇拍陸州','不詳','唐','御定全唐诗','yuding','','[]','西去輪台萬里餘，故鄉音耗日應疏。',32,'御定全唐詩/json/027.json','["西去輪台萬里餘，故鄉音耗日應疏。", "隴山鸚鵡能言語，為報閨人數寄書。"]'),
('yuding-67','雜曲歌辭：石州','不詳','唐','御定全唐诗','yuding','','[]','自從君去遠巡邊，終日羅幃獨自眠。看花情轉切，',34,'御定全唐詩/json/027.json','["自從君去遠巡邊，終日羅幃獨自眠。看花情轉切，", "何時狂虜滅，免得更留連。"]'),
('yuding-68','雜曲歌辭：蓋羅縫','不詳','唐','御定全唐诗','yuding','','[]','秦時明月漢時關，萬里征人尚未還。',64,'御定全唐詩/json/027.json','["秦時明月漢時關，萬里征人尚未還。", "但願龍庭神將在，不教胡馬渡陰山。", "音書杜絕白狼西，桃李無顏黃鳥啼。", "寒鳥春深歸去盡，出門腸斷草萋萋。"]'),
('yuding-69','雜曲歌辭：雙帶子','不詳','唐','御定全唐诗','yuding','','[]','私言切語誰人會，海燕雙飛繞畫梁。',32,'御定全唐詩/json/027.json','["私言切語誰人會，海燕雙飛繞畫梁。", "君學秋胡不相識，妾亦無心去采桑。"]'),
('yuding-70','雜曲歌辭：昆侖子','不詳','唐','御定全唐诗','yuding','','[]','揚子譚經去，淮王載酒過。醉來啼鳥喚，坐久落花多。',24,'御定全唐詩/json/027.json','["揚子譚經去，淮王載酒過。醉來啼鳥喚，坐久落花多。"]'),
('yuding-71','雜曲歌辭：祓禊曲','不詳','唐','御定全唐诗','yuding','','[]','昨見春條綠，那知秋葉黃。蟬聲猶未斷，寒雁已成行。',72,'御定全唐詩/json/027.json','["昨見春條綠，那知秋葉黃。蟬聲猶未斷，寒雁已成行。", "金谷園中柳，春來已舞腰。那堪好風景，獨上洛陽橋。", "何處堪愁思，花間長樂宮。君王不重客，泣淚向春風。"]'),
('yuding-72','雜曲歌辭：上巳樂','張祜','唐','御定全唐诗','yuding','','[]','猩猩血彩系頭標，天上齊聲舉畫橈。',32,'御定全唐詩/json/027.json','["猩猩血彩系頭標，天上齊聲舉畫橈。", "卻是內人爭意切，六宮羅袖一時招。"]'),
('yuding-73','雜曲歌辭：穆護砂','不詳','唐','御定全唐诗','yuding','','[]','玉管朝朝弄，清歌日日新。折花當驛路，寄與隴頭人。',24,'御定全唐詩/json/027.json','["玉管朝朝弄，清歌日日新。折花當驛路，寄與隴頭人。"]'),
('yuding-74','雜曲歌辭：思歸樂','不詳','唐','御定全唐诗','yuding','','[]','晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。',48,'御定全唐詩/json/027.json','["晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。", "萬里春應盡，三江雁亦稀。連天漢水廣，孤客未言歸。"]'),
('yuding-75','雜曲歌辭：金殿樂','不詳','唐','御定全唐诗','yuding','','[]','入夜秋砧動，千門起四鄰。不緣樓上月，應為隴頭人。',24,'御定全唐詩/json/027.json','["入夜秋砧動，千門起四鄰。不緣樓上月，應為隴頭人。"]'),
('yuding-76','雜曲歌辭：胡渭州','不詳','唐','御定全唐诗','yuding','','[]','亭亭孤月照行舟，寂寂長江萬里流。',56,'御定全唐詩/json/027.json','["亭亭孤月照行舟，寂寂長江萬里流。", "鄉國不知何處是，雲山漫漫使人愁。", "楊柳千尋色，桃花一苑芳。風吹入簾裏，惟有惹衣香。"]'),
('yuding-77','雜曲歌辭：戎渾','不詳','唐','御定全唐诗','yuding','','[]','風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。',24,'御定全唐詩/json/027.json','["風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。"]'),
('yuding-78','雜曲歌辭：牆頭花','不詳','唐','御定全唐诗','yuding','','[]','蟋蟀鳴洞房，梧桐落金井。為君裁舞衣，天寒剪刀冷。',48,'御定全唐詩/json/027.json','["蟋蟀鳴洞房，梧桐落金井。為君裁舞衣，天寒剪刀冷。", "妾有羅衣裳，秦王在時作。為舞春風多，秋來不堪著。"]'),
('yuding-79','雜曲歌辭：采桑','不詳','唐','御定全唐诗','yuding','','[]','自古多征戰，由來尚甲兵。長驅千里去，一舉兩蕃平。',48,'御定全唐詩/json/027.json','["自古多征戰，由來尚甲兵。長驅千里去，一舉兩蕃平。", "按劍從沙漠，歌謠滿帝京。寄言天下將，須立武功名。"]'),
('yuding-80','雜曲歌辭：楊下采桑','不詳','唐','御定全唐诗','yuding','','[]','飛絲惹綠塵，軟葉對孤輪。今朝入園去，物色強看人。',24,'御定全唐詩/json/027.json','["飛絲惹綠塵，軟葉對孤輪。今朝入園去，物色強看人。"]'),
('yuding-81','雜曲歌辭：破陣樂','不詳','唐','御定全唐诗','yuding','','[]','秋來四面足風沙，塞外征人暫別家。',102,'御定全唐詩/json/027.json','["秋來四面足風沙，塞外征人暫別家。", "千里不辭行路遠，時光早晚到天涯。", "漢兵出頓金微，照日明光鐵衣。百里火幡焰焰，", "正屬四方朝賀，端知萬舞皇威。", "少年膽氣淩雲，共許驍雄出群。匹馬城南挑戰，", "誓欲成名報國，羞將開口論勳。"]'),
('yuding-82','雜曲歌辭：戰勝樂','不詳','唐','御定全唐诗','yuding','','[]','百戰得功名，天兵意氣生。三邊永不戰，此是我皇英。',24,'御定全唐詩/json/027.json','["百戰得功名，天兵意氣生。三邊永不戰，此是我皇英。"]'),
('yuding-83','雜曲歌辭：劍南臣','不詳','唐','御定全唐诗','yuding','','[]','不分君恩斷，觀妝視鏡中。容華尚春日，嬌愛已秋風。',48,'御定全唐詩/json/027.json','["不分君恩斷，觀妝視鏡中。容華尚春日，嬌愛已秋風。", "枕席臨窗曉，屏帷對月空。年年後庭樹，芳悴在深宮。"]'),
('yuding-84','雜曲歌辭：征步郎','不詳','唐','御定全唐诗','yuding','','[]','塞外虜塵飛，頻年度磧西。死生隨玉劍，辛苦向金微。',24,'御定全唐詩/json/027.json','["塞外虜塵飛，頻年度磧西。死生隨玉劍，辛苦向金微。"]'),
('yuding-85','雜曲歌辭：歎疆場','不詳','唐','御定全唐诗','yuding','','[]','聞道行人至，妝梳對鏡臺。淚痕猶尚在，笑靨自然開。',24,'御定全唐詩/json/027.json','["聞道行人至，妝梳對鏡臺。淚痕猶尚在，笑靨自然開。"]'),
('yuding-86','雜曲歌辭：塞姑','不詳','唐','御定全唐诗','yuding','','[]','昨日盧梅塞口，整見諸人鎮守。',28,'御定全唐詩/json/027.json','["昨日盧梅塞口，整見諸人鎮守。", "都護三年不歸，折盡江邊楊柳。"]'),
('yuding-87','雜曲歌辭：水鼓子','不詳','唐','御定全唐诗','yuding','','[]','雕弓白羽獵初回，薄夜牛羊複下來。',32,'御定全唐詩/json/027.json','["雕弓白羽獵初回，薄夜牛羊複下來。", "夢水河邊秋草合，黑山峰外陣雲開。"]'),
('yuding-88','雜曲歌辭：婆羅門','不詳','唐','御定全唐诗','yuding','','[]','回樂峰前沙似雪，受降城外月如霜。',32,'御定全唐詩/json/027.json','["回樂峰前沙似雪，受降城外月如霜。", "不知何處吹蘆管，一夜征人盡望鄉。"]'),
('yuding-89','雜曲歌辭：浣沙女','不詳','唐','御定全唐诗','yuding','','[]','南陌春風早，東鄰去日斜。千花開瑞錦，香撲美人車。',48,'御定全唐詩/json/027.json','["南陌春風早，東鄰去日斜。千花開瑞錦，香撲美人車。", "長樂青門外，宜春小苑東。樓開萬戶上，人向百花中。"]'),
('yuding-90','雜曲歌辭：鎮西','不詳','唐','御定全唐诗','yuding','','[]','天邊物色更無春，只有羊群與馬群。',64,'御定全唐詩/json/027.json','["天邊物色更無春，只有羊群與馬群。", "誰家營裏吹羌笛，哀怨教人不忍聞。", "歲去年來拜聖朝，更無山闕對溪橋。", "九門楊柳渾無半，猶自千條與萬條。"]'),
('yuding-91','雜曲歌辭：回紇','不詳','唐','御定全唐诗','yuding','','[]','曾聞瀚海使難通，幽閨少婦罷裁縫。緬想邊庭征戰苦，',24,'御定全唐詩/json/027.json','["曾聞瀚海使難通，幽閨少婦罷裁縫。緬想邊庭征戰苦，"]'),
('yuding-92','雜曲歌辭：長命女','不詳','唐','御定全唐诗','yuding','','[]','雲送關西雨，風傳渭北秋。孤燈然客夢，寒杵搗鄉愁。',24,'御定全唐詩/json/027.json','["雲送關西雨，風傳渭北秋。孤燈然客夢，寒杵搗鄉愁。"]'),
('yuding-93','雜曲歌辭：醉公子','不詳','唐','御定全唐诗','yuding','','[]','昨日春園飲，今朝倒接z5。誰人扶上馬，不省下樓時。',25,'御定全唐詩/json/027.json','["昨日春園飲，今朝倒接z5。誰人扶上馬，不省下樓時。"]'),
('yuding-94','雜曲歌辭：一片子','不詳','唐','御定全唐诗','yuding','','[]','柳色青山映，梨花雪鳥藏。綠窗桃李下，閑坐歎春芳。',24,'御定全唐詩/json/027.json','["柳色青山映，梨花雪鳥藏。綠窗桃李下，閑坐歎春芳。"]'),
('yuding-95','雜曲歌辭：甘州','不詳','唐','御定全唐诗','yuding','','[]','欲使傳消息，空書意不任。寄君明月鏡，偏照故人心。',24,'御定全唐詩/json/027.json','["欲使傳消息，空書意不任。寄君明月鏡，偏照故人心。"]'),
('yuding-96','雜曲歌辭：濮陽女','不詳','唐','御定全唐诗','yuding','','[]','雁來書不至，月照獨眠房。賤妾多愁思，不堪秋夜長。',24,'御定全唐詩/json/027.json','["雁來書不至，月照獨眠房。賤妾多愁思，不堪秋夜長。"]'),
('yuding-97','雜曲歌辭：相府蓮','不詳','唐','御定全唐诗','yuding','','[]','夜聞鄰婦泣，切切有餘哀。即問緣何事，征人戰未回。',24,'御定全唐詩/json/027.json','["夜聞鄰婦泣，切切有餘哀。即問緣何事，征人戰未回。"]'),
('yuding-98','雜曲歌辭：簇拍相府蓮','不詳','唐','御定全唐诗','yuding','','[]','莫以今時寵，寧無舊日恩。看花滿眼淚，不共楚王言。',48,'御定全唐詩/json/027.json','["莫以今時寵，寧無舊日恩。看花滿眼淚，不共楚王言。", "閨燭無人影，羅屏有夢魂。近來音耗絕，終日望應門。"]'),
('yuding-99','雜曲歌辭：離別難','不詳','唐','御定全唐诗','yuding','','[]','此別難重陳，花深複變人。來時梅覆雪，去日柳含春。',48,'御定全唐詩/json/027.json','["此別難重陳，花深複變人。來時梅覆雪，去日柳含春。", "物候催行客，歸途淑氣新。剡川今已遠，魂夢暗相親。"]'),
('yuding-100','雜曲歌辭：離別難','白居易','唐','御定全唐诗','yuding','','[]','綠楊陌上送行人，馬去車回一望塵。',32,'御定全唐詩/json/027.json','["綠楊陌上送行人，馬去車回一望塵。", "不覺別時紅淚盡，歸來無淚可沾巾。"]'),
('yuding-101','雜曲歌辭：山鷓鴣','不詳','唐','御定全唐诗','yuding','','[]','玉關征戍久，空閨人獨愁。寒露濕青苔，別來蓬鬢秋。',48,'御定全唐詩/json/027.json','["玉關征戍久，空閨人獨愁。寒露濕青苔，別來蓬鬢秋。", "人坐青樓晚，鶯語百花時。愁人多自老，腸斷君不知。"]'),
('yuding-102','雜曲歌辭：鷓鴣詞','李益','唐','御定全唐诗','yuding','','[]','湘江斑竹枝，錦翼鷓鴣飛。處處湘陰合，郎從何處歸。',24,'御定全唐詩/json/027.json','["湘江斑竹枝，錦翼鷓鴣飛。處處湘陰合，郎從何處歸。"]'),
('yuding-103','雜曲歌辭：鷓鴣詞','李涉','唐','御定全唐诗','yuding','','[]','湘江煙水深，沙岸隔楓林。何處鷓鴣飛，日斜斑竹陰。',96,'御定全唐詩/json/027.json','["湘江煙水深，沙岸隔楓林。何處鷓鴣飛，日斜斑竹陰。", "二女虛垂淚，三閭枉自沉。惟有鷓鴣鳥，獨傷行客心。", "越岡連越井，越鳥更南飛。何處鷓鴣啼，夕煙東嶺歸。", "嶺頭行人少，天涯北客稀。鷓鴣啼別處，相對淚沾衣。"]'),
('yuding-104','雜曲歌辭：樂世','白居易','唐','御定全唐诗','yuding','','[]','管急絲繁拍漸稠，綠腰宛轉曲終頭。',32,'御定全唐詩/json/027.json','["管急絲繁拍漸稠，綠腰宛轉曲終頭。", "誠知樂世聲聲樂，老病人聽未免愁。"]'),
('yuding-105','雜曲歌辭：急樂世','白居易','唐','御定全唐诗','yuding','','[]','正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。',32,'御定全唐詩/json/027.json','["正抽碧線繡紅羅，忽聽黃鶯斂翠蛾。", "秋思冬愁春恨望，大都不得意時多。"]'),
('yuding-106','雜曲歌辭：何滿子','白居易','唐','御定全唐诗','yuding','','[]','世傳滿子是人名，臨就刑時曲始成。',32,'御定全唐詩/json/027.json','["世傳滿子是人名，臨就刑時曲始成。", "一曲四詞歌八疊，從頭便是斷腸聲。"]'),
('yuding-107','雜曲歌辭：何滿子','薛逢','唐','御定全唐诗','yuding','','[]','系馬宮槐老，持懷店菊黃。故交今不見，流恨滿川光。',24,'御定全唐詩/json/027.json','["系馬宮槐老，持懷店菊黃。故交今不見，流恨滿川光。"]'),
('yuding-108','雜曲歌辭：清平調','李白','唐','御定全唐诗','yuding','','[]','雲想衣裳花想容，春風拂檻露華濃。',96,'御定全唐詩/json/027.json','["雲想衣裳花想容，春風拂檻露華濃。", "若非群玉山頭見，會向瑤台月下逢。", "一枝紅豔露凝香，雲雨巫山枉斷腸。", "借問漢宮誰得似，可憐飛燕倚新妝。", "名花傾國兩相歡，長得君王帶笑看。", "解釋春風無限恨，沉香亭北倚闌幹。"]'),
('yuding-109','雜曲歌辭：回波樂','李景伯','唐','御定全唐诗','yuding','','[]','回波爾時酒卮，微臣職在箴規。',28,'御定全唐詩/json/027.json','["回波爾時酒卮，微臣職在箴規。", "侍宴既過三爵，喧嘩竊恐非儀。"]'),
('yuding-110','雜曲歌辭：聖明樂','張仲素','唐','御定全唐诗','yuding','','[]','玉帛殊方至，歌鐘比屋聞。華夷今一貫，同賀聖明君。',48,'御定全唐詩/json/027.json','["玉帛殊方至，歌鐘比屋聞。華夷今一貫，同賀聖明君。", "九陌祥煙合，千春瑞月明。宮花將苑柳，先發鳳凰城。"]'),
('yuding-111','雜曲歌辭：聖明樂','令狐楚','唐','御定全唐诗','yuding','','[]','海浪恬丹徼，邊塵靖黑山。從今萬里外，不復鎮蕭關。',24,'御定全唐詩/json/027.json','["海浪恬丹徼，邊塵靖黑山。從今萬里外，不復鎮蕭關。"]'),
('yuding-112','雜曲歌辭：大酺樂','不詳','唐','御定全唐诗','yuding','','[]','淚滴珠難盡，容殘玉易銷。儻隨明月去，莫道夢魂遙。',24,'御定全唐詩/json/027.json','["淚滴珠難盡，容殘玉易銷。儻隨明月去，莫道夢魂遙。"]'),
('yuding-113','雜曲歌辭：大酺樂','杜審言','唐','御定全唐诗','yuding','','[]','聖後乘幹日，皇明禦曆辰。紫宮初啟坐，蒼璧正臨春。',88,'御定全唐詩/json/027.json','["聖後乘幹日，皇明禦曆辰。紫宮初啟坐，蒼璧正臨春。", "雷雨垂膏澤，金錢賜下人。詔酺歡賞遍，交泰睹惟新。", "毗陵震澤九州通，士女歡娛萬國同。伐鼓撞鐘驚海上，", "大德不官逢道泰，天長地久屬年豐。"]'),
('yuding-114','雜曲歌辭：大酺樂','張祜','唐','御定全唐诗','yuding','','[]','車駕東來值太平，大酺三日洛陽城。',64,'御定全唐詩/json/027.json','["車駕東來值太平，大酺三日洛陽城。", "小兒一伎竿頭絕，天下傳呼萬歲聲。", "紫陌酺歸日欲斜，紅塵開路薛王家。", "雙鬟前說樓前鼓，兩伎爭輪好結花。"]'),
('yuding-115','雜曲歌辭：千秋樂','張祜','唐','御定全唐诗','yuding','','[]','八月平時花萼樓，萬方同樂奏千秋。',32,'御定全唐詩/json/027.json','["八月平時花萼樓，萬方同樂奏千秋。", "傾城人看長竿出，一伎初成趙解愁。"]'),
('yuding-116','雜曲歌辭：火鳳辭','李百藥','唐','御定全唐诗','yuding','','[]','歌聲扇裏出，妝影扇中輕。未能令掩笑，何處欲鄣聲。',96,'御定全唐詩/json/027.json','["歌聲扇裏出，妝影扇中輕。未能令掩笑，何處欲鄣聲。", "知音自不惑，得念是分明。莫見雙嚬斂，疑人含笑情。", "佳人靚晚妝，清唱動蘭房。影入含風扇，聲飛照日梁。", "嬌嚬眉際斂，逸韻口中香。自有橫陳分，應憐秋夜長。"]'),
('yuding-117','雜曲歌辭：熱戲樂','張祜','唐','御定全唐诗','yuding','','[]','熱戲爭心劇火燒，銅槌暗執不相饒。',32,'御定全唐詩/json/027.json','["熱戲爭心劇火燒，銅槌暗執不相饒。", "上皇失喜甯王笑，百尺幢竿果動搖。"]'),
('yuding-118','雜曲歌辭：春鶯囀','張祜','唐','御定全唐诗','yuding','','[]','興慶池南柳未開，太真先把一枝梅。',32,'御定全唐詩/json/027.json','["興慶池南柳未開，太真先把一枝梅。", "內人已唱春鶯囀，花下傞傞軟舞來。"]'),
('yuding-119','雜曲歌辭：達摩支','溫庭筠','唐','御定全唐诗','yuding','','[]','搗麝成塵香不滅，拗蓮作寸絲難絕。紅淚文姬洛水春，',48,'御定全唐詩/json/027.json','["搗麝成塵香不滅，拗蓮作寸絲難絕。紅淚文姬洛水春，", "舊臣頭鬢霜華早，可惜雄心醉中老。萬古春歸夢不歸，"]'),
('yuding-120','雜曲歌辭：如意娘','武則天','唐','御定全唐诗','yuding','','[]','看朱成碧思紛紛，憔悴支離為憶君。',32,'御定全唐詩/json/027.json','["看朱成碧思紛紛，憔悴支離為憶君。", "不信比來長下淚，開箱驗取石榴裙。"]'),
('yuding-121','雜曲歌辭：雨霖鈴','張祜','唐','御定全唐诗','yuding','','[]','雨霖鈴夜卻歸秦，猶是張徽一曲新。',32,'御定全唐詩/json/027.json','["雨霖鈴夜卻歸秦，猶是張徽一曲新。", "長說上皇垂淚教，月明南內更無人。"]'),
('yuding-122','雜曲歌辭：桂花曲','不詳','唐','御定全唐诗','yuding','','[]','可憐天上桂花孤，試問姮娥更要無。',32,'御定全唐詩/json/027.json','["可憐天上桂花孤，試問姮娥更要無。", "月宮幸有閒田地，何不中央種兩株。"]'),
('yuding-123','雜曲歌辭：渭城曲','王維','唐','御定全唐诗','yuding','','[]','渭城朝雨浥輕塵，客舍青青柳色春。',32,'御定全唐詩/json/027.json','["渭城朝雨浥輕塵，客舍青青柳色春。", "勸君更盡一杯酒，西出陽關無故人。"]'),
('yuding-0','雜曲歌辭：竹枝','顧況','唐','御定全唐诗','yuding','','[]','帝子蒼梧不復歸，洞庭葉下荊雲飛。',32,'御定全唐詩/json/028.json','["帝子蒼梧不復歸，洞庭葉下荊雲飛。", "巴人夜唱竹枝後，腸斷曉猿聲漸稀。"]'),
('yuding-1','雜曲歌辭：竹枝','劉禹錫','唐','御定全唐诗','yuding','','[]','白帝城頭春草生，白鹽山下蜀江清。',352,'御定全唐詩/json/028.json','["白帝城頭春草生，白鹽山下蜀江清。", "南人上來歌一曲，北人莫上動鄉情。", "山桃紅花滿上頭，蜀江春水拍江流。", "花紅易衰似郎意，水流無限似儂愁。", "江上朱樓新雨晴，瀼西春水縠文生。", "橋東橋西好楊柳，人來人去唱歌行。", "日出三竿春霧消，江頭蜀客駐蘭橈。", "憑寄狂夫書一紙，住在成都萬里橋。", "兩岸山花似雪開，家家春酒滿銀盃。", "昭君坊中多女伴，永安宮外踏青來。", "瞿塘嘈嘈十二灘，此中道路古來難。", "長恨人心不如水，等閒平地起波瀾。", "巫峽蒼蒼煙雨時，清猿啼在最高枝。", "個裏愁人腸自斷，由來不是此聲悲。", "城西門前灩澦堆，年年波浪不能摧。", "懊惱人心不如石，少時東去複西來。", "山上層層桃李花，雲間煙火是人家。", "銀釧金釵來負水，長刀短笠去燒畬。", "楊柳青青江水準，聞郎江上唱歌聲。", "東邊日出西邊雨，道是無情還有情。", "楚水巴山江雨多，巴人能唱本鄉歌。", "今朝北客思歸去，回入紇那披綠羅。"]'),
('yuding-2','雜曲歌辭：竹枝','白居易','唐','御定全唐诗','yuding','','[]','瞿塘峽口冷煙低，白帝城頭月向西。',128,'御定全唐詩/json/028.json','["瞿塘峽口冷煙低，白帝城頭月向西。", "唱到竹枝聲咽處，寒猿晴鳥一時啼。", "竹枝苦怨怨何人，夜靜山空歇又聞。", "蠻兒巴女齊聲唱，愁殺江樓病使君。", "巴東船舫上巴西，波面風生雨腳齊。", "水蓼冷花紅蔟蔟，江蘺濕葉碧萋萋。", "江畔誰人唱竹枝，前聲斷咽後聲遲。", "怪來調苦緣詞苦，多是通州司馬詩。"]'),
('yuding-3','雜曲歌辭：竹枝','李涉','唐','御定全唐诗','yuding','','[]','荊門灘急水潺潺，兩岸猿啼煙滿山。',128,'御定全唐詩/json/028.json','["荊門灘急水潺潺，兩岸猿啼煙滿山。", "渡頭年少應官去，月落西陵望不還。", "巫峽雲開神女祠，綠潭紅樹影參差。", "下牢戍口初相問，無義灘頭剩別離。", "石壁千重樹萬重，白雲斜掩碧芙蓉。", "昭君溪上年年月，獨自嬋娟色最濃。", "十二峰頭月欲低，空蒙江上子規啼。", "孤舟一夜東歸客，泣向春風憶建溪。"]'),
('yuding-4','雜曲歌辭：竹枝','孫光憲','唐','御定全唐诗','yuding','','[]','門前春水白蘋花，岸上無人小艇斜。',64,'御定全唐詩/json/028.json','["門前春水白蘋花，岸上無人小艇斜。", "商女經過江欲暮，散拋殘食飼神鴉。", "亂繩千結絆人深，越羅萬丈表長尋。", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('yuding-5','雜曲歌辭：楊柳枝','白居易','唐','御定全唐诗','yuding','','[]','一樹春風萬萬枝，嫩于金色軟於絲。',64,'御定全唐詩/json/028.json','["一樹春風萬萬枝，嫩于金色軟於絲。", "永豐西角荒園裏，盡日無人屬阿誰。", "一樹衰殘委泥土，雙枝榮耀植天庭。", "定知玄象今春後，柳宿光中添兩星。"]'),
('yuding-6','雜曲歌辭：楊柳枝','白居易','唐','御定全唐诗','yuding','','[]','六麼水調家家唱，白雪梅花處處吹。',256,'御定全唐詩/json/028.json','["六麼水調家家唱，白雪梅花處處吹。", "古歌舊曲君休聽，聽取新翻楊柳枝。", "陶令門前四五樹，亞夫營裏百千條。", "何似東都正二月，黃金枝映洛陽橋。", "依依嫋嫋複青青，勾引清風無限情。", "白雪花繁空撲地，綠絲條弱不勝鶯。", "紅板江橋青酒旗，館娃宮暖日斜時。", "可憐雨歇東風定，萬樹千條各自垂。", "蘇州楊柳任君誇，更有錢塘勝館娃。", "若解多情尋小小，綠楊深處是蘇家。", "蘇家小女舊知名，楊柳風前別有情。", "剝條盤作銀環樣，卷葉吹為玉笛聲。", "葉含濃露如啼眼，枝嫋輕風似舞腰。", "小樹不禁攀折苦，乞君留取兩三條。", "人言柳葉似愁眉，更有愁腸似柳絲。", "柳絲挽斷腸牽斷，彼此應無續得期。"]'),
('yuding-7','雜曲歌辭：楊柳枝','盧貞','唐','御定全唐诗','yuding','','[]','一樹依依在永豐，兩枝飛去杳無蹤。',32,'御定全唐詩/json/028.json','["一樹依依在永豐，兩枝飛去杳無蹤。", "玉皇曾采人間曲，應逐歌聲入九重。"]'),
('yuding-8','雜曲歌辭：楊柳枝','劉禹錫','唐','御定全唐诗','yuding','','[]','塞北梅花羌笛吹，淮南桂樹小山詞。',288,'御定全唐詩/json/028.json','["塞北梅花羌笛吹，淮南桂樹小山詞。", "請君莫奏前朝曲，聽唱新翻楊柳枝。", "南陌東城春早時，相逢何處不依依。", "桃紅李白皆誇好，須得垂楊相發輝。", "鳳闕輕遮翡翠帷，龍墀遙望曲塵絲。", "禦溝春水柳暉映，狂殺長安年少兒。", "金穀園中鶯亂飛，銅駝陌上好風吹。", "城東桃李須臾盡，爭似垂楊無限時。", "花萼樓前初種時，美人樓上鬥腰支。", "如今拋擲上街裏，露葉如啼欲恨誰。", "煬帝行宮汴水濱，數株殘柳不勝春。", "昨來風起花如雪，飛入宮牆不見人。", "禦陌青門拂地垂，千條金縷萬條絲。", "如今綰作同心結，將贈行人知不知。", "城外春風滿酒旗，行人揮袂日西時。", "長安陌上無窮樹，唯有垂楊管別離。", "輕盈嫋娜占春華，舞榭妝樓處處遮。", "春盡絮飛留不得，隨風好去落誰家。"]'),
('yuding-9','雜曲歌辭：楊柳枝','劉禹錫','唐','御定全唐诗','yuding','','[]','揚子江頭煙景迷，隋家宮樹拂金堤。',96,'御定全唐詩/json/028.json','["揚子江頭煙景迷，隋家宮樹拂金堤。", "嵯峨猶有當時色，半蘸波中水鳥棲。", "迎得春光先到來，淺黃輕綠映樓臺。", "只緣嫋娜多情思，便被春風長請挼。", "巫峽巫山楊柳多，朝雲暮雨遠相和。", "因想陽臺無限事，為君回唱竹枝歌。"]'),
('yuding-10','雜曲歌辭：楊柳枝','李商隱','唐','御定全唐诗','yuding','','[]','暫憑樽酒送無憀，莫損愁眉與細腰。',64,'御定全唐詩/json/028.json','["暫憑樽酒送無憀，莫損愁眉與細腰。", "人世死前唯有別，春風爭擬惜長條。", "含煙惹霧每依依，萬緒千條拂落暉。", "為報行人休盡折，半留相送半迎歸。"]'),
('yuding-11','雜曲歌辭：楊柳枝','韓琮','唐','御定全唐诗','yuding','','[]','梁苑隋堤事已空，萬條猶舞舊春風。',32,'御定全唐詩/json/028.json','["梁苑隋堤事已空，萬條猶舞舊春風。", "那堪更想千年後，誰見楊花入漢宮。"]'),
('yuding-12','雜曲歌辭：楊柳枝','施肩吾','唐','御定全唐诗','yuding','','[]','傷見路傍楊柳春，一枝折盡一重新。',32,'御定全唐詩/json/028.json','["傷見路傍楊柳春，一枝折盡一重新。", "今年還折去年處，不送去年離別人。"]'),
('yuding-13','雜曲歌辭：楊柳枝','溫庭筠','唐','御定全唐诗','yuding','','[]','宜春苑外最長條，閑嫋春風伴舞腰。',256,'御定全唐詩/json/028.json','["宜春苑外最長條，閑嫋春風伴舞腰。", "正是玉人腸斷處，一渠春水赤欄橋。", "南內牆東禦路傍，預知春色柳絲黃。", "杏花未肯無情思，何事情人最斷腸。", "蘇小門前柳萬條，毿毿金線拂平橋。", "黃鶯不語東風起，深閉朱門伴細腰。", "金縷毿毿碧瓦溝，六宮眉黛惹春愁。", "晚來更帶龍池雨，半拂欄幹半入樓。", "館娃宮外鄴城西，遠映征帆近拂堤。", "系得王孫歸意切，不關春草綠萋萋。", "兩兩黃鸝色似金，嫋枝啼露動芳音。", "春來幸自長如線，可惜牽纏蕩子心。", "禦柳如絲映九重，鳳凰窗柱繡芙蓉。", "景陽樓伴千條露，一面新妝待曉鐘。", "織錦機邊鶯語頻，停梭垂淚憶征人。", "塞門三月猶蕭索，縱有垂楊未覺春。"]'),
('yuding-14','雜曲歌辭：楊柳枝','皇甫松','唐','御定全唐诗','yuding','','[]','春入行宮映翠微，玄宗侍女舞煙絲。',64,'御定全唐詩/json/028.json','["春入行宮映翠微，玄宗侍女舞煙絲。", "如今柳向空城綠，玉笛何人更把吹。", "爛熳春歸水國時，吳王宮殿柳垂絲。", "黃鶯長叫空閨畔，西子無因更得知。"]'),
('yuding-15','雜曲歌辭：楊柳枝','齊己','唐','御定全唐诗','yuding','','[]','鳳樓高映綠陰陰，凝碧多含雨露深。',128,'御定全唐詩/json/028.json','["鳳樓高映綠陰陰，凝碧多含雨露深。", "莫謂一枝柔軟力，幾曾牽破別離心。", "館娃宮畔響廊前，依託吳王養翠煙。", "劍去國亡台榭毀，卻隨紅樹噪秋蟬。", "濃低似中陶潛酒，軟極如傷宋玉風。", "多謝將軍繞營種，翠中閑卓戰旗紅。", "高僧愛惜遮江寺，遊子傷殘露野橋。", "爭似著行垂上苑，碧桃紅杏對搖搖。"]'),
('yuding-16','雜曲歌辭：楊柳枝','張祜','唐','御定全唐诗','yuding','','[]','莫折宮前楊柳枝，玄宗曾向笛中吹。',64,'御定全唐詩/json/028.json','["莫折宮前楊柳枝，玄宗曾向笛中吹。", "傷心日暮煙霞起，無限春愁生翠眉。", "凝碧池邊斂翠眉，景陽臺下綰青絲。", "那勝妃子朝元閣，玉手和煙弄一枝。"]'),
('yuding-17','雜曲歌辭：楊柳枝','孫魴','唐','御定全唐诗','yuding','','[]','靈和風暖太昌春，舞線搖絲向昔人。',160,'御定全唐詩/json/028.json','["靈和風暖太昌春，舞線搖絲向昔人。", "何似曉來江雨後，一行如畫隔遙津。", "彭澤初栽五樹時，只應閑看一枝枝。", "不知天意風流處，要與佳人學畫眉。", "暖傍離亭靜拂橋，入流穿檻綠搖搖。", "不知落日誰相送，魂斷千條與萬條。", "春來綠樹遍天涯，未見垂楊未可誇。", "晴日萬株煙一陣，閑坊兼是莫愁家。", "十首當年有舊詞，唱青歌翠幾無遺。", "未曾得向行人道，不為離情莫折伊。"]'),
('yuding-18','雜曲歌辭：楊柳枝','薛能','唐','御定全唐诗','yuding','','[]','華清高樹出離宮，南陌柔條帶暖風。',384,'御定全唐詩/json/028.json','["華清高樹出離宮，南陌柔條帶暖風。", "誰風輕陰是良夜，瀑泉聲畔月明中。", "洛橋晴影覆江船，羌笛秋聲濕塞煙。", "閑想習池公宴罷，水蒲風絮夕陽天。", "嫩綠輕懸似綴旒，路人遙見隔宮樓。", "誰能更近丹墀種，解播皇風入九州。", "暖風晴日斷浮埃，廢路新條發釣台。", "處處輕輕可惆悵，後人攀處古人栽。", "潭上江邊嫋嫋垂，日高風靜絮相隨。", "青樓一樹無人見，正是女郎眠覺時。", "汴水高懸百萬條，風清兩岸一時搖。", "隋家力盡虛栽得，無限春風屬聖朝。", "和花煙樹九重城，夾路春陰十萬營。", "唯向邊頭不堪望，一株憔悴少人行。", "窗外齊垂旭日初，樓邊輕好暖風徐。", "遊人莫道栽無益，桃李清陰卻不如。", "眾木猶寒獨早青，禦溝橋畔曲江亭。", "陶家舊日應如此，一院春條綠繞廳。", "帳偃纓垂細複繁，令人心想石家園。", "風條月影皆堪重，何事侯門愛樹萱。", "數首新詞帶恨成，柳絲牽我我傷情。", "柔娥幸有腰支穩，試踏吹聲作唱聲。", "高出軍營遠映橋，賊兵曾斫火曾燒。", "風流性在終難改，依舊春來萬萬條。"]'),
('yuding-19','雜曲歌辭：楊柳枝','牛嶠','唐','御定全唐诗','yuding','','[]','解凍風來末上青，解垂羅袖拜卿卿。',160,'御定全唐詩/json/028.json','["解凍風來末上青，解垂羅袖拜卿卿。", "無端嫋娜臨官路，舞送行人過一生。", "吳王宮裏色偏深，一簇纖條萬縷金。", "不憤錢塘蘇小小，引郎枝下結同心。", "橋北橋南千萬條，恨伊張緒不相饒。", "金羈白馬臨風望，認得羊家靜婉腰。", "狂雪隨風撲馬飛，惹煙無力被風欹。", "莫交移入靈和殿，宮女三千又妒伊。", "嫋翠籠煙拂暖波，舞裙新染曲塵羅。", "章華台畔隋堤上，倚得春風爾許多。"]'),
('yuding-20','雜曲歌辭：楊柳枝','和凝','唐','御定全唐诗','yuding','','[]','軟碧搖煙似送人，映花時把翠眉顰。',96,'御定全唐詩/json/028.json','["軟碧搖煙似送人，映花時把翠眉顰。", "青青自是風流主，漫颭金絲待洛神。", "瑟瑟羅裙金縷腰，黛眉偎破未重描。", "醉來咬損新花子，拽住仙郎盡放嬌。", "鵲橋初就咽銀河，今夜仙郎自性和。", "不是昔年攀桂樹，豈能月裏索姮娥。"]'),
('yuding-21','雜曲歌辭：楊柳枝','孫光憲','唐','御定全唐诗','yuding','','[]','閭門風暖落花幹，飛遍江南雪不寒。',128,'御定全唐詩/json/028.json','["閭門風暖落花幹，飛遍江南雪不寒。", "獨有晚來臨水驛，閒人多憑赤闌幹。", "有池有榭即濛濛，浸潤翻成長養功。", "恰似有人長點檢，著行排立向春風。", "根柢雖然傍濁河，無妨終日近笙歌。", "驂驂金帶誰堪比，還笑黃鶯不較多。", "萬株枯槁怨亡隋，似吊吳台各自垂。", "好是淮陰明月裏，酒樓橫笛不勝吹。"]'),
('yuding-22','雜曲歌辭：浪淘沙','劉禹錫','唐','御定全唐诗','yuding','','[]','九曲黃河萬里沙，浪淘幾簸自天涯。',288,'御定全唐詩/json/028.json','["九曲黃河萬里沙，浪淘幾簸自天涯。", "如今直上銀河去，同到牽牛織女家。", "洛水橋邊春日斜，碧流輕淺見瓊沙。", "無端陌上狂風急，驚起鴛鴦出浪花。", "汴水東流虎眼文，清淮曉色鴨頭春。", "君看渡口淘沙處，渡卻人間多少人。", "鸚鵡洲頭浪颭沙，青樓春望日將斜。", "銜泥燕子爭歸舍，獨自狂夫不憶家。", "濯錦江邊兩岸花，春風吹浪正淘沙。", "女郎剪下鴛鴦錦，將向中流匹晚霞。", "日照澄洲江霧開，淘金女伴滿江隈。", "美人首飾侯王印，儘是沙中浪底來。", "八月濤聲吼地來，頭高數丈觸山回。", "須臾卻入海門去，卷起沙堆似雪堆。", "莫道讒言如浪深，莫言遷客似沙沉。", "千淘萬漉雖辛苦，吹盡狂沙始到金。", "流水淘沙不暫停，前波未滅後波生。", "令人忽憶瀟湘渚，回唱迎神三兩聲。"]'),
('yuding-23','雜曲歌辭：浪淘沙','白居易','唐','御定全唐诗','yuding','','[]','一泊沙來一泊去，一重浪滅一重生。',192,'御定全唐詩/json/028.json','["一泊沙來一泊去，一重浪滅一重生。", "相攪相淘無歇日，會交山海一時平。", "白浪茫茫與海連，平沙浩浩四無邊。", "暮去朝來淘不住，遂令東海變桑田。", "青草湖中萬里程，黃梅雨裏一人行。", "愁見灘頭夜泊處，風翻暗浪打船聲。", "借問江湖與海水，何似君情與妾心。", "相恨不如潮有信，相思始覺海非深。", "海底飛塵終有日，山頭化石豈無時。", "誰道小郎拋小婦，船頭一去沒回期。", "隨波逐浪到天涯，遷客生還有幾家。", "卻到帝鄉重富貴，請君莫忘浪淘沙。"]'),
('yuding-24','雜曲歌辭：浪淘沙','皇甫松','唐','御定全唐诗','yuding','','[]','灘頭細草接疏林，浪惡罾船半欲沉。',64,'御定全唐詩/json/028.json','["灘頭細草接疏林，浪惡罾船半欲沉。", "宿鷺眠洲非舊浦，去年沙觜是江心。", "蠻歌豆蔻北人愁，松雨蒲風夜艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。"]'),
('yuding-25','雜曲歌辭：紇那曲','劉禹錫','唐','御定全唐诗','yuding','','[]','楊柳鬱青青，竹枝無限情。同郎一回顧，聽唱紇那聲。',48,'御定全唐詩/json/028.json','["楊柳鬱青青，竹枝無限情。同郎一回顧，聽唱紇那聲。", "踏曲興無窮，調同詞不同。願郎千萬壽，長作主人翁。"]'),
('yuding-26','雜曲歌辭：瀟湘神二曲','劉禹錫','唐','御定全唐诗','yuding','','[]','湘水流，湘水流，九疑雲物至今愁。君問二妃何處所，',48,'御定全唐詩/json/028.json','["湘水流，湘水流，九疑雲物至今愁。君問二妃何處所，", "斑竹枝，斑竹枝，淚痕點點寄相思。楚客欲聽瑤瑟怨，"]'),
('yuding-27','雜曲歌辭：拋球樂','劉禹錫','唐','御定全唐诗','yuding','','[]','五彩繡團團，登君玳瑁筵。最宜紅燭下，偏稱落花前。',72,'御定全唐詩/json/028.json','["五彩繡團團，登君玳瑁筵。最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。", "春早見花枝，朝朝恨發遲。及看花落後，卻憶未開時。", "幸有拋球樂，一杯君莫辭。"]'),
('yuding-28','雜曲歌辭：太平樂','白居易','唐','御定全唐诗','yuding','','[]','歲豐仍節儉，時泰更銷兵。聖念長如此，何憂不太平。',48,'御定全唐詩/json/028.json','["歲豐仍節儉，時泰更銷兵。聖念長如此，何憂不太平。", "湛露浮堯酒，熏風起舜歌。願同堯舜意，所樂在人和。"]'),
('yuding-29','雜曲歌辭：太平樂','王涯','唐','御定全唐诗','yuding','','[]','風俗今和厚，君王在穆清。行看采花曲，儘是太階平。',24,'御定全唐詩/json/028.json','["風俗今和厚，君王在穆清。行看采花曲，儘是太階平。"]'),
('yuding-30','雜曲歌辭：太平樂','張仲素','唐','御定全唐诗','yuding','','[]','聖德超千古，皇威靜四方。蒼生今息戰，無事覺時長。',24,'御定全唐詩/json/028.json','["聖德超千古，皇威靜四方。蒼生今息戰，無事覺時長。"]'),
('yuding-31','雜曲歌辭：升平樂','薛能','唐','御定全唐诗','yuding','','[]','正氣繞宮樓，皇居信上游。遠岡延聖祚，平地載神州。',480,'御定全唐詩/json/028.json','["正氣繞宮樓，皇居信上游。遠岡延聖祚，平地載神州。", "會合皆重譯，潺湲近八流。中興豈假問，據此自千秋。", "寥泬敞延英，朝班立位橫。宣傳無草動，拜舞有衣聲。", "鴛瓦雲消濕，蟲絲日照明。辛勤自不到，遙見似前生。", "處處足歡聲，時康歲已深。不同三尺劍，應似五弦琴。", "壽笑山猶盡，明嫌日有陰。何當憐一物，亦遣斷愁吟。", "曙質絕埃氛，彤庭列禁軍。聖顏初對日，龍尾競緣雲。", "佩響交成韻，簾陰暖帶紋。逍遙豈有事，于此詠南熏。", "一物周天至，洪纖盡晏然。車書無異俗，甲子並豐年。", "奇技皆歸樸，征夫亦服田。君王故不有，台鼎合韋弦。", "日日聽歌謠，區中盡祝堯。蟲蝗初不害，夷狄近全銷。", "史筆唯書瑞，天臺絕見祆。因令匹夫志，轉欲事清朝。", "品物盡昭蘇，神功複帝謨。他時應有壽，當代且無虞。", "賜曆通遐俗，移關入半胡。鷦鷯一何幸，於此寄微軀。", "無戰複無私，堯時即此時。焚香臨極早，待月捲簾遲。", "端拱乾坤內，何言黈纊垂。君看聖明驗，只此是神龜。", "旭日上清穹，明堂坐聖聰。衣裳承瑞氣，冠冕蓋重瞳。", "花木經宵露，旌旗立仗風。何期於此地，見說似仙宮。", "五帝三皇主，蕭曹魏邴臣。文章惟反朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。升平不可紀，所見是閒人。"]'),
('yuding-32','雜曲歌辭：金縷衣','不詳','唐','御定全唐诗','yuding','','[]','勸君莫惜金縷衣，勸君惜取少年時。',32,'御定全唐詩/json/028.json','["勸君莫惜金縷衣，勸君惜取少年時。", "花開堪折直須折，莫待無花空折枝。"]'),
('yuding-33','雜曲歌辭：鳳歸雲','滕潛','唐','御定全唐诗','yuding','','[]','金井欄邊見羽儀，梧桐樹上宿寒枝。',64,'御定全唐詩/json/028.json','["金井欄邊見羽儀，梧桐樹上宿寒枝。", "五陵公子憐文彩，畫與佳人刺繡衣。", "飲啄蓬山最上頭，和煙飛下禁城秋。", "曾將弄玉歸雲去，金翿斜開十二樓。"]'),
('yuding-34','雜曲歌辭：拜新月','李端','唐','御定全唐诗','yuding','','[]','開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。',24,'御定全唐詩/json/028.json','["開簾見新月，便即下階拜。細語人不聞，北風吹裙帶。"]'),
('yuding-35','雜曲歌辭：拜新月','吉中孚妻','唐','御定全唐诗','yuding','','[]','拜新月，拜月出堂前，暗魄深籠桂，虛弓未引弦。',90,'御定全唐詩/json/028.json','["拜新月，拜月出堂前，暗魄深籠桂，虛弓未引弦。", "拜新月，拜月妝樓上，鸞鏡未安台，蛾眉已相向。", "拜新月，拜月不勝情，庭前風露清，月臨人自老，", "昔年拜月逞容儀，如今拜月雙淚垂。回看眾女拜新月，"]'),
('yuding-36','雜曲歌辭：憶江南','白居易','唐','御定全唐诗','yuding','','[]','江南好，風景舊曾諳。日出江花紅勝火，',54,'御定全唐詩/json/028.json','["江南好，風景舊曾諳。日出江花紅勝火，", "江南憶，最憶是杭州。山寺月中尋桂子，", "江南憶，其次憶吳宮。吳酒一杯春竹葉，"]'),
('yuding-37','雜曲歌辭：憶江南','劉禹錫','唐','御定全唐诗','yuding','','[]','春過也，共惜豔陽年。猶有桃花流水上，',36,'御定全唐詩/json/028.json','["春過也，共惜豔陽年。猶有桃花流水上，", "春去也，多謝洛城人。弱柳從風疑舉袂，"]'),
('yuding-38','雜曲歌辭：宮中調笑','王建','唐','御定全唐诗','yuding','','[]','團扇，團扇，美人病來遮面。玉顏憔悴三年，',80,'御定全唐詩/json/028.json','["團扇，團扇，美人病來遮面。玉顏憔悴三年，", "蝴蝶，蝴蝶，飛上金花枝葉。君前對舞春風，", "羅袖，羅袖，暗舞春風依舊。遙看歌舞玉樓，", "楊柳，楊柳，日暮白沙渡口。船頭江水茫茫，"]'),
('yuding-39','雜曲歌辭：宮中調笑','韋應物','唐','御定全唐诗','yuding','','[]','胡馬，胡馬，遠放燕支山下。咆沙咆雪獨嘶，',40,'御定全唐詩/json/028.json','["胡馬，胡馬，遠放燕支山下。咆沙咆雪獨嘶，", "河漢，河漢，曉掛秋城漫漫。愁人起望相思，"]'),
('yuding-40','雜曲歌辭：轉應詞','戴叔倫','唐','御定全唐诗','yuding','','[]','邊草，邊草，邊草盡來兵老。山南山北雪晴，',20,'御定全唐詩/json/028.json','["邊草，邊草，邊草盡來兵老。山南山北雪晴，"]'),
('yuding-41','雜曲歌辭：宮中行樂詞','李白','唐','御定全唐诗','yuding','','[]','小小生金屋，盈盈在紫微。山花插寶髻，石竹繡羅衣。',384,'御定全唐詩/json/028.json','["小小生金屋，盈盈在紫微。山花插寶髻，石竹繡羅衣。", "每出深宮裏，常隨步輦歸。只愁歌舞散，化作彩雲飛。", "柳色黃金嫩，梨花白雪香。玉樓巢翡翠，金殿鎖鴛鴦。", "選妓隨雕輦，征歌出洞房。宮中誰第一，飛燕在昭陽。", "盧橘為秦樹，蒲萄出漢宮。煙花宜落日，絲管醉春風。", "笛奏龍鳴水，簫吟鳳下空。君王多樂事，何必向回中。", "玉樹春歸日，金宮樂事多。後庭朝未入，輕輦夜相過。", "笑出花間語，嬌來燭下歌。莫教明月去，留著醉姮娥。", "繡戶香風暖，紗窗曙色新。宮花爭笑日，池草暗生春。", "綠樹聞歌鳥，青樓見舞人。昭陽桃李月，羅綺自相親。", "今日明光裏，還須結伴遊。春風開紫殿，天樂下珠樓。", "豔舞全知巧，嬌歌半欲羞。更憐花月夜，宮女笑藏鉤。", "寒雪梅中盡，春風柳上歸。宮鶯嬌欲醉，簷燕語還飛。", "遲日明歌席，新花豔舞衣。晚來移彩仗，行樂泥光輝。", "水綠南熏殿，花紅北闕樓。鶯歌聞太液，鳳吹繞瀛洲。", "素女鳴珠佩，天人弄彩球。今朝風日好，宜入未央遊。"]'),
('yuding-42','雜曲歌辭：宮中樂','令狐楚','唐','御定全唐诗','yuding','','[]','楚塞金陵靜，巴山玉壘空。萬方無一事，端拱大明宮。',120,'御定全唐詩/json/028.json','["楚塞金陵靜，巴山玉壘空。萬方無一事，端拱大明宮。", "霜霽長楊苑，冰開太液池。宮中行樂日，天下盛明時。", "柳色煙相似，梨花雪不如。春風真有意，一一麗皇居。", "月上宮花靜，煙含苑樹深。銀台門已閉，仙漏夜沉沉。", "九重青鎖闥，百尺碧雲樓。明月秋風起，珠簾上玉鉤。"]'),
('yuding-43','雜曲歌辭：宮中樂','張仲素','唐','御定全唐诗','yuding','','[]','網戶交如綺，紗窗薄似煙。樂吹天上曲，人是月中仙。',120,'御定全唐詩/json/028.json','["網戶交如綺，紗窗薄似煙。樂吹天上曲，人是月中仙。", "翠匣開寒鏡，珠釵掛步搖。妝成隻畏曉，更漏促春宵。", "江果瑤池實，金盤露井冰。甘泉將避暑，台殿曉光凝。", "月彩浮鸞殿，砧聲隔鳳樓。笙歌臨水檻，紅燭乍迎秋。", "奇樹留寒翠，神池結夕波。黃山一夜雪，渭水雁聲多。"]'),
('yuding-44','雜曲歌辭：踏歌詞','崔液','唐','御定全唐诗','yuding','','[]','彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠帖花黃。',72,'御定全唐詩/json/028.json','["彩女迎金屋，仙姬出畫堂。鴛鴦裁錦袖，翡翠帖花黃。", "歌響舞分行，豔色動流光。", "庭際花微落，樓前漢已橫。金壺催夜盡，羅袖拂寒輕。", "樂笑暢歡情，未半著天明。"]'),
('yuding-45','雜曲歌辭：踏歌詞','謝偃','唐','御定全唐诗','yuding','','[]','春景嬌春台，新露泣新梅。春葉參差吐，新花重疊開。',144,'御定全唐詩/json/028.json','["春景嬌春台，新露泣新梅。春葉參差吐，新花重疊開。", "花影飛鶯去，歌聲度鳥來。倩看飄颻雪，何如舞袖回。", "逶迤度香閣，顧步出蘭閨。欲繞鴛鴦殿，先過桃李蹊。", "風帶舒還卷，簪花舉複低。欲問今宵樂，但聽歌聲齊。", "夜久星沉沒，更深月影斜。裙輕才動佩，鬟薄不勝花。", "細風吹寶襪，輕露濕紅紗。相看樂未已，蘭燈照九華。"]'),
('yuding-46','雜曲歌辭：踏歌詞','張說','唐','御定全唐诗','yuding','','[]','花萼樓前雨露新，長安城裏太平人。',64,'御定全唐詩/json/028.json','["花萼樓前雨露新，長安城裏太平人。", "龍銜火樹千燈豔，雞踏蓮花萬歲春。", "帝宮三五戲春台，行雨流風莫妒來。", "西域燈輪千影合，東華金闕萬重開。"]'),
('yuding-47','雜曲歌辭：踏歌行','劉禹錫','唐','御定全唐诗','yuding','','[]','春江月出大堤平，堤上女郎連袂行。',128,'御定全唐詩/json/028.json','["春江月出大堤平，堤上女郎連袂行。", "唱盡新詞看不見，紅霞影樹鷓鴣鳴。", "桃蹊柳陌好經過，燈下妝成月下歌。", "為是襄王故宮地，至今猶自細腰多。", "新詞宛轉遞相傳，振袖傾鬟風露前。", "月落烏啼雲雨散，游童陌上拾花鈿。", "日暮江頭聞竹枝，南人行樂北人悲。", "自從雪裏唱新曲，直至三春花盡時。"]'),
('yuding-48','雜曲歌辭：天長地久詞','盧綸','唐','御定全唐诗','yuding','','[]','玉砌紅花樹，香風不敢吹。春光解天意，偏發殿南枝。',136,'御定全唐詩/json/028.json','["玉砌紅花樹，香風不敢吹。春光解天意，偏發殿南枝。", "虹橋千步廊，半在水中央。天子方清暑，宮人重暮妝。", "辭輦複當熊，傾心奉上宮。君王若看貌，甘在眾妃中。", "雲日呈祥禮物殊，北庭生獻五單于。", "塞天萬里無飛鳥，可在邊城用郅都。", "台殿雲涼風日微，君王初賜六宮衣。", "樓船罷泛歸猶早，行道才人鬥射飛。"]'),
('yuding-49','雜曲歌辭：欸乃曲','元結','唐','御定全唐诗','yuding','','[]','偏存名跡在人間，順俗與時未安閒。',160,'御定全唐詩/json/028.json','["偏存名跡在人間，順俗與時未安閒。", "來謁大官兼問政，扁舟卻入九疑山。", "湘江二月春水準，滿月和風宜夜行。", "唱橈欲過平陽戍，守吏相呼問姓名。", "千里楓林煙雨深，無朝無暮有猿吟。", "停橈靜聽曲中意，好是雲山韶濩音。", "零陵郡北湘水東，浯溪形勝滿湘中。", "溪口石顛堪自逸，誰能相伴作漁翁。", "下瀧船似入深淵，上瀧船似欲升天。", "瀧南始到九疑郡，應絕高人乘興船。"]'),
('yuding-50','雜曲歌辭：十二月樂辭：正月','李賀','唐','御定全唐诗','yuding','','[]','上樓迎春新春歸，暗黃著柳宮漏遲。薄薄淡靄弄野姿，',40,'御定全唐詩/json/028.json','["上樓迎春新春歸，暗黃著柳宮漏遲。薄薄淡靄弄野姿，", "官街柳帶不堪折，早晚菖蒲勝綰結。"]'),
('yuding-51','雜曲歌辭：十二月樂辭：二月','李賀','唐','御定全唐诗','yuding','','[]','二月飲酒采桑津，宜男草生蘭笑人。蒲如交劍風如熏，',24,'御定全唐詩/json/028.json','["二月飲酒采桑津，宜男草生蘭笑人。蒲如交劍風如熏，"]'),
('yuding-52','雜曲歌辭：十二月樂辭：三月','李賀','唐','御定全唐诗','yuding','','[]','東方風來滿眼春，花城柳暗愁幾人。複宮深殿竹風起，',48,'御定全唐詩/json/028.json','["東方風來滿眼春，花城柳暗愁幾人。複宮深殿竹風起，", "軍裝宮妓掃蛾淺，搖搖錦旗夾城暖。曲水飄香去不歸，"]'),
('yuding-53','雜曲歌辭：十二月樂辭：四月','李賀','唐','御定全唐诗','yuding','','[]','曉涼暮涼樹如蓋，千山濃綠生雲外。依微香雨青氛氳，',24,'御定全唐詩/json/028.json','["曉涼暮涼樹如蓋，千山濃綠生雲外。依微香雨青氛氳，"]'),
('yuding-54','雜曲歌辭：十二月樂辭：五月','李賀','唐','御定全唐诗','yuding','','[]','雕玉押簾上，輕縠籠虛門。井汲鉛華水，扇織鴛鴦文。',48,'御定全唐詩/json/028.json','["雕玉押簾上，輕縠籠虛門。井汲鉛華水，扇織鴛鴦文。", "回雪舞涼殿，甘露洗空綠。羅袖從徊翔，香汗沾寶粟。"]'),
('yuding-55','雜曲歌辭：十二月樂辭：六月','李賀','唐','御定全唐诗','yuding','','[]','裁生羅，伐湘竹，帔拂疏霜簟秋玉。炎炎紅鏡東方開，',24,'御定全唐詩/json/028.json','["裁生羅，伐湘竹，帔拂疏霜簟秋玉。炎炎紅鏡東方開，"]'),
('yuding-56','雜曲歌辭：十二月樂辭：七月','李賀','唐','御定全唐诗','yuding','','[]','星依雲渚冷，露滴盤中圓。好花生木末，衰蕙愁空園。',60,'御定全唐詩/json/028.json','["星依雲渚冷，露滴盤中圓。好花生木末，衰蕙愁空園。", "夜天如玉砌，池葉極青錢。僅厭舞衫薄，稍知花簟寒。", "曉風何拂拂，北斗光闌幹。"]'),
('yuding-57','雜曲歌辭：十二月樂辭：八月','李賀','唐','御定全唐诗','yuding','','[]','孀妾怨長夜，獨客夢歸家。傍簷蟲緝絲，向壁燈垂花。',48,'御定全唐詩/json/028.json','["孀妾怨長夜，獨客夢歸家。傍簷蟲緝絲，向壁燈垂花。", "簷外月光吐，簾中樹影斜。悠悠飛露姿，點綴池中荷。"]'),
('yuding-58','雜曲歌辭：十二月樂辭：九月','李賀','唐','御定全唐诗','yuding','','[]','離宮散螢天似水，竹黃池冷芙蓉死。月綴金鋪光脈脈，',40,'御定全唐詩/json/028.json','["離宮散螢天似水，竹黃池冷芙蓉死。月綴金鋪光脈脈，", "雞人罷唱曉瓏璁，鴉啼金井下疏桐。"]'),
('yuding-59','雜曲歌辭：十二月樂辭：十月','李賀','唐','御定全唐诗','yuding','','[]','玉壺銀箭稍難傾，釭花夜笑凝幽明。碎霜斜舞上羅幕，',24,'御定全唐詩/json/028.json','["玉壺銀箭稍難傾，釭花夜笑凝幽明。碎霜斜舞上羅幕，"]'),
('yuding-60','雜曲歌辭：十二月樂辭：十一月','李賀','唐','御定全唐诗','yuding','','[]','宮城團回凜嚴光，白天碎碎墮瓊芳。撾鐘高飲千日酒，',24,'御定全唐詩/json/028.json','["宮城團回凜嚴光，白天碎碎墮瓊芳。撾鐘高飲千日酒，"]'),
('yuding-61','雜曲歌辭：十二月樂辭：十二月','李賀','唐','御定全唐诗','yuding','','[]','日腳淡光紅灑灑，薄霜不銷桂枝下。',32,'御定全唐詩/json/028.json','["日腳淡光紅灑灑，薄霜不銷桂枝下。", "依稀和氣解冬嚴，已就長日辭長夜。"]'),
('yuding-62','雜曲歌辭：十二月樂辭：閏月','李賀','唐','御定全唐诗','yuding','','[]','帝重光，年重時，七十二候回環推。天官玉管灰剩飛，',24,'御定全唐詩/json/028.json','["帝重光，年重時，七十二候回環推。天官玉管灰剩飛，"]'),
('yuding-63','雜曲歌辭：桃花行','李嶠','唐','御定全唐诗','yuding','','[]','歲去無言忽憔悴，時來含笑吐氛氳。',32,'御定全唐詩/json/028.json','["歲去無言忽憔悴，時來含笑吐氛氳。", "不能擁路迷仙客，故欲開蹊侍聖君。"]'),
('yuding-64','雜曲歌辭：桃花行','李乂','唐','御定全唐诗','yuding','','[]','綺萼成蹊遍籞芳，紅英撲地滿筵香。',32,'御定全唐詩/json/028.json','["綺萼成蹊遍籞芳，紅英撲地滿筵香。", "莫將秋宴傳王母，來比春華壽聖皇。"]'),
('yuding-65','雜曲歌辭：桃花行','徐彥伯','唐','御定全唐诗','yuding','','[]','源水叢花無數開，丹跗紅萼間青梅。',32,'御定全唐詩/json/028.json','["源水叢花無數開，丹跗紅萼間青梅。", "從今結子三千歲，預喜仙遊複摘來。"]'),
('yuding-66','雜曲歌辭：桃花行','蘇頲','唐','御定全唐诗','yuding','','[]','桃花灼灼有光輝，無數成蹊點更飛。',32,'御定全唐詩/json/028.json','["桃花灼灼有光輝，無數成蹊點更飛。", "為見芳林含笑待，遂同溫樹不言歸。"]'),
('yuding-67','雜曲歌辭：桃花行','趙彥昭','唐','御定全唐诗','yuding','','[]','紅萼競妍春苑曙，粉茸新向禦筵開。',32,'御定全唐詩/json/028.json','["紅萼競妍春苑曙，粉茸新向禦筵開。", "長年願奉西王宴，近侍慚無東朔才。"]'),
('yuding-68','雜曲歌辭：蘇摩遮','張說','唐','御定全唐诗','yuding','','[]','摩遮本出海西胡，琉璃寶服紫髯胡。',160,'御定全唐詩/json/028.json','["摩遮本出海西胡，琉璃寶服紫髯胡。", "聞道皇恩遍宇宙，來時歌舞助歡娛。", "繡裝帕額寶花冠，夷歌騎舞借人看。", "自能激水成陰氣，不慮今年寒不寒。", "臘月凝陰積帝台，豪歌擊鼓送寒來。", "油囊取得天河水，將添上壽萬年杯。", "寒氣宜人最可憐，故將寒水散庭前。", "惟願聖君無限壽，長取新年續舊年。", "昭成皇后帝家親，榮樂諸人不比倫。", "往日霜前花委地，今年雪後樹逢春。"]'),
('yuding-69','雜曲歌辭：舞馬詞','張說','唐','御定全唐诗','yuding','','[]','萬玉朝宗鳳扆，千金率領龍媒。',168,'御定全唐詩/json/028.json','["萬玉朝宗鳳扆，千金率領龍媒。", "眄鼓凝驕躞蹀，聽歌弄影徘徊。", "天祿遙征衛叔，日龍上借羲和。", "將共兩驂爭舞，來隨八駿齊歌。", "彩旄八佾成行，時龍五色因方。", "屈膝銜杯赴節，傾心獻壽無疆。", "帝皂龍駒沛艾，星蘭驥子權奇。", "騰倚驤洋應節，繁驕接跡不移。", "二聖先天合德，群靈率土可封。", "擊石驂驔紫燕，摐金顧步蒼龍。", "聖君出震應籙，神馬浮河獻圖。", "足踏天庭鼓舞，心將帝樂踟躊。"]'),
('yuding-70','雜曲歌辭：舞馬千秋萬歲樂府詞','張說','唐','御定全唐诗','yuding','','[]','金天誕聖千秋節，玉醴還分萬壽觴。試聽紫騮歌樂府，',120,'御定全唐詩/json/028.json','["金天誕聖千秋節，玉醴還分萬壽觴。試聽紫騮歌樂府，", "歲歲相傳指樹日，翩翩來伴慶雲翔。", "聖王至德與天齊，天馬來儀自海西。腕足齊行拜兩膝，", "更有銜杯終宴曲，垂頭掉尾醉如泥。", "遠聽明君愛逸才，玉鞭金翅引龍媒。不因茲白人間有，", "莫言闕下桃花舞，別有河中蘭葉開。"]'),
('yuding-71','雜曲歌辭：小曲新詞','白居易','唐','御定全唐诗','yuding','','[]','霽色鮮宮殿，秋聲脆管弦。聖明千歲樂，歲歲似今年。',48,'御定全唐詩/json/028.json','["霽色鮮宮殿，秋聲脆管弦。聖明千歲樂，歲歲似今年。", "紅裙明月夜，碧殿早秋時。好向昭陽宿，天涼玉漏遲。"]'),
('yuding-72','雜曲歌辭：閨怨詞','白居易','唐','御定全唐诗','yuding','','[]','朝憎鶯百囀，夜妒燕雙棲。不慣經春別，誰知到曉啼。',72,'御定全唐詩/json/028.json','["朝憎鶯百囀，夜妒燕雙棲。不慣經春別，誰知到曉啼。", "珠箔籠寒月，紗窗背曉燈。夜來巾上淚，一半是春冰。", "關山征戍遠，閨閣別離難。苦戰應憔悴，寒衣不要寬。"]'),
('yuding-73','雜曲歌辭：皇帝感詞','盧綸','唐','御定全唐诗','yuding','','[]','提劍雲雷動，垂衣日月明。禁花呈瑞色，國老見星精。',192,'御定全唐詩/json/028.json','["提劍雲雷動，垂衣日月明。禁花呈瑞色，國老見星精。", "發棹魚先躍，窺巢鳥不驚。山呼一萬歲，直入九重城。", "天衣五鳳彩，禦馬六龍文。雨露清馳道，風雷翊上軍。", "高旍花外轉，行漏樂前聞。時見金鞭舉，空中指瑞雲。", "妙算干戈止，神謀宇宙清。兩階文物盛，七德武功成。", "校獵長楊苑，屯軍細柳營。歸來獻明主，歌舞隘春城。", "天樂下天中，雲輧儼在空。鉛黃豔河漢，語笑合笙鏞。", "已見長隨鳳，仍聞不避熊。君王親試舞，閶闔靜無風。"]');
